-- Poems batch 413
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('song-ci-722','瑞鹧鸪','李清照','宋','宋词','song-ci','瑞鹧鸪','[]','风韵雍容未甚都。',64,'宋词/ci.song.6000.json','["风韵雍容未甚都。", "尊前甘橘可为奴。", "谁怜流落江湖上，玉骨冰肌未肯枯。", "谁教并蒂连枝摘，醉后明皇倚太真。", "居士擘开真有意，要吟风味两家新。"]'),
('song-ci-723','临江仙','李清照','宋','宋词','song-ci','临江仙','[]','庭院深深深几许，云窗雾阁春迟。',70,'宋词/ci.song.6000.json','["庭院深深深几许，云窗雾阁春迟。", "为谁憔悴损芳姿。", "夜来清梦好，应是发南枝。", "玉瘦檀轻无限恨，南楼羌管休吹。", "浓香吹尽有谁知。", "暖风迟日也，别到杏花肥。"]'),
('song-ci-724','庆清朝','李清照','宋','宋词','song-ci','庆清朝','[]','禁幄低张，彤阑巧护，就中独占残春。',119,'宋词/ci.song.6000.json','["禁幄低张，彤阑巧护，就中独占残春。", "容华淡伫，绰约俱见天真。", "待得群花过后，一番风露晓妆新。", "妖娆艳态，妒风笑月，长殢东君。", "东城边，南陌上，正日烘池馆，竟走香轮。", "绮筵散日，谁人可继芳尘。", "更好明光宫殿，几枝先近日边匀。", "金尊倒，拚了尽烛，不管黄昏。"]'),
('song-ci-725','浣溪沙','李清照','宋','宋词','song-ci','浣溪沙','[]','髻子伤春慵更梳。',48,'宋词/ci.song.6000.json','["髻子伤春慵更梳。", "晚风庭院落梅初。", "淡云来往月疏疏。", "玉鸭熏炉闲瑞脑，朱樱斗帐掩流苏。", "通犀还解辟寒无。"]'),
('song-ci-726','浣溪沙','李清照','宋','宋词','song-ci','浣溪沙','[]','绣面芙蓉一笑开。',48,'宋词/ci.song.6000.json','["绣面芙蓉一笑开。", "斜飞宝鸭衬香腮。", "眼波才动被人猜。", "一面风情深有韵，半笺娇恨寄幽怀。", "月移花影约重来。"]'),
('song-ci-727','采桑子','吕本中','宋','宋词','song-ci','采桑子','[]','恨君不似江楼月，南北东西。',47,'宋词/ci.song.6000.json','["恨君不似江楼月，南北东西。", "只有相随无别离。", "恨君却似江楼月，暂满还亏。", "暂满还亏。", "待得团团是几时。"]'),
('song-ci-728','采桑子','吕本中','宋','宋词','song-ci','采桑子','[]','乱红夭绿风吹尽，小市疏楼。',52,'宋词/ci.song.6000.json','["乱红夭绿风吹尽，小市疏楼。", "细雨轻鸥。", "总向离人恨里收。", "年年春好年年病，妾自西游。", "水自东流。", "不似残花一样愁。"]'),
('song-ci-729','西江月','吕本中','宋','宋词','song-ci','西江月','[]','渺渺风吹月上，濛濛雾挟霜回。',58,'宋词/ci.song.6000.json','["渺渺风吹月上，濛濛雾挟霜回。", "百年心事老相催。", "人在夕阳落外。", "有梦常嫌去远，无书可恨来迟。", "一杯浊酒两篇诗。", "小槛黄花共醉。"]'),
('song-ci-730','西江月','吕本中','宋','宋词','song-ci','西江月','[]','酒罢悠扬醉兴。',58,'宋词/ci.song.6000.json','["酒罢悠扬醉兴。", "茶烹唤起醒魂。", "却嫌仙剂点甘辛。", "冲破龙团气韵。", "金鼎清泉乍泻，香沈微惜芳熏。", "玉人歌断恨轻分。", "欢意厌厌未尽。"]'),
('song-ci-731','朝中措','吕本中','宋','宋词','song-ci','朝中措','[]','病香无力傍栏干。',57,'宋词/ci.song.6000.json','["病香无力傍栏干。", "风雨送春还。", "一枕晓来清梦，无人说似西山。", "匆匆笑语，时时邂逅，草草杯盘。", "莫谓杂花时候，便忘梅蕊冲寒。"]'),
('song-ci-732','南歌子','吕本中','宋','宋词','song-ci','南歌子','[]','驿路侵斜月，溪桥度晓霜。',62,'宋词/ci.song.6000.json','["驿路侵斜月，溪桥度晓霜。", "短篱残菊一枝黄。", "正是乱山深处、过重阳。", "旅枕元无梦，寒更每自长。", "只言江左好风光。", "不道中原归思、转凄凉。"]'),
('song-ci-733','虞美人','吕本中','宋','宋词','song-ci','虞美人','[]','梅花自是于春懒。',66,'宋词/ci.song.6000.json','["梅花自是于春懒。", "不是春来晚。", "看伊开在众花前。", "便道与春无分、结因缘。", "风前月下频相就。", "笑我如伊瘦。", "几回冲雨过疏篱。", "已见一番青子、缀残枝。"]'),
('song-ci-734','虞美人','吕本中','宋','宋词','song-ci','虞美人','[]','平生臭味如君少。',66,'宋词/ci.song.6000.json','["平生臭味如君少。", "自是君难老。", "似侬憔悴更谁知。", "只道心情、不似少年时。", "春风也到江南路。", "小槛花深处。", "对人不是忆姚黄。", "实是旧时风味、老难忘。"]'),
('song-ci-735','浣溪沙','吕本中','宋','宋词','song-ci','浣溪沙','[]','暖日温风破浅寒。',48,'宋词/ci.song.6000.json','["暖日温风破浅寒。", "短青无数簇幽栏。", "三年春在病中看。", "中酒心情浑似梦，探花时候不曾闲。", "几年芳信隔秦关。"]'),
('song-ci-736','浣溪沙','吕本中','宋','宋词','song-ci','浣溪沙','[]','共饮昏昏到暮鸦。',48,'宋词/ci.song.6000.json','["共饮昏昏到暮鸦。", "不须春日念京华。", "迩来沈醉是生涯。", "不是对君犹惜醉，只嫌春病却怜他。", "愿为蜂采落残花。"]'),
('song-ci-737','长相思','吕本中','宋','宋词','song-ci','长相思','[]','要相忘。',44,'宋词/ci.song.6000.json','["要相忘。", "不相忘。", "玉树郎君月艳娘。", "几回曾断肠。", "欲下床。", "却上床。", "上得床来思旧乡。", "北风吹梦长。"]'),
('song-ci-738','减字木兰花','吕本中','宋','宋词','song-ci','减字木兰花','[]','去年今夜。',52,'宋词/ci.song.6000.json','["去年今夜。", "同醉月明花树下。", "此夜江边。", "月暗长堤柳暗船。", "故人何处。", "带我离愁江外去。", "来岁花前。", "又是今年忆去年。"]'),
('song-ci-739','菩萨蛮','吕本中','宋','宋词','song-ci','菩萨蛮','[]','客愁不到西池路。',52,'宋词/ci.song.6000.json','["客愁不到西池路。", "残春又逐花飞去。", "今日傍池行。", "新荷昨夜生。", "故人千虑绕。", "不道书来少。", "去住隔关河。", "长亭风雨多。"]'),
('song-ci-740','菩萨蛮','吕本中','宋','宋词','song-ci','菩萨蛮','[]','高楼只在斜阳里。',52,'宋词/ci.song.6000.json','["高楼只在斜阳里。", "春风淡荡人声喜。", "携客不嫌频。", "使君如酒醇。", "花光人不会。", "月色须君醉。", "月色与花光。", "共成今夜长。"]'),
('song-ci-741','菩萨蛮','吕本中','宋','宋词','song-ci','菩萨蛮','[]','登楼一望南山雪。',52,'宋词/ci.song.6000.json','["登楼一望南山雪。", "使君风味如新月。", "月向雪前明。", "主人今夜情。", "平生相与意。", "老病犹堪记。", "对酒为君欢。", "酒杯嫌未宽。"]'),
('song-ci-742','踏莎行','吕本中','宋','宋词','song-ci','踏莎行','[]','雪似梅花，梅花似雪。',68,'宋词/ci.song.6000.json','["雪似梅花，梅花似雪。", "似和不似都奇绝。", "恼人风味阿谁知，请君问取南楼月。", "记得旧时，探梅时节。", "老来旧事无人说。", "为谁醉倒为谁醒，到今犹恨轻离别。"]'),
('song-ci-743','清平乐','吕本中','宋','宋词','song-ci','清平乐','[]','故人何处。',54,'宋词/ci.song.6000.json','["故人何处。", "同在江南路。", "百种旧愁分不去。", "枉被落花留住。", "旧愁百种谁知。", "除非是见伊时。", "最是一春多病，等闲过了酴醿。"]'),
('song-ci-744','渔家傲','吕本中','宋','宋词','song-ci','渔家傲','[]','小院悠悠春未远。',72,'宋词/ci.song.6000.json','["小院悠悠春未远。", "牡丹昨夜开犹浅。", "珍重使君帘尽卷。", "风欲转。", "绿阴掩映栏干晚。", "记得旧时清夜短。", "洛阳芳讯时相伴。", "一朵姚黄䯳髻满。", "情未展。", "新来衰病无人管。"]'),
('song-ci-745','生查子','吕本中','宋','宋词','song-ci','生查子','[]','残春雾雨馀，小院黄昏后。',48,'宋词/ci.song.6000.json','["残春雾雨馀，小院黄昏后。", "说道觅新词，把酒来相就。", "酴醿插髻云，岁岁长如旧。", "不是做词迟，却怕添伊瘦。"]'),
('song-ci-746','满江红','吕本中','宋','宋词','song-ci','满江红','[]','东里先生，家何在、山阴溪曲。',112,'宋词/ci.song.6000.json','["东里先生，家何在、山阴溪曲。", "对一川平野，数间茅屋。", "昨夜冈头新雨过，门前流水清如玉。", "抱小桥、回合柳参天，摇新绿。", "疏篱下，丛丛菊。", "虚檐外，萧萧竹。", "叹古今得失，是非荣辱。", "须信人生归去好，世间万事何时足。", "问此春、春酝酒何如，今朝熟。"]'),
('song-ci-747','浪淘沙','吕本中','宋','宋词','song-ci','浪淘沙','[]','柳色过疏篱。',64,'宋词/ci.song.6000.json','["柳色过疏篱。", "花又离披。", "旧时心绪没人知。", "记得一年寒食下，独自归时。", "归后却寻伊。", "月上嫌迟。", "十分斟酒不推辞。", "将为老来浑忘却，因甚沾衣。"]'),
('song-ci-748','浪淘沙','吕本中','宋','宋词','song-ci','浪淘沙','[]','柳塘新涨。',54,'宋词/ci.song.6000.json','["柳塘新涨。", "艇子操双浆。", "闲倚曲楼成怅望。", "是处春愁一样。", "傍人几点飞花。", "夕阳又送栖鸦。", "试问画楼西畔，暮云恐近天涯。"]'),
('song-ci-749','生查子','吕本中','宋','宋词','song-ci','生查子','[]','双双小凤斜，淡淡鸦儿稳。',48,'宋词/ci.song.6000.json','["双双小凤斜，淡淡鸦儿稳。", "一曲渭城歌，柳色饶春恨。", "离觞洗别愁，酒尽愁难尽。", "宝瑟雁纵横，谁寄天涯信。"]'),
('song-ci-750','生查子','吕本中','宋','宋词','song-ci','生查子','[]','人分南浦春，酒把阳关盏。',48,'宋词/ci.song.6000.json','["人分南浦春，酒把阳关盏。", "衣带自无情，顿为离人缓。", "愁随苦海深，恨逐前峰远。", "更听断肠猿，一似闻弦雁。"]'),
('song-ci-751','蝶恋花','吕本中','宋','宋词','song-ci','蝶恋花','[]','巧语娇莺春未暮。',70,'宋词/ci.song.6000.json','["巧语娇莺春未暮。", "杨柳风流，恰过池塘雨。", "芳草满庭花满树。", "无情胡蝶飞来去。", "睡起小奁香一缕。", "玉篆回纹，等个人分付。", "桃叶不言人不语。", "眉尖一点君知否。"]'),
('song-ci-752','鹧鸪天','向子諲','宋','宋词','song-ci','鹧鸪天','[]','说著分飞百种猜。',64,'宋词/ci.song.6000.json','["说著分飞百种猜。", "泥人细数几时回。", "风流可惯曾孤冷，怀抱如何得好开。", "垂玉箸，下香阶。", "凭肩小语更兜鞋。", "再三莫遣归期误，第一频教入梦来。"]'),
('song-ci-753','鹧鸪天','向子諲','宋','宋词','song-ci','鹧鸪天','[]','浅浅妆成淡淡梅。',64,'宋词/ci.song.6000.json','["浅浅妆成淡淡梅。", "见梅忆着傍妆台。", "书无鸿雁如何寄，肠断催归作麽回。", "千种恨，百般猜。", "为伊怀抱几时开。", "可堪江上风头恶，不放朝云入梦来。"]'),
('song-ci-754','鹧鸪天','向子諲','宋','宋词','song-ci','鹧鸪天','[]','几处秋千懒未收。',64,'宋词/ci.song.6000.json','["几处秋千懒未收。", "花梢柳外出纤柔。", "霞衣轻举疑奔月，宝髻敧倾若坠楼。", "争缥缈，斗风流。", "蜂儿蛱蝶共嬉游。", "朝朝暮暮春风里，落尽梨花未肯休。"]'),
('song-ci-755','踏莎行','向子諲','宋','宋词','song-ci','踏莎行','["\u957f\u6c5f"]','霭霭朝云，矜春态度。',68,'宋词/ci.song.6000.json','["霭霭朝云，矜春态度。", "楚宫梦断寻无路。", "欲将尊酒遣新愁，谁知引到愁深处。", "不尽长江，无边细雨。", "只疑都把愁来做。", "西山总不解遮栏，随春直过东湖去。"]'),
('song-ci-756','鹊桥仙','向子諲','宋','宋词','song-ci','鹊桥仙','[]','合巹风流，擘钗情态，压倒痴牛呆女。',68,'宋词/ci.song.6000.json','["合巹风流，擘钗情态，压倒痴牛呆女。", "今年云外果深期，想却笑、人间离苦。", "萦愁叠恨，青山绿水，杳杳重重无数。", "寻常犹有梦能来，到此夜、无寻梦处。"]'),
('song-ci-757','虞美人','向子諲','宋','宋词','song-ci','虞美人','[]','濛濛烟树无重数。',65,'宋词/ci.song.6000.json','["濛濛烟树无重数。", "不碍相思路。", "晚云分外欲增愁。", "更那堪疏雨、送归舟。", "雨来还被风吹去。", "陨泪多如雨。", "拟题双叶问离忧。", "怎得水随人意、肯西流。"]'),
('song-ci-758','虞美人','向子諲','宋','宋词','song-ci','虞美人','[]','去年不到琼花底。',66,'宋词/ci.song.6000.json','["去年不到琼花底。", "蝶梦空相倚。", "今年特地趁花来。", "却甚不教同醉、过花开。", "花知此恨年年有。", "也伴人春瘦。", "一枝和泪寄春风。", "应把旧愁新怨、入眉峰。"]'),
('song-ci-759','虞美人','向子諲','宋','宋词','song-ci','虞美人','[]','去年雪满长安树。',66,'宋词/ci.song.6000.json','["去年雪满长安树。", "望断扬州路。", "今年看雪在扬州。", "人在蓬莱深处、若为愁。", "而今不恨伊相误。", "自恨来何暮。", "平山堂下旧嬉游。", "只有舞春杨柳、似风流。"]'),
('song-ci-760','虞美人','向子諲','宋','宋词','song-ci','虞美人','[]','倚窗人似莺藏柳。',66,'宋词/ci.song.6000.json','["倚窗人似莺藏柳。", "巧语春心透。", "声声清切入人深。", "一夜不知两鬓、雪霜侵。", "何时月下歌金缕。", "醉看行云住。", "懒将幽恨寄瑶琴。", "却倩金笼鹦鹉、递芳音。"]'),
('song-ci-761','更漏子','向子諲','宋','宋词','song-ci','更漏子','[]','竹孤青，梅酽白。',58,'宋词/ci.song.6000.json','["竹孤青，梅酽白。", "更着使君清绝。", "梅似竹，竹如君。", "须知德有邻。", "月同高，风同调。", "月底风前一笑。", "翻碎影，度微香。", "与人风味长。"]'),
('song-ci-762','更漏子','向子諲','宋','宋词','song-ci','更漏子','[]','鹊桥边，牛渚上。',58,'宋词/ci.song.6000.json','["鹊桥边，牛渚上。", "翠节红旌相向。", "承玉露，御金风。", "年年岁岁同。", "懒飞梭，停弄杼。", "遥想彩云深处。", "人咫尺，事关山。", "无聊独倚栏。"]'),
('song-ci-763','鹊桥仙','向子諲','宋','宋词','song-ci','鹊桥仙','[]','澄江如练，远山横翠，一段风烟如画。',68,'宋词/ci.song.6000.json','["澄江如练，远山横翠，一段风烟如画。", "层楼杰阁倚晴空，疑便是、支矶石下。", "宝奁琼鉴，淡匀轻扫，纤手弄妆初罢。", "拟将心事问天公，与牛女、平分今夜。"]'),
('song-ci-764','南歌子','向子諲','宋','宋词','song-ci','南歌子','[]','碧落飞明镜，晴烟幂远山。',62,'宋词/ci.song.6000.json','["碧落飞明镜，晴烟幂远山。", "扁舟夜下广陵滩。", "照我白苹红蓼、一杯残。", "初望同盘饮，如何两处看。", "遥知香雾湿云鬟。", "凭暖琼楼十二、玉栏干。"]'),
('song-ci-765','鹊桥仙','向子諲','宋','宋词','song-ci','鹊桥仙','[]','飞云多态，凉飕微度，都到酒边歌处。',68,'宋词/ci.song.6000.json','["飞云多态，凉飕微度，都到酒边歌处。", "冰肌玉骨照人寒，更做弄、一帘风雨。", "同盘风味，合欢情思，不管星娥猜妒。", "桃花溪水接银河，与占断、鹊桥归路。"]'),
('song-ci-766','南歌子','向子諲','宋','宋词','song-ci','南歌子','[]','缥缈云间质，轻盈波上身。',62,'宋词/ci.song.6000.json','["缥缈云间质，轻盈波上身。", "瑶林玉树出风尘。", "不是野花凡草、等闲春。", "翠羽双垂珥，乌纱巧制巾。", "经珠不动两眉颦。", "须信铅华销尽、见天真。"]'),
('song-ci-767','南歌子','向子諲','宋','宋词','song-ci','南歌子','[]','梁苑千花乱，隋堤一水长。',62,'宋词/ci.song.6000.json','["梁苑千花乱，隋堤一水长。", "眼前风物总悲凉。", "何况眉头心上、不相忘。", "因梦聊携手，凭书续断肠。", "已惊蝴蝶过东墙。", "更被风吹鸿雁、不成行。"]'),
('song-ci-768','卜算子','向子諲','宋','宋词','song-ci','卜算子','[]','竹里一枝梅，雨洗娟娟静。',52,'宋词/ci.song.6000.json','["竹里一枝梅，雨洗娟娟静。", "疑是佳人日暮来，绰约风前影。", "新恨有谁知，往事何堪省。", "梦绕阳台寂寞回，沾袖馀香冷。"]'),
('song-ci-769','菩萨蛮','向子諲','宋','宋词','song-ci','菩萨蛮','[]','鸳鸯翡翠同心侣。',52,'宋词/ci.song.6000.json','["鸳鸯翡翠同心侣。", "惊风不得双飞去。", "春水绿西池。", "重期相见时。", "长怜心共语。", "梦里池边路。", "相见不如新。", "花应解笑人。"]'),
('song-ci-770','菩萨蛮','向子諲','宋','宋词','song-ci','菩萨蛮','[]','娟娟明月如霜白。',52,'宋词/ci.song.6000.json','["娟娟明月如霜白。", "鳌山可是蓬山隔。", "恨不及春风。", "行云处处同。", "暖香红雾里。", "一笑谁新喜。", "知得远愁无。", "春衫有泪珠。"]'),
('song-ci-771','菩萨蛮','向子諲','宋','宋词','song-ci','菩萨蛮','[]','袜儿窄剪鞋儿小。',52,'宋词/ci.song.6000.json','["袜儿窄剪鞋儿小。", "纹鸳并影双双好。", "微步巧藏人。", "轻飞洛浦尘。", "前回深处见。", "欲近还相远。", "心事不能知。", "教人直是疑。"]'),
('song-ci-772','南歌子','向子諲','宋','宋词','song-ci','南歌子','[]','雨过林峦静，风回池阁凉。',62,'宋词/ci.song.6000.json','["雨过林峦静，风回池阁凉。", "窥人双燕语雕梁。", "笑看小荷翻处、戏鸳鸯。", "共饮菖蒲细，同分彩线长。", "今朝真不负风光。", "绝胜几年飞梦、绕高唐。"]'),
('song-ci-773','减字木兰花','向子諲','宋','宋词','song-ci','减字木兰花','[]','几年不见。',52,'宋词/ci.song.6000.json','["几年不见。", "胡蝶枕中魂梦远。", "一日相逢。", "鹦鹉杯深笑靥浓。", "欢心未已。", "流水落花愁又起。", "离恨如何。", "细雨斜风晚更多。"]'),
('song-ci-774','秦楼月・忆秦娥','向子諲','宋','宋词','song-ci','秦楼月・忆秦娥','[]','虫声切。',56,'宋词/ci.song.6000.json','["虫声切。", "柔肠欲断伤离别。", "伤离别。", "几行清泪，界残红颊。", "玉阶白露侵罗袜。", "下帘却望玲珑月。", "玲珑月。", "寒光凌乱，照人愁绝。"]'),
('song-ci-775','生查子','向子諲','宋','宋词','song-ci','生查子','[]','月在两山间，人在空明里。',48,'宋词/ci.song.6000.json','["月在两山间，人在空明里。", "山色碧於天，月色光於水。", "心闲物物幽，心动尘尘起。", "莫向动中来，长愿闲如此。"]'),
('song-ci-776','生查子','向子諲','宋','宋词','song-ci','生查子','[]','春心如杜鹃，日夜思归切。',48,'宋词/ci.song.6000.json','["春心如杜鹃，日夜思归切。", "啼尽一川花，愁落千山月。", "遥怜白玉人，翠被馀香歇。", "可惯独眠寒，减动丰肌雪。"]'),
('song-ci-777','生查子','向子諲','宋','宋词','song-ci','生查子','[]','近似月当怀，远似花藏雾。',48,'宋词/ci.song.6000.json','["近似月当怀，远似花藏雾。", "好是月明时，同醉花深处。", "看花不自持，对月空相顾。", "愿学月频圆，莫作花飞去。"]'),
('song-ci-778','生查子','向子諲','宋','宋词','song-ci','生查子','[]','春山和恨长，秋水无言度。',48,'宋词/ci.song.6000.json','["春山和恨长，秋水无言度。", "脉脉复盈盈，几点梨花雨。", "深深一段愁，寂寂无行路。", "推去又还来，没个遮栏处。"]'),
('song-ci-779','生查子','向子諲','宋','宋词','song-ci','生查子','[]','娟娟月入眉，整整云归鬓。',48,'宋词/ci.song.6000.json','["娟娟月入眉，整整云归鬓。", "镜里弄妆迟，帘外花移影。", "斜窥秋水长，软语春莺近。", "无计奈情何，只有相思分。"]'),
('song-ci-780','生查子','向子諲','宋','宋词','song-ci','生查子','[]','相思懒下床，春梦迷蝴蝶。',48,'宋词/ci.song.6000.json','["相思懒下床，春梦迷蝴蝶。", "入柳又穿花，去去轻如叶。", "可堪歧路长，不道关山隔。", "无赖是黄鹂，唤起空愁绝。"]'),
('song-ci-781','望江南・忆江南','向子諲','宋','宋词','song-ci','望江南・忆江南','[]','微雨过，庭院净无尘。',64,'宋词/ci.song.6000.json','["微雨过，庭院净无尘。", "天上秋期明日是，人间月影十分清，真不负佳辰。", "称寿处，香雾绕花身。", "玉兔已成千岁药，桂华更与一枝新。", "喜气满重闉。"]'),
('song-ci-782','浣溪沙','向子諲','宋','宋词','song-ci','浣溪沙','[]','冰雪肌肤不受尘。',48,'宋词/ci.song.6000.json','["冰雪肌肤不受尘。", "脸桃眉柳暖生春。", "手搓梅子笑迎人。", "欲语又休无限思，暂来还去不胜颦。", "梦随蝴蝶过东邻。"]'),
('song-ci-783','西江月','向子諲','宋','宋词','song-ci','西江月','[]','微步凌波尘起，弄妆满镜花开。',58,'宋词/ci.song.6000.json','["微步凌波尘起，弄妆满镜花开。", "春心掷处眼频来。", "秀色著人无耐。", "旧事如风无迹，新愁似水难裁。", "相思日夜梦阳台。", "减尽沈郎衣带。"]'),
('song-ci-784','点绛唇','向子諲','宋','宋词','song-ci','点绛唇','[]','丹凤飞来，细传日下丝纶语。',50,'宋词/ci.song.6000.json','["丹凤飞来，细传日下丝纶语。", "使君归去。", "已近沙堤路。", "风叶露花，秋意浓如许。", "江天暮。", "离歌轻举。", "愁满西山雨。"]'),
('song-ci-785','丑奴儿・采桑子','向子諲','宋','宋词','song-ci','丑奴儿・采桑子','[]','无双亭下琼花树，玉骨云腴。',52,'宋词/ci.song.6000.json','["无双亭下琼花树，玉骨云腴。", "倾国称姝。", "除却扬州是无处。", "天教红药来参乘，桃李先驱。", "总作花奴。", "翠拥红遮到玉都。"]'),
('song-ci-786','如梦令','向子諲','宋','宋词','song-ci','如梦令','[]','午夜凉生翠幔。',40,'宋词/ci.song.6000.json','["午夜凉生翠幔。", "帘外行云撩乱。", "可恨白苹风，欲雨又还吹散。", "肠断。", "肠断。", "楚梦惊残一半。"]'),
('song-ci-787','好事近','向子諲','宋','宋词','song-ci','好事近','[]','小雨度微云，快染一天新碧。',53,'宋词/ci.song.6000.json','["小雨度微云，快染一天新碧。", "恰到中秋佳处，是芳年华日。", "冰轮莫做九分看，天意在今夕。", "先占广寒风露，怕姮娥偏得。"]'),
('song-ci-788','好事近','向子諲','宋','宋词','song-ci','好事近','[]','初上舞茵时，争看袜罗弓窄。',53,'宋词/ci.song.6000.json','["初上舞茵时，争看袜罗弓窄。", "恰似晚霞零乱，衬一钩新月。", "折旋多态小腰身，分明是回雪。", "生怕因风飞去，放真珠帘隔。"]'),
('song-ci-789','采桑子','向子諲','宋','宋词','song-ci','采桑子','[]','人如濯濯春杨柳，彻骨风流。',52,'宋词/ci.song.6000.json','["人如濯濯春杨柳，彻骨风流。", "脱体温柔。", "牵系多情尽未休。", "最怜恰恰新眠起，云雨初收。", "斜倚琼楼。", "叶叶眉心一样愁。"]'),
('song-ci-790','清平乐','向子諲','宋','宋词','song-ci','清平乐','[]','云无天净。',54,'宋词/ci.song.6000.json','["云无天净。", "明月端如镜。", "乌鹊绕枝栖未稳。", "零露垂垂珠陨。", "扁舟共绝潮河。", "秋风别去如梭。", "今夜凄然对影，与谁斟酌姮娥。"]'),
('song-ci-791','浣溪沙','向子諲','宋','宋词','song-ci','浣溪沙','[]','花想仪容柳想腰。',48,'宋词/ci.song.6000.json','["花想仪容柳想腰。", "融融曳曳一团娇。", "绮罗丛里最妖娆。", "歌罢碧天零影乱，舞时红袖雪花飘。", "几回相见为魂销。"]'),
('song-ci-792','浣溪沙','向子諲','宋','宋词','song-ci','浣溪沙','[]','艳赵倾燕花里仙。',48,'宋词/ci.song.6000.json','["艳赵倾燕花里仙。", "乌丝阑写永和年。", "有时闲弄醒心弦。", "茗碗分云微醉后，纹楸斜倚髻鬟偏。", "风流模样总堪怜。"]'),
('song-ci-793','浣溪沙','向子諲','宋','宋词','song-ci','浣溪沙','[]','曾是襄王梦里仙。',48,'宋词/ci.song.6000.json','["曾是襄王梦里仙。", "娇痴恰恰破瓜年。", "芳心已解品朱弦。", "浅浅笑时双靥媚，盈盈立处绿云偏。", "称人心是尽人怜。"]'),
('song-ci-794','浣溪沙','向子諲','宋','宋词','song-ci','浣溪沙','[]','一夜凉飔动碧厨。',48,'宋词/ci.song.6000.json','["一夜凉飔动碧厨。", "晓庭飞雨溅真珠。", "玉人睡起倚金铺。", "云髻作堆初未整，柳腰如醉不胜扶。", "天仙风调世间无。"]'),
('song-ci-795','浣溪沙','向子諲','宋','宋词','song-ci','浣溪沙','[]','璧月光中玉漏清。',48,'宋词/ci.song.6000.json','["璧月光中玉漏清。", "小梅疏影水边明。", "似梅人醉月西倾。", "梅欲黄时朝暮雨，月重圆处短长亭。", "旧愁新恨若为情。"]'),
('song-ci-796','浣溪沙','向子諲','宋','宋词','song-ci','浣溪沙','[]','人意天公则甚知。',48,'宋词/ci.song.6000.json','["人意天公则甚知。", "故教小雨作深悲。", "桃花浑似泪胭脂。", "理棹又从今日去，断肠还似去年时。", "经行处处是相思。"]'),
('song-ci-797','浣溪沙','向子諲','宋','宋词','song-ci','浣溪沙','[]','花样风流柳样娇。',48,'宋词/ci.song.6000.json','["花样风流柳样娇。", "雪中微步过溪桥。", "心期春色到梅梢。", "折得一枝归绿鬓，冰容玉艳不相饶。", "索人同去醉金蕉。"]'),
('song-ci-798','浣溪沙','向子諲','宋','宋词','song-ci','浣溪沙','[]','守得梅开著意看。',48,'宋词/ci.song.6000.json','["守得梅开著意看。", "春风几醉玉栏干。", "去时犹自惜馀欢。", "雨后重来花扫地，叶间青子已团团。", "凭谁寄与蹙眉山。"]'),
('song-ci-799','浣溪沙','向子諲','宋','宋词','song-ci','浣溪沙','[]','翡翠衣裳白玉人。',48,'宋词/ci.song.6000.json','["翡翠衣裳白玉人。", "不将朱粉污天真。", "清风为伴月为邻。", "枕上解随良夜梦，壶中别是一家春。", "同心小绾更尖新。"]'),
('song-ci-800','浣溪沙','向子諲','宋','宋词','song-ci','浣溪沙','[]','雨点春山入翠眉。',48,'宋词/ci.song.6000.json','["雨点春山入翠眉。", "一ь杨柳作腰肢。", "语音娇软带儿痴。", "犹省当来求识面，隔帘清唱倒琼彝。", "真成相见说当时。"]'),
('song-ci-801','浣溪沙','向子諲','宋','宋词','song-ci','浣溪沙','[]','姑射肌肤雪一团。',48,'宋词/ci.song.6000.json','["姑射肌肤雪一团。", "掺掺玉手弄冰纨。", "著人情思几多般。", "水上月如天样远，眼前花似镜中看。", "见时容易近时难。"]'),
('song-ci-802','浣溪沙','向子諲','宋','宋词','song-ci','浣溪沙','[]','云外遥山是翠眉。',48,'宋词/ci.song.6000.json','["云外遥山是翠眉。", "风前杨柳入腰肢。", "凌波微步袜尘飞。", "倚醉传歌留客处，佯嗔不语殢人时。", "风流态度百般宜。"]'),
('song-ci-803','浣溪沙','向子諲','宋','宋词','song-ci','浣溪沙','[]','百斛明珠得翠娥。',48,'宋词/ci.song.6000.json','["百斛明珠得翠娥。", "风流彻骨更能歌。", "碧云留住劝金荷。", "取醉归来因一笑，恼人深处是横波。", "酒醒情味却知麽。"]'),
('song-ci-804','相见欢','向子諲','宋','宋词','song-ci','相见欢','[]','亭亭秋水芙蓉。',45,'宋词/ci.song.6000.json','["亭亭秋水芙蓉。", "翠围中。", "又是一年风露、笑相逢。", "天机畔。", "云锦乱。", "思无穷。", "路隔银河犹解、嫁西风。"]'),
('song-ci-805','相见欢','向子諲','宋','宋词','song-ci','相见欢','[]','桃源深闭春风。',45,'宋词/ci.song.6000.json','["桃源深闭春风。", "信难通。", "流水落花馀恨、几时穷。", "水无定。", "花有尽。", "会相逢。", "可是人生长在、别离中。"]'),
('song-ci-806','相见欢','向子諲','宋','宋词','song-ci','相见欢','[]','腰肢一缕纤长。',45,'宋词/ci.song.6000.json','["腰肢一缕纤长。", "是垂杨。", "泥泥风中衣袖、冷沈香。", "花如颊。", "眉如叶。", "语如簧。", "微笑微颦相恼、过回廊。"]'),
('song-ci-807','最高楼','向子諲','宋','宋词','song-ci','最高楼','[]','无双亭下，琼树正花敷。',95,'宋词/ci.song.6000.json','["无双亭下，琼树正花敷。", "玉骨莹云腴。", "已知倾国无能比，除非天上有仙姝。", "到扬州才见，是处俱无。", "比碧桃、也无二朵，算丹桂、止是一株。", "千万卉，尽花奴。", "天教芍药来骖乘，一春桃李作先驱。", "尽红遮绿拥驻江都。"]'),
('song-ci-808','醉蓬莱','吴穆仲','宋','宋词','song-ci','醉蓬莱','[]','见处即已，无心即了。',10,'宋词/ci.song.6000.json','["见处即已，无心即了。"]'),
('song-ci-809','南柯子・南歌子','杨适2','宋','宋词','song-ci','南柯子・南歌子','[]','怨草迷南浦，愁花傍短亭。',62,'宋词/ci.song.6000.json','["怨草迷南浦，愁花傍短亭。", "有情歌酒莫催行。", "看取无情花草、也关情。", "旧日临岐曲，而今忍泪听。", "淮山何在暮云凝。", "待倩春风吹梦、过江城。"]'),
('song-ci-810','江城子','莫蒙','宋','宋词','song-ci','江城子','[]','长庚入梦夜何其。',86,'宋词/ci.song.6000.json','["长庚入梦夜何其。", "月波迟。", "露华滋。", "珠褓犀帷，生此宁馨儿。", "天上麒麟人不识，森□砢，骏权奇。", "文章锦绣识新机。", "国风诗。", "楚人词。", "銮殿蓬莱，早晚奉论思。", "百岁归来如魏武，从老大，好威仪。"]'),
('song-ci-811','满庭霜・满庭芳','李璆','宋','宋词','song-ci','满庭霜・满庭芳','[]','白玉肌肤，清冰神彩，仙妃何事烟村。',117,'宋词/ci.song.6000.json','["白玉肌肤，清冰神彩，仙妃何事烟村。", "自然标韵，羞入百花群。", "不易盈盈瘦质，犯寒腊、独作春温。", "溪桥外，斜枝半吐，行客一销魂。", "清香无处著，雪中暗认，月下空闻。", "算谁许幽人，相伴芳尊。", "莫放高楼弄笛，忍教看、雪落纷纷。", "堪调鼎，濛濛烟雨，滋养待和羹。"]'),
('song-ci-812','念奴娇','韩驹','宋','宋词','song-ci','念奴娇','[]','海天向晚，渐霞收馀绮，波澄微绿。',120,'宋词/ci.song.6000.json','["海天向晚，渐霞收馀绮，波澄微绿。", "木落山高真个是，一雨秋容新沐。", "唤起嫦娥，撩云拨雾，驾此一轮玉。", "桂华疏淡，广寒谁伴幽独。", "不见弄玉吹箫，尊前空对此，清光堪掬。", "雾鬓风鬟何处问，云雨巫山六六。", "珠斗斓斒，银河清浅，影转西楼曲。", "此情谁会，倚风三弄横竹。"]'),
('song-ci-813','失调名','韩驹','宋','宋词','song-ci','失调名','[]','孤舟晚扬湖光里。',16,'宋词/ci.song.6000.json','["孤舟晚扬湖光里。", "衰草斜阳无限意。"]'),
('song-ci-814','西江月','颜博文','宋','宋词','song-ci','西江月','[]','草草书传锦字，厌厌梦绕梅花。',58,'宋词/ci.song.6000.json','["草草书传锦字，厌厌梦绕梅花。", "海山无计驻星槎。", "肠断芭蕉影下。", "缺月旧时庭院，飞云到处人家。", "而今赢得鬓先华。", "说著多情已怕。"]'),
('song-ci-815','品令','颜博文','宋','宋词','song-ci','品令','[]','夜萧索。',65,'宋词/ci.song.6000.json','["夜萧索。", "侧耳听、清海楼头吹角。", "停归棹、不觉重门闭，恨只恨、暮潮落。", "偷想红啼绿怨，道我真个情薄。", "纱窗外、厌厌新月上，也应则、睡不著。"]'),
('song-ci-816','浣溪沙','沈与求','宋','宋词','song-ci','浣溪沙','[]','云幕垂垂不掩关，落鸿孤没有无间。',48,'宋词/ci.song.6000.json','["云幕垂垂不掩关，落鸿孤没有无间。", "雪花欺鬓一年残。", "欲把小梅还斗雪，冷香嫌怕乱沈檀。", "恼人归梦绕江干。"]'),
('song-ci-817','浣溪沙','沈与求','宋','宋词','song-ci','浣溪沙','[]','花信催春入帝关。',48,'宋词/ci.song.6000.json','["花信催春入帝关。", "玉霙争腊去留间。", "不禁风力又吹残。", "客舍不眠清夜冷，萦愁一缕袅旃檀。", "空庭月落斗栏干。"]'),
('song-ci-818','江城子','沈与求','宋','宋词','song-ci','江城子','[]','华灯高宴水精宫。',86,'宋词/ci.song.6000.json','["华灯高宴水精宫。", "浪花中。", "意无穷。", "十载江湖，重绾汉符铜。", "应有青藜存往事，人缥缈，佩丁东。", "卧听萧寺响疏钟。", "渡溪风。", "转空濛。", "月上孤窗，邻唱有渔翁。", "追念使君清坐久，歌一发，恨千重。"]'),
('song-ci-819','江城子','沈与求','宋','宋词','song-ci','江城子','[]','鱼龙戏舞近幽宫。',86,'宋词/ci.song.6000.json','["鱼龙戏舞近幽宫。", "乱山中。", "似途穷。", "绿野堂深，门敞兽铺铜。", "无限青瑶攒峭壁，花木老，映西东。", "消磨万事酒千锺。", "一襟风。", "鬓霜濛。", "忧国平生，堪笑已成翁。", "惟有经纶心事在，承密诏，看重重。"]'),
('song-ci-820','秦刷子','陈东','宋','宋词','song-ci','秦刷子','[]','谁斫碧琅玕，影撼半庭风月。',54,'宋词/ci.song.6000.json','["谁斫碧琅玕，影撼半庭风月。", "尚有岁寒心在，留得数根华发。", "龙孙受戏碧波涛，喜动清风发。", "到得浪花深处，□一瓯香雪。"]'),
('song-ci-821','西江月','陈东','宋','宋词','song-ci','西江月','[]','风动一轩花竹，琅玕青锦薰笼。',58,'宋词/ci.song.6000.json','["风动一轩花竹，琅玕青锦薰笼。", "怜才自是宋墙东。", "更识琴心挑弄。", "暮雨乍收寒浅，朝云又起春浓。", "冰肌玉骨信俱融。", "不比巫山闲梦。"]'),
('song-ci-822','蓦山溪','陈东','宋','宋词','song-ci','蓦山溪','[]','半生羁旅，几度经元夜。',102,'宋词/ci.song.6000.json','["半生羁旅，几度经元夜。", "长是竞虚名，把良宵、等闲弃舍。", "去年元夜，道得□身闲，依旧是，客长安，寂寞孤眠者。", "今年元夜。", "也则非乡社。", "却有人□约，携手□、灯前月下。", "那知风雨，此事又参差，成怨恨，独凄惶，清泪淆然洒。"]'),
('song-ci-823','西江月','陈东','宋','宋词','song-ci','西江月','[]','我笑牛郎织女，一年一度相逢。',58,'宋词/ci.song.6000.json','["我笑牛郎织女，一年一度相逢。", "欢情尽逐晓云空。", "愁损舞莺歌凤。", "牛女而今笑我，七年独卧西风。", "西风还解过江东。", "为报佳期入梦。"]'),
('song-ci-824','念奴娇','姚孝宁','宋','宋词','song-ci','念奴娇','[]','素娥睡起，驾冰轮碾破，一天秋绿。',120,'宋词/ci.song.6000.json','["素娥睡起，驾冰轮碾破，一天秋绿。", "醉倚高楼风露下，凛凛寒生肌粟。", "横管孤吹，龙吟风劲，雪浪翻银屋。", "壮游回首，会稽何限修竹。", "今夜对月依然，尊前须快泻，山头鸣瀑。", "吸此清光倾肺腑，洗我明珠千斛。", "只恐蝉娟，明年依旧，衰鬓先成鹄。", "举杯相劝，为予且挂团玉。"]'),
('song-ci-825','石州词・石州慢','胡松年','宋','宋词','song-ci','石州词・石州慢','["\u94b1\u5858\u6c5f"]','月上疏帘，风射小窗，孤馆岑寂。',120,'宋词/ci.song.6000.json','["月上疏帘，风射小窗，孤馆岑寂。", "一杯强洗愁怀，万里堪嗟行客。", "乱山无数，晚秋云物苍然，何如轻抹淮山碧。", "喜气拂征衣，作眉间黄色。", "役役。", "马头尘暗斜阳，陇首路回飞翼。", "梦里姑苏城外，钱塘江北。", "故人应念我，负吹帽佳时，同把金英摘。", "归路且加鞭，看梅花消息。"]'),
('song-ci-826','石州词・石州慢','胡松年','宋','宋词','song-ci','石州词・石州慢','[]','歌阕阳关，肠断短亭，惟有离别。',120,'宋词/ci.song.6000.json','["歌阕阳关，肠断短亭，惟有离别。", "画船送我薰风，瘦马迎人飞雪。", "平生幽梦，岂知塞北江南，而今真叹河山阔。", "屈指数分携，早许多时节。", "愁绝。", "雁行点点云垂，木叶霏霏霜滑。", "正是荒城落日，空山残月。", "一尊谁念我，苦憔悴天涯，陡觉生华发。", "赖有紫枢人，共扬鞭丹阙。"]'),
('song-ci-827','明月逐人来','李持正','宋','宋词','song-ci','明月逐人来','[]','星河明淡。',76,'宋词/ci.song.6000.json','["星河明淡。", "春来深浅。", "红莲正、满城开遍。", "禁街行乐，暗尘香拂面。", "皓月随人近远。", "天半鳌山，光动凤楼两观。", "东风静、珠帘不卷。", "玉辇待归，云外闻弦管。", "认得宫花影转。"]'),
('song-ci-828','人月圆令・人月园','李持正','宋','宋词','song-ci','人月圆令・人月园','[]','小桃枝上春风早，初试薄罗衣。',59,'宋词/ci.song.6000.json','["小桃枝上春风早，初试薄罗衣。", "年年乐事，华灯竞处，人月圆时。", "禁街箫鼓，寒轻夜永，纤手重携。", "更阑人散，千门笑语，声在帘帏。"]'),
('song-ci-829','桃源忆故人','王道亨','宋','宋词','song-ci','桃源忆故人','[]','刘郎自是桃花主。',56,'宋词/ci.song.6000.json','["刘郎自是桃花主。", "不许春风闲度。", "春色易随风去。", "片片伤春暮。", "返魂不用清香炷。", "却有梅花淡伫。", "从此镇长相顾。", "不怨飘残雨。"]'),
('song-ci-830','五福降中天','江致和','宋','宋词','song-ci','五福降中天','[]','喜元宵三五，纵马御柳沟东。',103,'宋词/ci.song.6000.json','["喜元宵三五，纵马御柳沟东。", "斜日映珠帘，瞥见芳容。", "秋水娇横俊眼，腻雪轻铺素胸。", "爱把菱花，笑匀粉面露春葱。", "徘徊步懒，奈一点、灵犀未通。", "怅望七香车去，慢辗春风。", "云情雨态，愿暂入阳台梦中。", "路隔烟霞，甚时还许到蓬宫。"]'),
('song-ci-831','清平乐','韩璜','宋','宋词','song-ci','清平乐','[]','秋光如水。',54,'宋词/ci.song.6000.json','["秋光如水。", "酿作鹅黄蚁。", "散入千岩佳树里。", "惟许修门人醉。", "轻钿重上风鬟。", "不禁月冷霜寒。", "步障深沈归去，依然愁满江山。"]'),
('song-ci-832','菩萨蛮','李邦献','宋','宋词','song-ci','菩萨蛮','[]','薰沈刻蜡工夫巧。',52,'宋词/ci.song.6000.json','["薰沈刻蜡工夫巧。", "蜜脾锁碎金锺小。", "别是一般香。", "解教人断肠。", "冰霜相与瘦。", "清在江梅右。", "念我忍寒来。", "怜君特地开。"]'),
('song-ci-833','眼儿媚','宋齐愈','宋','宋词','song-ci','眼儿媚','[]','霏霏疏影转征鸿。',58,'宋词/ci.song.6000.json','["霏霏疏影转征鸿。", "人语暗香中。", "小桥斜渡，西亭深院，水月朦胧。", "人间不是藏春处，玉笛晓霜空。", "江南树树，黄垂密雨，绿涨薰风。"]'),
('song-ci-834','念奴娇','宋江','宋','宋词','song-ci','念奴娇','[]','天南地北。',120,'宋词/ci.song.6000.json','["天南地北。", "问乾坤何处，可容狂客。", "借得山东烟水寨，来买凤城春色。", "翠袖围香，鲛绡笼玉，一笑千金值。", "神仙体态，薄幸如何销得。", "回想芦叶滩头，蓼花汀畔，皓月空凝碧。", "六六雁行连八九，只待金鸡消息。", "义胆包天，忠肝盖地，四海无人识。", "闲愁万种，醉乡一夜头白。"]'),
('song-ci-835','撒金钱','袁','宋','宋词','song-ci','撒金钱','[]','频瞻礼。',85,'宋词/ci.song.6000.json','["频瞻礼。", "喜升平、又逢元宵佳致。", "鳌山高耸翠。", "对端门、珠玑交制。", "似嫦娥降仙宫，乍临凡世。", "恩露匀施，凭御栏、圣颜垂视。", "撒金钱，乱抛坠。", "万姓推抢没理会。", "告官里。", "这失仪、且与免罪。"]'),
('song-ci-836','传言玉女','袁','宋','宋词','song-ci','传言玉女','[]','眉黛轻分，惯学玉真梳掠。',89,'宋词/ci.song.6000.json','["眉黛轻分，惯学玉真梳掠。", "艳容可画，那精神怎貌。", "鲛绡映玉，钿带双穿缨络。", "歌音清丽，舞腰柔弱。", "宴罢瑶池，御风跨皓鹤。", "凤凰台上，有萧郎共约。", "一面笑开，向月斜褰珠箔。", "东园无限，好花羞落。"]'),
('song-ci-837','念奴娇','连仲宣','宋','宋词','song-ci','念奴娇','[]','暗黄著柳，渐寒威收敛，日和风细。',120,'宋词/ci.song.6000.json','["暗黄著柳，渐寒威收敛，日和风细。", "□□端门初锡宴，郁郁葱葱佳气。", "太一行春，青藜照夜，夜色明如水。", "鳌山彩结，恍然移在平地。", "曲盖初展湘罗，玉皇香案，近雕阑十二。", "夹道红帘齐卷上，两行绝新珠翠。", "清跸声乾，传柑宴罢，闪闪星球坠。", "下楼归去，觚稜月衔龙尾。"]'),
('song-ci-838','临江仙','邢俊臣','宋','宋词','song-ci','临江仙','[]','巍峨万丈与天高。',20,'宋词/ci.song.6000.json','["巍峨万丈与天高。", "物轻人意重，千里送鹅毛。"]'),
('song-ci-839','临江仙','邢俊臣','宋','宋词','song-ci','临江仙','[]','远来犹自忆梁陈。',20,'宋词/ci.song.6000.json','["远来犹自忆梁陈。", "江南无好物，聊赠一枝春。"]'),
('song-ci-840','临江仙','邢俊臣','宋','宋词','song-ci','临江仙','[]','用心勤苦是新诗。',20,'宋词/ci.song.6000.json','["用心勤苦是新诗。", "吟安一个字，拈断数茎髭。"]'),
('song-ci-841','临江仙','邢俊臣','宋','宋词','song-ci','临江仙','[]','扪窗摸户入房来。',20,'宋词/ci.song.6000.json','["扪窗摸户入房来。", "笙歌归院落，灯火下楼台。"]'),
('song-ci-842','临江仙','邢俊臣','宋','宋词','song-ci','临江仙','[]','酥胸露出白皑皑。',20,'宋词/ci.song.6000.json','["酥胸露出白皑皑。", "遥知不是雪，为有暗香来。"]'),
('song-ci-843','临江仙','邢俊臣','宋','宋词','song-ci','临江仙','[]','只愁歌舞罢，化作彩云飞。',12,'宋词/ci.song.6000.json','["只愁歌舞罢，化作彩云飞。"]'),
('song-ci-844','浪淘沙','幼卿','宋','宋词','song-ci','浪淘沙','[]','目送楚云空。',64,'宋词/ci.song.6000.json','["目送楚云空。", "前事无踪。", "谩留遗恨锁眉峰。", "自是荷花开较晚，孤负东风。", "客馆叹飘蓬。", "聚散匆匆。", "扬鞭那忍骤花骢。", "望断斜阳人不见，满袖啼红。"]'),
('song-ci-845','减字木兰花','蒋氏女','宋','宋词','song-ci','减字木兰花','[]','朝云横渡。',52,'宋词/ci.song.6000.json','["朝云横渡。", "辘辘车声如水去。", "白草黄沙。", "月照孤村三两家。", "飞鸿过也。", "万结愁肠无昼夜。", "渐近燕山。", "回首乡关归路难。"]'),
('song-ci-846','鹧鸪天','蔡楠','宋','宋词','song-ci','鹧鸪天','[]','病酒厌厌与睡宜。',64,'宋词/ci.song.6000.json','["病酒厌厌与睡宜。", "珠帘罗幕卷银泥。", "风来绿树花含笑，恨入西楼月敛眉。", "惊瘦尽，怨归迟。", "休将桐叶更题诗。", "不知桥下无情水，流到天涯是几时。"]'),
('song-ci-847','念奴娇','蔡楠','宋','宋词','song-ci','念奴娇','[]','碧梧转影，正露冷天高，凉生襟袖。',122,'宋词/ci.song.6000.json','["碧梧转影，正露冷天高，凉生襟袖。", "此夕清辉，谁信道、夜色居然如昼。", "玉斧重修，宝奁初启，万里寒光透。", "将军高会，翠鬟争劝尊酒。", "遥想地近仙丘，碧山高处，引手攀星斗。", "醉嘱姮娥，惟但愿、月与佳人长久。", "罗覆银鞍，雨抛金甲，赢得诗千首。", "掀髯一笑，此怀人解知否。"]'),
('song-ci-848','满庭芳','蔡楠','宋','宋词','song-ci','满庭芳','[]','手染橙芗，杯摇烛影，夜阑人意醺酣。',118,'宋词/ci.song.6000.json','["手染橙芗，杯摇烛影，夜阑人意醺酣。", "故人惜别，却酒更清谈。", "只合相从老矣，知何事、还著征衫。", "流年晚，长途匹马，奔走亦何堪。", "江潭。", "摇落后，云嘘绝壁，雪舞空岩。", "念行人归鬓，今已毵毵。", "往事真成梦里，十年恨、江北江南。", "休凝伫，霜风卷地，寒日又西衔。"]'),
('song-ci-849','摊破诉衷情・诉衷情','蔡楠','宋','宋词','song-ci','摊破诉衷情・诉衷情','[]','夕阳低户水当楼。',56,'宋词/ci.song.6000.json','["夕阳低户水当楼。", "风烟惨淡秋。", "乱云飞尽碧山留。", "寒沙卧海鸥。", "浑似画，只供愁。", "相看空泪流。", "故人如欲问安不。", "病来今白头。"]'),
('song-ci-850','摊破诉衷情・诉衷情','蔡楠','宋','宋词','song-ci','摊破诉衷情・诉衷情','[]','栏干十二绕层楼。',56,'宋词/ci.song.6000.json','["栏干十二绕层楼。", "珠帘卷素秋。", "当年尊酒屡迟留。", "识公惟白鸥。", "才得趣，又成愁。", "情锺我辈流。", "买山同隐肯来不。", "遥怜笑点头。"]'),
('song-ci-851','凤栖梧・蝶恋花','蔡楠','宋','宋词','song-ci','凤栖梧・蝶恋花','[]','狂滥生涯今几许。',70,'宋词/ci.song.6000.json','["狂滥生涯今几许。", "敕赐湖天，万顷烟波主。", "约我小舟同老去。", "要前一叶风掀舞。", "邂逅同寻溪上路。", "淡墨题诗，正在云深处。", "别后作书频寄语。", "无忘林下萧萧雨。"]'),
('song-ci-852','念奴娇','李久善','宋','宋词','song-ci','念奴娇','[]','东君试手，向南枝著意，争先时节。',120,'宋词/ci.song.6000.json','["东君试手，向南枝著意，争先时节。", "纵有丹青谁便忍，轻点肌肤冰雪。", "色借琼瑰，香分兰麝，元自标孤洁。", "冲寒独秀，误他多少蜂蝶。", "缟练不染缁尘，算来□合是，广寒宫阙。", "未问阳和先占取，前村一溪风月。", "留取清芬，主张真态，驿使休轻折。", "梢头青子，异时风味甚别。"]'),
('song-ci-853','蝶恋花','李久善','宋','宋词','song-ci','蝶恋花','[]','莺掷垂杨，一点黄金溜。',11,'宋词/ci.song.6000.json','["莺掷垂杨，一点黄金溜。"]'),
('song-ci-854','蓦山溪','宝月','宋','宋词','song-ci','蓦山溪','[]','清江平淡，疏雨和烟染。',102,'宋词/ci.song.6000.json','["清江平淡，疏雨和烟染。", "春在广寒宫，付江梅、先开素艳。", "年年第一，相见越溪东，云体态，雪精神，不把年华占。", "山亭水榭，别恨多销黯。", "又是主人来，更不辜、香心一点。", "题诗才思，清似玉壶冰，轻回顾，落尊前，桃杏声华减。"]'),
('song-ci-855','鹊踏枝・蝶恋花','宝月','宋','宋词','song-ci','鹊踏枝・蝶恋花','[]','斜日平山寒已薄。',70,'宋词/ci.song.6000.json','["斜日平山寒已薄。", "雪过松梢，犹有残英落。", "晚色际天天似幕。", "一尊先与东风约。", "邀得红梅同宴乐。", "酒面融春，春满纤纤萼。", "客意为伊浑忘却。", "归船且傍花阴泊。"]'),
('song-ci-856','点绛唇','宝月','宋','宋词','song-ci','点绛唇','[]','春遇瑶池，长空飞下残英片。',50,'宋词/ci.song.6000.json','["春遇瑶池，长空飞下残英片。", "素光围练。", "寒透笙歌院。", "莫把寿阳，妆信传书箭。", "掩香面。", "汉宫寻遍。", "月里还相见。"]'),
('song-ci-857','失调名','宝月','宋','宋词','song-ci','失调名','[]','遥想天孙离别后，一宵欢会，暂停极杼。',18,'宋词/ci.song.6000.json','["遥想天孙离别后，一宵欢会，暂停极杼。"]'),
('song-ci-858','柳梢青','宝月','宋','宋词','song-ci','柳梢青','[]','脉脉春心，情人渐远，难托离愁。',61,'宋词/ci.song.6000.json','["脉脉春心，情人渐远，难托离愁。", "雨后寒轻，风前香软，春在梨花。", "行人倚棹天涯。", "酒醒处、残阳乱鸦。", "门外秋千，墙头红粉，深院谁家。"]'),
('song-ci-859','惜双双・惜分飞','宝月','宋','宋词','song-ci','惜双双・惜分飞','[]','庚岭香前亲写得。',68,'宋词/ci.song.6000.json','["庚岭香前亲写得。", "子细看、粉匀无迹。", "月殿休寻觅。", "姑射人来，知是曾相识。", "不要青春闲用力。", "也会寄、江南信息。", "著意应难摘。", "留与梨花，此并真颜色。"]'),
('song-ci-860','洞仙歌','宝月','宋','宋词','song-ci','洞仙歌','[]','广寒晓驾，姑射寻仙侣。',113,'宋词/ci.song.6000.json','["广寒晓驾，姑射寻仙侣。", "偷被霜华送将去。", "过越岭、栖息南枝，匀妆面、凝酥轻聚。", "爱横管孤度陇头声，尽拚得幽香，为君分付。", "水亭山驿，衰草斜阳，无限行人断肠处。", "尽为我、留得多情，何须待、春风相顾。", "任倒断深思向梨花，也无奈，寒食几番春雨。"]'),
('song-ci-861','念奴娇','苏仲及','宋','宋词','song-ci','念奴娇','[]','问梅何事，对岩东微笑，暗中轻馥。',120,'宋词/ci.song.6000.json','["问梅何事，对岩东微笑，暗中轻馥。", "韵绝姿高直下视，红紫端如童仆。", "绕树千回，临风三嗅，待与论心曲。", "何人还解，为伊特地青目。", "潇洒些个精神，谁怜孤瘦，正无语幽独。", "不许春知应自负，一生风月心足。", "傲雪难陪，欺霜无伴，耿耿横修竹。", "纷纷桃李，□□□□□□。"]'),
('song-ci-862','远朝归','赵耆孙','宋','宋词','song-ci','远朝归','[]','金谷先春，见乍开江梅，晶明玉腻。',114,'宋词/ci.song.6000.json','["金谷先春，见乍开江梅，晶明玉腻。", "珠帘院落，人静雨疏烟细。", "横斜带月，又别是、一般风味。", "金尊里。", "任遗英乱点，残粉低坠。", "惆怅杜陇当年，念水远天长，故人难寄。", "山城倦眼，无绪更看桃李。", "当时醉魄，算依旧、裴回花底。", "斜阳外。", "谩回首、画楼十二。"]'),
('song-ci-863','蓦山溪','费时举','宋','宋词','song-ci','蓦山溪','[]','黄苞初绽，谁向江头寄。',102,'宋词/ci.song.6000.json','["黄苞初绽，谁向江头寄。", "天赋与清香，笑红颜、呈妖逞媚。", "低垂花面，不与众争妍，春尚未。", "先群卉。", "独禀中央气。", "何须施巧，点缀芳丛里。", "只恐暗寻香，误蜂儿、归来故垒。", "玉纤攀处，金钏色相宜，朔风寒，空雪坠。", "痛赏休辞醉。"]'),
('song-ci-864','梅花引','刘均国','宋','宋词','song-ci','梅花引','[]','千里月，千山雪。',140,'宋词/ci.song.6000.json','["千里月，千山雪。", "梅花正落寒时节。", "一枝昂。", "一枝藏。", "清香冷艳、天赋与孤光。", "孤光似被珠帘隔。", "风度烟遮好颜色。", "粉垂垂。", "玉累累。", "先春挺秀，不管百花知。", "似霜结。", "与霜别。", "莫使幽人容易折。", "短墙边。", "矮窗前。", "横斜峭影，重叠斗婵娟。", "黄昏惯听楼头角。", "只恐听时零乱落。", "醉来看。", "醒来看。", "萦绊丽人，潇洒倚阑干。"]'),
('song-ci-865','凤凰台忆吹箫・凤凰台上忆吹箫','权无染','宋','宋词','song-ci','凤凰台忆吹箫・凤凰台上忆吹箫','[]','水国云乡，冰魂雪魄，朝来新领春还。',120,'宋词/ci.song.6000.json','["水国云乡，冰魂雪魄，朝来新领春还。", "便未怕、天暄蜂蝶，笛转羌蛮。", "一树垂云似画，香暗暗、白浅红班。", "东风外，清新雪月，潇洒溪山。", "应是飞琼弄玉，天不管、年年谪向人间。", "占芳事，铅华一洗，红叶俱残。", "多少烟愁雨恨，空脉脉、意远情闲。", "无人见，翠袖倚竹天寒。"]'),
('song-ci-866','乌夜啼','权无染','宋','宋词','song-ci','乌夜啼','[]','洗尽铅华污，玉颜自发轻红。',55,'宋词/ci.song.6000.json','["洗尽铅华污，玉颜自发轻红。", "无言雪月黄昏后，别是个丰容。", "骨瘦难禁消瘦，香寒不并芳秾。", "与君高却看花眼，红紫谩春风。"]'),
('song-ci-867','南歌子','权无染','宋','宋词','song-ci','南歌子','[]','照水金莲小，披风宝麝浮。',62,'宋词/ci.song.6000.json','["照水金莲小，披风宝麝浮。", "雪中开占百花头。", "一味潇潇洒洒、自风流。", "病态含春瘦，芳魂傍月愁。", "轻烟微雨更清幽。", "遮莫姚黄相并、也应羞。"]'),
('song-ci-868','南歌子','权无染','宋','宋词','song-ci','南歌子','[]','一点檀心紫，千重粉翅光。',62,'宋词/ci.song.6000.json','["一点檀心紫，千重粉翅光。", "蔷薇水浸淡鹅黄。", "别是一般风韵、断人肠。", "有艳难欺雪，无花可此香。", "寻思无计与幽芳。", "除是玉人清瘦、道家妆。"]'),
('song-ci-869','孤馆深沈','权无染','宋','宋词','song-ci','孤馆深沈','[]','琼英雪艳岭梅芳。',61,'宋词/ci.song.6000.json','["琼英雪艳岭梅芳。", "天付与清香。", "向腊后春前，解压万花，先占东阳。", "拟待折、一枝相赠，奈水远天长。", "对妆面、忍听羌笛，又还空断人肠。"]'),
('song-ci-870','永遇乐','南山居士','宋','宋词','song-ci','永遇乐','[]','满眼寒姿，桂蟾匀素，霜女同莹。',128,'宋词/ci.song.6000.json','["满眼寒姿，桂蟾匀素，霜女同莹。", "野屋喷香，池波弄影，仿佛鸾窥镜。", "一枝堪寄，天涯远信，惆怅塞鸿难倩。", "这情怀、厌厌怎向，无人伴我孤另。", "风凄露冷。", "仙郎此夜，若许枕衾相并。", "解吐芳心，绸缪共约，学取双交颈。", "好天难遇，从今一去，荏苒后期无定。", "把柔肠、千萦万断，为伊薄幸。"]'),
('song-ci-871','永遇乐','南山居士','宋','宋词','song-ci','永遇乐','[]','玉骨冰肌，野墙山径，烟雨萧索。',127,'宋词/ci.song.6000.json','["玉骨冰肌，野墙山径，烟雨萧索。", "公子豪华，贪红恋紫，谁分怜孤萼。", "想应窥见，潘毛相似，故把素怀相托。", "岂知人、年来闷损，被名利拘缚。", "当歌对酒，如痴如梦，欲笑啼痕先落。", "二十年前，欢娱一醉，不忍思量著。", "衾寒枕冷，不教孤另，不是自家情薄。", "枉将心、千尤万殢，算应殢著。"]'),
('song-ci-872','江神子・江城子','郭仲宣','宋','宋词','song-ci','江神子・江城子','[]','腊寒犹重见年芳。',86,'宋词/ci.song.6000.json','["腊寒犹重见年芳。", "为花忙。", "倚雕墙。", "准拟巡檐，一笑但清狂。", "冷蕊疏枝浑不奈，凭折取，泛清觞。", "扬州春梦两微茫。", "记娥妆。", "耿冰肠。", "春信全通，何用玉奁香。", "谁见月斜人去后，疏影乱，蘸寒塘。"]'),
('song-ci-873','连理枝','邵叔齐','宋','宋词','song-ci','连理枝','[]','淡泊疏篱隔。',86,'宋词/ci.song.6000.json','["淡泊疏篱隔。", "寂寞官桥侧。", "绿萼青枝风尘外，别是一般姿质。", "念天涯、憔悴各飘零，记初曾相识。", "雪里清寒逼。", "月下幽香袭。", "不似薄情无凭准，一去音书难得。", "看年年、时候不逾期，报阳和消息。"]'),
('song-ci-874','扑蝴蝶','邵叔齐','宋','宋词','song-ci','扑蝴蝶','[]','兰摧蕙折，霜重晓风恶。',92,'宋词/ci.song.6000.json','["兰摧蕙折，霜重晓风恶。", "长安何处，孤根谩自托。", "水寒断续溪桥，月破黄昏院落。", "相逢俨然瘦削。", "最萧索。", "星星蓬鬓，杳杳家山路正貌。", "攀枝嗅蕊，露陪清泪阁。", "已无蝶使蜂媒，不共莺期燕约。", "甘心伴人淡泊。"]'),
('song-ci-875','鹧鸪天','邵叔齐','宋','宋词','song-ci','鹧鸪天','[]','不比江梅粉作华。',64,'宋词/ci.song.6000.json','["不比江梅粉作华。", "天香肯作俗香夸。", "高悬蜡蓓蜂房密，遍挂金锺雁字斜。", "侵月影，上窗纱。", "中央颜色自仙家。", "玉人插向乌云畔，浑似灵犀正透芽。"]'),
('song-ci-876','减兰十梅・减字木兰花','李子正','宋','宋词','song-ci','减兰十梅・减字木兰花','[]','梅萼香嫩。',52,'宋词/ci.song.6000.json','["梅萼香嫩。", "雪里开时春粉润。", "雨蕊风枝。", "暗与黄昏取次宜。", "日边月下。", "休问初开兼欲谢。", "却最妖娆。", "不似群花春正娇。"]'),
('song-ci-877','减兰十梅・减字木兰花','李子正','宋','宋词','song-ci','减兰十梅・减字木兰花','[]','东风吹暖。',52,'宋词/ci.song.6000.json','["东风吹暖。", "轻动枝头娇艳颤。", "成片惊飞。", "不是城南画角吹。", "香英飘处。", "定向寿阳妆阁去。", "莫损柔柯。", "今日清香远更多。"]'),
('song-ci-878','减兰十梅・减字木兰花','李子正','宋','宋词','song-ci','减兰十梅・减字木兰花','[]','潇潇细雨。',52,'宋词/ci.song.6000.json','["潇潇细雨。", "雨歇芳菲犹淡伫。", "密洒轻笼。", "湿遍柔枝香更浓。", "琼腮微腻。", "疑是凝酥初点缀。", "冷艳相宜。", "不似梨花带雨时。"]'),
('song-ci-879','减兰十梅・减字木兰花','李子正','宋','宋词','song-ci','减兰十梅・减字木兰花','[]','六花飞素。',52,'宋词/ci.song.6000.json','["六花飞素。", "飘入枝头无觅处。", "密缀轻堆。", "只似香苞次第开。", "栏边欲坠。", "姑射山头人半醉。", "墙外低垂。", "窥送佳人粉再吹。"]'),
('song-ci-880','减兰十梅・减字木兰花','李子正','宋','宋词','song-ci','减兰十梅・减字木兰花','[]','寒蟾初满。',52,'宋词/ci.song.6000.json','["寒蟾初满。", "正是枝头开烂熳。", "素质笼明。", "多少风姿无限情。", "暗香疏影。", "冰麝萧萧山驿静。", "浅蕊轻枝。", "酒醒更阑梦断时。"]'),
('song-ci-881','减兰十梅・减字木兰花','李子正','宋','宋词','song-ci','减兰十梅・减字木兰花','[]','腾腾初照。',52,'宋词/ci.song.6000.json','["腾腾初照。", "半拆琼苞还似笑。", "莫近柔条。", "只恐凝酥暖欲消。", "三竿已上。", "点缀胭脂红荡漾。", "刚道宜寒。", "不似前村雪里看。"]'),
('song-ci-882','减兰十梅・减字木兰花','李子正','宋','宋词','song-ci','减兰十梅・减字木兰花','[]','急催银漏。',52,'宋词/ci.song.6000.json','["急催银漏。", "渐渐纱窗明欲透。", "点检花枝。", "晓笛吹时几片飞。", "淡烟初破。", "仿佛夜来飞几朵。", "浅粉馀香。", "晨起佳人带晓妆。"]'),
('song-ci-883','减兰十梅・减字木兰花','李子正','宋','宋词','song-ci','减兰十梅・减字木兰花','[]','天寒欲暮。',52,'宋词/ci.song.6000.json','["天寒欲暮。", "别有一般姿媚处。", "半载斜阳。", "宝鉴微开试晚妆。", "淡烟轻处。", "渐近黄昏香暗渡。", "休怕春寒。", "秉烛重来子细看。"]'),
('song-ci-884','减兰十梅・减字木兰花','李子正','宋','宋词','song-ci','减兰十梅・减字木兰花','[]','阳和初布。',52,'宋词/ci.song.6000.json','["阳和初布。", "入萼春红才半露。", "暖律潜催。", "与占百花头上开。", "香英微吐。", "折赠一枝人已去。", "杨柳贪眠。", "不道春风已暗传。"]'),
('song-ci-885','减兰十梅・减字木兰花','李子正','宋','宋词','song-ci','减兰十梅・减字木兰花','[]','香苞渐少。',52,'宋词/ci.song.6000.json','["香苞渐少。", "满地残英寒不扫。", "传语东君。", "分付南枝桃李春。", "东风吹暖。", "南北枝头开烂熳。", "一任飘吹。", "已占东风第一枝。"]'),
('song-ci-886','忆秦娥','房舜卿','宋','宋词','song-ci','忆秦娥','[]','与君别。',56,'宋词/ci.song.6000.json','["与君别。", "相思一夜梅花发。", "梅花发。", "凄凉南浦，断桥斜月。", "盈盈微步凌波袜。", "东风笑倚天涯阔。", "天涯阔。", "一声羌管，暮云愁绝。"]'),
('song-ci-887','玉交枝・忆秦娥','房舜卿','宋','宋词','song-ci','玉交枝・忆秦娥','[]','蕙死兰枯待返魂。',54,'宋词/ci.song.6000.json','["蕙死兰枯待返魂。", "暗香梅上又重闻。", "粉妆额子，多少画难真。", "竹外冰清斜倒影，江头雪里暗藏春。", "千锺玉酒，休更待飘零。"]'),
('song-ci-888','鹧鸪天','石耆翁','宋','宋词','song-ci','鹧鸪天','[]','借问枝头昨夜春。',64,'宋词/ci.song.6000.json','["借问枝头昨夜春。", "已传消息到柴门。", "频看秀色无多艳，拖得清香不见痕。", "山矗矗，水粼粼。", "村南村北冷销魂。", "人间不识春风面，羞见瑶台破月明。"]'),
('song-ci-889','蝶恋花','石耆翁','宋','宋词','song-ci','蝶恋花','[]','半夜六龙飞海峤。',70,'宋词/ci.song.6000.json','["半夜六龙飞海峤。", "滉漾鳌波，露出珊瑚小。", "玉粉枝头春意早。", "东风未绿瀛洲草。", "姑射仙人真窃窕。", "净练明妆，如伴商岩老。", "梦入水云闲缥缈。", "一楼明月千山晓。"]'),
('song-ci-890','西江月','杜安道','宋','宋词','song-ci','西江月','[]','晓镜初妆玉粉，轻风暗递幽香。',58,'宋词/ci.song.6000.json','["晓镜初妆玉粉，轻风暗递幽香。", "闲随月影到寒塘。", "忘却人间天上。", "雪意空惊春意，孤芳已断年芳。", "从教驿使为伊忙。", "乞个寿阳宫样。"]'),
('song-ci-891','独脚令・忆王孙','史远道','宋','宋词','song-ci','独脚令・忆王孙','[]','墙头梅蕊一枝新。',36,'宋词/ci.song.6000.json','["墙头梅蕊一枝新。", "宋玉东邻算未真。", "折与冰姿绰约人。", "怯霜晨。", "桃李粉粉不当春。"]'),
('song-ci-892','玉楼春','郭仲循','宋','宋词','song-ci','玉楼春','[]','靓妆才学春无价。',64,'宋词/ci.song.6000.json','["靓妆才学春无价。", "腮粉额黄宫样画。", "妖娆闲倚曲阑边，孤净不胜微月下。", "牵情群蕊临风亚。", "惜恐苍苔和雨借。", "何如相傍玉楼人，芳酒绣筵红烛夜。"]'),
('song-ci-893','临江仙','范梦龙','宋','宋词','song-ci','临江仙','[]','试问前村深雪里，小梅未放云英。',70,'宋词/ci.song.6000.json','["试问前村深雪里，小梅未放云英。", "阳和先到锦官城。", "南枝初破粉，东阁有馀清。", "人在高楼横怨管，寄将陇客新声。", "西园下晚看飞琼。", "春风催结子，金鼎待调羹。"]'),
('song-ci-894','渔家傲','薛几圣','宋','宋词','song-ci','渔家傲','[]','雪月照梅溪畔路。',72,'宋词/ci.song.6000.json','["雪月照梅溪畔路。", "幽姿背立无言语。", "冷浸瘦枝清浅处。", "香暗度。", "妆成处士横斜句。", "浑似玉人常淡伫。", "菱花相对成清楚。", "谁解小图先画取。", "天欲曙。", "恐随月色云间去。"]'),
('song-ci-895','遂宁好','马咸','宋','宋词','song-ci','遂宁好','[]','遂宁好，胜地产糖霜。',26,'宋词/ci.song.6000.json','["遂宁好，胜地产糖霜。", "不待千年成琥珀，真疑六月冻琼浆。"]'),
('song-ci-896','点绛唇','洪皓','宋','宋词','song-ci','点绛唇','[]','不假施朱，鹤翎初试轻红亚。',50,'宋词/ci.song.6000.json','["不假施朱，鹤翎初试轻红亚。", "为栽堂下。", "更咏樵人画。", "绿叶青枝，辨认诗亏价。", "休催也。", "忍寒郊野。", "留待东坡马。"]'),
('song-ci-897','点绛唇','洪皓','宋','宋词','song-ci','点绛唇','[]','耐久芳馨，拟将蜂蜡龙涎亚。',50,'宋词/ci.song.6000.json','["耐久芳馨，拟将蜂蜡龙涎亚。", "化工裁下。", "风韵胜如画。", "鼻观先通，顿减沈檀价。", "思量也。", "梦游吴野。", "凭仗神为马。"]'),
('song-ci-898','减字木兰花','洪皓','宋','宋词','song-ci','减字木兰花','[]','蜂房馀液。',52,'宋词/ci.song.6000.json','["蜂房馀液。", "写就南枝凌正色。", "折干垂芳。", "点缀如生秘暗香。", "寿阳妆样。", "纤手拈来簪髻上。", "恍若还家。", "暂睹真花压百花。"]'),
('song-ci-899','蓦山溪','洪皓','宋','宋词','song-ci','蓦山溪','[]','鳌山凤阙，多少飞琼侣。',102,'宋词/ci.song.6000.json','["鳌山凤阙，多少飞琼侣。", "顒俟翠华临，庆新春、金波盈五。", "莲灯开遍，侍从尽登楼，簪花赴。", "传柑处。", "咫尺聆天语。", "厌厌欲罢，宣劝犹旁午。", "扶上玉花骢，更踟蹰、梨园四部。", "追思往事，一夕九回肠，皇恩溥。", "归期阻。", "引领江南路。"]'),
('song-ci-900','木兰花慢','洪皓','宋','宋词','song-ci','木兰花慢','[]','属三秋正半，暮云敛、月舒圆。',124,'宋词/ci.song.6000.json','["属三秋正半，暮云敛、月舒圆。", "误惊鹤鸣皋，栖乌绕树，魑魅惊旋。", "寻常对三五夜，纵清光、皎洁未精妍。", "须是风高气爽，一轮绝后光前。", "无偏。", "故国迢迢，千万里、共婵娟。", "但陟屺瞻驰，高楼念远，宁不凄然。", "天涯更新雁过，□哀嗷、出塞影联翩。", "空俾骚人叹羡，向隅耿耿无眠。"]'),
('song-ci-901','木兰花慢','洪皓','宋','宋词','song-ci','木兰花慢','[]','对金商暮节，此时客、意难忘。',124,'宋词/ci.song.6000.json','["对金商暮节，此时客、意难忘。", "正卉木凋零，蛩螀韵切，宾雁南翔。", "东篱有黄蕊绽，是幽人、最爱折浮觞。", "须信凌霜可赏，任他落帽清狂。", "茫茫。", "去国三年，行万里、过重阳。", "奈眷恋庭闱，矜怜幼稚，坠泪回肠。", "凭栏处空引领，望江南、不见转凄凉。", "羁旅登高易感，况於留滞殊方。"]'),
('song-ci-902','浣溪沙','洪皓','宋','宋词','song-ci','浣溪沙','[]','丧乱佳辰不易攀。',48,'宋词/ci.song.6000.json','["丧乱佳辰不易攀。", "四逢寒食尽投闲。", "踏青无处想家山。", "麟殿阻趋陪内宴，萱堂遥忆侍慈颜。", "感时双泪滴潺潺。"]'),
('song-ci-903','浣溪沙','洪皓','宋','宋词','song-ci','浣溪沙','[]','南北渝盟久未和。',48,'宋词/ci.song.6000.json','["南北渝盟久未和。", "斯民涂炭死亡多。", "不知何日戢干戈。", "赖有兴王如世祖，况闻谋帅得廉颇。", "蔺卿全璧我蹉跎。"]'),
('song-ci-904','临江仙','洪皓','宋','宋词','song-ci','临江仙','[]','冷落天涯今一纪，谁怜万里无家。',70,'宋词/ci.song.6000.json','["冷落天涯今一纪，谁怜万里无家。", "三闾憔悴赋怀沙。", "思新增怅望，吊影觉敧斜。", "兀坐书堂真可怪，销忧殢酒难赊。", "因人成事耻矜夸。", "何时还使节，踏雪看梅花。"]'),
('song-ci-905','江梅引・江城梅花引','洪皓','宋','宋词','song-ci','江梅引・江城梅花引','[]','天涯除馆忆江梅。',108,'宋词/ci.song.6000.json','["天涯除馆忆江梅。", "几枝开。", "使南来。", "还带馀杭、春信到燕台。", "准拟寒英聊慰远，隔山水，应销落，赴诉谁。", "空恁遐想笑摘蕊。", "断回肠，思故里。", "漫弹绿绮。", "引三弄、不觉魂飞。", "更听胡笳、哀怨泪沾衣。", "乱插繁花须异日，待孤讽，怕东风，一夜吹。"]'),
('song-ci-906','江梅引・江城梅花引','洪皓','宋','宋词','song-ci','江梅引・江城梅花引','[]','春还消息访寒梅。',108,'宋词/ci.song.6000.json','["春还消息访寒梅。", "赏初开。", "梦吟来。", "映雪衔霜、清绝绕风台。", "可怕长洲桃李妒，度香远，惊愁眼，欲媚谁。", "曾动诗兴笑冷蕊。", "效少陵，惭下里。", "万株连绮。", "叹金谷、人坠莺飞。", "引领罗浮、翠羽幻青衣。", "月下花神言极丽，且同醉，休先愁，玉笛吹。"]'),
('song-ci-907','江梅引・江城梅花引','洪皓','宋','宋词','song-ci','江梅引・江城梅花引','[]','重闺佳丽最怜梅。',108,'宋词/ci.song.6000.json','["重闺佳丽最怜梅。", "牖春开。", "学妆来。", "争粉翻光、何遽落梳台。", "笑坐雕鞍歌古曲，催玉柱，金卮满，劝阿谁。", "贪为结子藏暗蕊。", "敛蛾眉，隔千里。", "旧时罗绮。", "已零散、沈谢双飞。", "不见娇姿、真悔著单衣。", "若作和羹休讶晚，堕烟雨，任春风，片片吹。"]'),
('song-ci-908','江梅引・江城梅花引','洪皓','宋','宋词','song-ci','江梅引・江城梅花引','["\u897f\u6e56"]','去年湖上雪欺梅。',108,'宋词/ci.song.6000.json','["去年湖上雪欺梅。", "片云开。", "月飞来。", "雪月光中、无处认楼台。", "今岁梅开依旧雪，人如月，对花笑，还有谁。", "一枝两枝三四蕊。", "想西湖，今帝里。", "彩笺烂绮。", "孤山外、目断云飞。", "坐久花寒、香露湿人衣。", "谁作叫云横短玉，三弄彻，对东风，和泪吹。"]'),
('song-ci-909','渔家傲','洪皓','宋','宋词','song-ci','渔家傲','[]','臂上萸囊悬已满。',72,'宋词/ci.song.6000.json','["臂上萸囊悬已满。", "杯中菊蕊浮无限。", "纵使登高宁忍看。", "昏复旦。", "心肠似铁还须断。", "岁月川流难把玩。", "平生万事思量遍。", "但对割愁山似剑。", "聊自劝。", "东坡海岛犹三见。"]'),
('song-ci-910','渔家傲','洪皓','宋','宋词','song-ci','渔家傲','[]','圃蕙庭桐凋大半。',72,'宋词/ci.song.6000.json','["圃蕙庭桐凋大半。", "西风不借行人便。", "不用留题明月观。", "西园宴。", "颜酡浪说觞无算。", "万斛羁愁推不远。", "千杯鲁酒何曾见。", "却羡南宾凫与雁。", "行不乱。", "哀鸣直到翻江岸。"]'),
('song-ci-911','渔家傲','洪皓','宋','宋词','song-ci','渔家傲','[]','□□□□□□□。',72,'宋词/ci.song.6000.json','["□□□□□□□。", "□□□□□□□。", "□□□□□□□。", "□□□。", "□□□□□□□。", "正念当筵人已换。", "疏砧又捣谁家练。", "独坐愁吟搔首乱。", "肠欲断。", "凭高不见吴宫殿。"]'),
('song-ci-912','渔家傲','洪皓','宋','宋词','song-ci','渔家傲','[]','侍宴乐游游赏惯。',72,'宋词/ci.song.6000.json','["侍宴乐游游赏惯。", "今兹吊影难呼伴。", "欲上望乡台复倦。", "愁满眼。", "琵琶莫写昭君怨。", "满目平芜无足玩。", "南冠未税徒增欢。", "万里庭闱安否断。", "形魂散。", "此身何暇穷游观。"]'),
('song-ci-913','忆仙姿・如梦令','洪皓','宋','宋词','song-ci','忆仙姿・如梦令','[]','试问春归何处。',40,'宋词/ci.song.6000.json','["试问春归何处。", "蜂懒蝶忙来去。", "婉娩倦寻芳，偶遂涉园成趣。", "莺语。", "莺语。", "唤起小鱼吹絮。"]'),
('song-ci-914','忆仙姿・如梦令','洪皓','宋','宋词','song-ci','忆仙姿・如梦令','[]','乍到园亭清处。',40,'宋词/ci.song.6000.json','["乍到园亭清处。", "面面此君忘去。", "把酒挹幽人，仰止七贤高趣。", "吴语。", "吴语。", "弗见满城风絮。"]'),
('song-ci-915','忆仙姿・如梦令','洪皓','宋','宋词','song-ci','忆仙姿・如梦令','[]','小憩书斋胡处。',40,'宋词/ci.song.6000.json','["小憩书斋胡处。", "闲取响泉调去。", "是事不关心，自得曲中深趣。", "无语。", "无语。", "回首暮云飞絮。"]'),
('song-ci-916','忆仙姿・如梦令','洪皓','宋','宋词','song-ci','忆仙姿・如梦令','[]','燕敞画堂深处。',40,'宋词/ci.song.6000.json','["燕敞画堂深处。", "夜艾不知归去。", "忍醉作歌词，要引遏云奇趣。", "娇语。", "娇语。", "似劝老人休絮。"]'),
('song-ci-917','水调歌头','蔡伸','宋','宋词','song-ci','水调歌头','[]','醉击玉壶缺，恨写绿琴哀。',114,'宋词/ci.song.6000.json','["醉击玉壶缺，恨写绿琴哀。", "悠悠往事谁问，离思渺难裁。", "绿野堂前桃李，燕子楼中歌吹，那忍首重回。", "唯有旧时月，远远逐人来。", "小庭空，清夜永，独徘徊。", "伴人幽怨，一枝潇洒陇头梅。", "肠断云帆西去，目送烟波东注，千里接长淮。", "为我将双泪，好过楚王台。"]'),
('song-ci-918','水调歌头','蔡伸','宋','宋词','song-ci','水调歌头','[]','亭皋木叶下，原隰菊花黄。',114,'宋词/ci.song.6000.json','["亭皋木叶下，原隰菊花黄。", "凭高满眼秋意，时节近重阳。", "追想彭门往岁，千骑云屯平野，高宴古球场。", "吊古论兴废，看剑引杯长。", "感流年，思往事，重凄凉。", "当时坐间英俊，强半已凋亡。", "慨念平生豪放，自笑如今霜鬓，漂泊水云乡。", "已矣功名志，此意付清觞。"]'),
('song-ci-919','水调歌头','蔡伸','宋','宋词','song-ci','水调歌头','[]','相逢非草草，分袂太匆匆。',114,'宋词/ci.song.6000.json','["相逢非草草，分袂太匆匆。", "征裘泪痕浥遍，眸子怯酸风。", "天际孤帆难驻，柳外香軿望断，云雨各西东。", "回首重城远，楼观暮烟中。", "黯销魂，思陈事，已成空。", "东郊胜赏，归路骑马踏残红。", "月下一樽芳酒，凭阑几曲清歌，别后少人同。", "为问桃花脸，一笑为谁容。"]'),
('song-ci-920','满庭芳','蔡伸','宋','宋词','song-ci','满庭芳','[]','烟锁长堤，云横孤屿，断桥流水溶溶。',118,'宋词/ci.song.6000.json','["烟锁长堤，云横孤屿，断桥流水溶溶。", "凭阑凝望，远目送征鸿。", "桃叶溪边旧事，如春梦、回首无踪。", "难忘处，紫薇花下，清夜一尊同。", "东城，携手地，寻芳选胜，赏遍珍丛。", "念紫箫声阕，燕子楼空。", "好是卢郎未老，佳期在、端有相逢。", "重重恨，聊凭红叶，和泪寄西风。"]'),
('song-ci-921','满庭芳','蔡伸','宋','宋词','song-ci','满庭芳','[]','风卷龙沙，云垂平野，晚来密雪交飞。',118,'宋词/ci.song.6000.json','["风卷龙沙，云垂平野，晚来密雪交飞。", "坐看阑槛，琼蕊遍寒枝。", "妆点兰房景致，金铺掩、帘幕低垂。", "红炉畔，浅斟低唱，天色正相宜。", "更阑，人半醉，香肌玉暖，宝髻云敧。", "又何须高会，梁苑瑶池。", "堪笑子猷访戴，清兴尽、忍冻空回。", "仍休羡，渔人江上，披得一蓑归。"]'),
('song-ci-922','满庭芳','蔡伸','宋','宋词','song-ci','满庭芳','[]','鹦鹉洲边，芙蓉城下，迥然水秀山明。',118,'宋词/ci.song.6000.json','["鹦鹉洲边，芙蓉城下，迥然水秀山明。", "小舟双桨，特地访云英。", "惊破兰衾好梦，开朱户、一笑相迎。", "良宵永，南窗皓月，依旧照娉婷。", "别来，无限恨，持杯欲语，恍若魂惊。", "念霎时相见，又惨离情。", "还是匆匆去也，重携手、密语叮咛。", "佳期在，宝钗鸾镜，端不负平生。"]'),
('song-ci-923','满庭芳','蔡伸','宋','宋词','song-ci','满庭芳','[]','秦洞花迷，巫阳梦断，夜来曾到蓝桥。',118,'宋词/ci.song.6000.json','["秦洞花迷，巫阳梦断，夜来曾到蓝桥。", "洞房深处，重许见云翘。", "惠帐残灯耿耿，纱窗外、疏雨萧萧。", "双心字，重衾小枕，玉困不胜娇。", "寻常，愁夜永，今宵更漏，弹指明朝。", "叙深情幽怨，泪裛香绡。", "记取于飞厚约，丹山愿、别选安巢。", "骖鸾去，青霄路稳，明月共吹箫。"]'),
('song-ci-924','满庭芳','蔡伸','宋','宋词','song-ci','满庭芳','[]','玉鼎翻香，红炉叠胜，绮窗疏雨潇潇。',118,'宋词/ci.song.6000.json','["玉鼎翻香，红炉叠胜，绮窗疏雨潇潇。", "故人相过，情话款良宵。", "酒晕微红衬脸，横波浸、满眼春娇。", "云屏掩，鸳鸯被暖，敧枕听寒潮。", "如今，成别恨，临风对月，总是无聊。", "念伤心南陌，执手河桥。", "还似一声春梦，离魂断、楚些难招。", "佳期在，踏青时候，花底听鸣镳。"]'),
('song-ci-925','苏武慢','蔡伸','宋','宋词','song-ci','苏武慢','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','雁落平沙，烟笼寒水，古垒鸣笳声断。',136,'宋词/ci.song.6000.json','["雁落平沙，烟笼寒水，古垒鸣笳声断。", "青山隐隐，败叶萧萧，天际暝鸦零乱。", "楼上黄昏，片帆千里归程，年华将晚。", "望碧云空暮，佳人何处，梦魂俱远。", "忆旧游、邃馆朱扉，小园香径，尚想桃花人面。", "书盈锦轴，恨满金徽，难写寸心幽怨。", "两地离愁，一尊芳酒，凄凉危阑倚遍。", "尽迟留、凭仗西风，吹乾泪眼。"]'),
('song-ci-926','飞雪满群山','蔡伸','宋','宋词','song-ci','飞雪满群山','[]','冰结金壶，寒生罗幕，夜阑霜月侵门。',131,'宋词/ci.song.6000.json','["冰结金壶，寒生罗幕，夜阑霜月侵门。", "翠筠敲竹，疏梅弄影，数声雁过南云。", "酒醒敧粲枕，怆犹有、残妆泪痕。", "绣衾孤拥，馀香未减，犹是那时熏。", "长记得、扁舟寻旧约，听小窗风雨，灯火昏昏。", "锦裀才展，琼签报曙，宝钗又是轻分。", "黯然携手处，倚朱箔、愁凝黛颦。", "梦回云散，山遥水远空断魂。"]'),
('song-ci-927','飞雪满群山','蔡伸','宋','宋词','song-ci','飞雪满群山','[]','绝代佳人，幽居空谷，绮窗森玉猗猗。',131,'宋词/ci.song.6000.json','["绝代佳人，幽居空谷，绮窗森玉猗猗。", "小舟双桨，重寻旧约，洞房宛是当时。", "夜阑红烛暗，黯相对、浑如梦里。", "旋烘鸳锦，尘生绣帐，香减缕金衣。", "须信有、盟言同皎日，□利牵名役，事与君违。", "□君已许，今生来世，两情到此奚疑。", "彩鸾须凤友，算何日、丹山共归。", "未酬深愿，绵绵此恨无尽期。"]'),
('song-ci-928','水龙吟','蔡伸','宋','宋词','song-ci','水龙吟','[]','画桥流水桃溪路，别是壶中佳致。',125,'宋词/ci.song.6000.json','["画桥流水桃溪路，别是壶中佳致。", "南楼夜月，东窗疏雨，金莲共醉。", "人静回廊，并肩携手，玉芝香里。", "念紫箫声断，巫阳梦觉，人何在、花空委。", "寂寞危栏独倚。", "望仙乡、水云无际。", "芸房花院，重来空锁，苍苔满地。", "物是人非，小池依旧，彩鸳双戏。", "念当时风月，如今怀抱有盈襟泪。"]'),
('song-ci-929','蓦山溪','蔡伸','宋','宋词','song-ci','蓦山溪','[]','孤城暮角，落日边声静。',102,'宋词/ci.song.6000.json','["孤城暮角，落日边声静。", "醉袖拂危阑，对天末、孤云愁凝。", "吴津楚望，表里抱江山，山隐隐，水迢迢，满目江南景。", "羁怀易感，往事伤重省。", "罗袂浥残香，鬓星星、忍窥清镜。", "琼英好在，应念玉关遥，凝泪眼，下层楼，回首平林暝。"]'),
('song-ci-930','蓦山溪','蔡伸','宋','宋词','song-ci','蓦山溪','[]','疏梅雪里，已报东君信。',102,'宋词/ci.song.6000.json','["疏梅雪里，已报东君信。", "冷艳与清香，似一个、人人标韵。", "晚来特地，酌酒慰幽芳，携素手，摘纤枝，插向乌云鬓。", "老来世事，百种皆消尽。", "荣利等浮云，谩汲汲、徒劳方寸。", "花前眼底，幸有赏心人，歌金缕，醉瑶卮，此外君休问。"]'),
('song-ci-931','蓦山溪','蔡伸','宋','宋词','song-ci','蓦山溪','[]','书云今旦，雪霁严凝候。',102,'宋词/ci.song.6000.json','["书云今旦，雪霁严凝候。", "玉辇想回銮，正花覆、千官锦绣。", "周南留滞，清梦绕觚稜，心耿耿，路迢迢，此际空回首。", "华堂荐寿。", "玉笋持椒酒。", "一曲啭春莺，更祝我、膺时纳佑。", "功名富贵，老去已灰心，唯只愿，捧觞人，岁岁长依旧。"]'),
('song-ci-932','蓦山溪','蔡伸','宋','宋词','song-ci','蓦山溪','[]','金风玉露，时节清秋候。',102,'宋词/ci.song.6000.json','["金风玉露，时节清秋候。", "散发步闲亭，对荧荧、一天星斗。", "悲歌慷慨，念远复伤时，心耿耿，发星星，倚杖空搔首。", "区区恋豆。", "岂是甘牛后。", "时命未来间，且只得、低眉袖手。", "男儿此志，肯向死前休，无限事，几多愁，总付杯中酒。"]'),
('song-ci-933','念奴娇','蔡伸','宋','宋词','song-ci','念奴娇','["\u957f\u6c5f"]','凌空宝观，乍登临、多少伤离情味。',119,'宋词/ci.song.6000.json','["凌空宝观，乍登临、多少伤离情味。", "淼淼烟波吴会远，极目江淮无际。", "槛外长江，楼中红袖，淡荡秋光里。", "一声横吹，半滩鸥鹭起。", "因念邃馆香闺，玉肌花貌，有盈盈仙子。", "弄水题红传密意，宝墨银钩曾寄。", "泪粉香销，碧云□杳，脉脉人千里。", "一弯新月，断肠危栏独倚。"]'),
('song-ci-934','念奴娇','蔡伸','宋','宋词','song-ci','念奴娇','[]','岁华晼晚，念羁怀多感，佳会难卜。',120,'宋词/ci.song.6000.json','["岁华晼晚，念羁怀多感，佳会难卜。", "草草杯盘聊话旧，同剪西窗寒烛。", "翠袖笼香，双蛾敛恨，低按新翻曲。", "无情风雨，断肠更漏催促。", "匆匆归骑难留，鸾屏鸳被，忍良宵孤宿。", "回首幽欢成梦境，唯觉衣襟芬馥。", "海约山盟，云情雨意，何日教心足。", "不如不见，为君一味愁蹙。"]'),
('song-ci-935','念奴娇','蔡伸','宋','宋词','song-ci','念奴娇','[]','画堂宴阕，望重帘不卷，轻哑朱户。',121,'宋词/ci.song.6000.json','["画堂宴阕，望重帘不卷，轻哑朱户。", "悄悄回廊，惊渐闻、蟋蟀凌波微步。", "酒力融春，香风暗度，携手偎金缕。", "低低笑问，睡得真个稳否。", "因念隔阔经年，除非魂梦里，有时相遇。", "天意怜人心在了，岂信关山遐阻。", "晓色朦胧，柔情倦恋，后约叮咛语。", "休教肠断，楚台朝暮云雨。"]'),
('song-ci-936','念奴娇','蔡伸','宋','宋词','song-ci','念奴娇','[]','当年豪放，况朋侪俱是，一时英杰。',121,'宋词/ci.song.6000.json','["当年豪放，况朋侪俱是，一时英杰。", "逸气凌云，佳丽地、独占春花秋月。", "冶叶倡条，寻芳选胜，是处曾攀折。", "昔游如梦，镜中空叹华发。", "邂逅萍梗相逢，十年往事，忍尊前重说。", "茂绿成阴春又晚，谁解丁香千结。", "宝瑟弹愁，玉壶敲怨，触目堪愁绝。", "酒阑人静，为君肠断时节。"]'),
('song-ci-937','念奴娇','蔡伸','宋','宋词','song-ci','念奴娇','[]','轻雷骤雨，洗千岩浓翠，层峦森列。',121,'宋词/ci.song.6000.json','["轻雷骤雨，洗千岩浓翠，层峦森列。", "衣袂凉生，丛竹外、时有飞萤明灭。", "云浪鳞鳞，兰舟泛泛，共载一轮月。", "五湖当日，未应此段奇绝。", "归路横玉惊鸾，叫云清似水，悠扬天末。", "玉宇琼林凝望处，依约广寒宫阙。", "老去情锺，此心仍在，未肯甘华发。", "清欢留作，异时嘉话重说。"]'),
('song-ci-938','雨中花慢','蔡伸','宋','宋词','song-ci','雨中花慢','[]','寓目伤怀，逢欢感旧，年来事事疏慵。',117,'宋词/ci.song.6000.json','["寓目伤怀，逢欢感旧，年来事事疏慵。", "叹身心业重，赋得情浓。", "况是离多会少，难忘雨迹云踪。", "断无锦字，双鳞杳杳，新雁雍雍。", "良宵孤枕，人远天涯，除非梦里相逢。", "相逢处，愁红敛黛，还又匆匆。", "回首绿窗朱户，可怜明月清风。", "断肠风月，关河有尽，此恨无穷。"]'),
('song-ci-939','喜迁莺','蔡伸','宋','宋词','song-ci','喜迁莺','[]','青娥呈瑞。',127,'宋词/ci.song.6000.json','["青娥呈瑞。", "正惨惨暮寒，同云千里。", "剪水飞花，渐渐瑶英，密洒翠筠声细。", "邃馆静深，金铺半掩，重帘垂地。", "明窗外。", "伴疏梅潇洒，玉肌香腻。", "幽人当此际。", "醒魂照影，永漏愁无寐。", "强拊清尊，慵添宝鸭，谁会黯然情味。", "幸有赏心人，奈咫尺、重门深闭。", "今夜里。", "算忍教孤负，浓香鸳被。"]'),
('song-ci-940','忆瑶姬','蔡伸','宋','宋词','song-ci','忆瑶姬','[]','微雨初晴。',128,'宋词/ci.song.6000.json','["微雨初晴。", "洗瑶空万里，月挂冰轮。", "广寒宫阙近，望素娥缥缈，丹桂亭亭。", "金盘露冷，玉树风轻。", "倍觉秋思清。", "念去年曾共吹箫侣，同赏蓬瀛。", "奈此夜、旅泊江城。", "谩花光眩目，绿酒如渑。", "幽怀终有恨，恨绮窗清影，虚照娉婷。", "蓝桥□杳，楚馆云深。", "似凭归梦去，强就枕，无奈孤衾梦易惊。"]'),
('song-ci-941','丑奴儿慢・采桑子慢','蔡伸','宋','宋词','song-ci','丑奴儿慢・采桑子慢','[]','明眸秀色，别是天真潇洒。',110,'宋词/ci.song.6000.json','["明眸秀色，别是天真潇洒。", "更鬓发堆云，玉脸淡拂轻霞。", "醉里精神，众中标格谁能画。", "当时携手，花笼淡月，重门深亚。", "巫峡梦回，已成陈事，岂堪重话。", "谩赢得、罗襟清泪，鬓边霜华。", "念□伤怀，凭阑烟水渺无涯。", "秦源目断，碧云暮合，难认仙家。"]'),
('song-ci-942','满江红','蔡伸','宋','宋词','song-ci','满江红','[]','人倚金铺，颦翠黛、盈盈堕睫。',115,'宋词/ci.song.6000.json','["人倚金铺，颦翠黛、盈盈堕睫。", "话别处、留连无计，语娇声咽。", "十幅云帆风力满，一川烟暝波光阔。", "但回首、极目望高城，弹清血。", "并兰舟，停画楫。", "曾共醉，津亭月。", "销魂处，今夜月圆人缺。", "楚岫云归空怅望，汉皋佩解成轻别。", "最苦是、拍塞满怀愁，无人说。"]'),
('song-ci-943','婆罗门引','蔡伸','宋','宋词','song-ci','婆罗门引','[]','素秋向晚，岁华分付木芙蓉。',93,'宋词/ci.song.6000.json','["素秋向晚，岁华分付木芙蓉。", "萧萧红蓼西风。", "记得当时撷翠，拥手绕芳丛。", "念吹箫人去，明月楼空。", "遥山万重。", "望寸碧、想眉峰。", "翠钿琼珰谩好，谁适为容。", "凄凉怀抱，算此际、唯我与君同。", "凝泪际、目送征鸿。"]'),
('song-ci-944','青玉案','蔡伸','宋','宋词','song-ci','青玉案','[]','参差弱柳长堤路。',78,'宋词/ci.song.6000.json','["参差弱柳长堤路。", "柳外征帆去。", "皓齿明眸娇态度。", "回头一梦，断肠千里，不到相逢地。", "来时约略春将暮。", "幽恨空馀锦中句。", "小院重门深几许。", "桃花依旧，出墙临水，乱落如红雨。"]'),
('song-ci-945','青玉案','蔡伸','宋','宋词','song-ci','青玉案','[]','鸾凰本是和鸣友。',80,'宋词/ci.song.6000.json','["鸾凰本是和鸣友。", "奈无计、长相守。", "云雨匆匆分袂后。", "彩舟东去，橹声呕轧，目断长堤柳。", "涓涓清泪轻绡透。", "残粉馀香尚依旧。", "独上南楼空回首。", "夜来明月，怎知今夜，少个人携手。"]'),
('song-ci-946','浣溪沙','蔡伸','宋','宋词','song-ci','浣溪沙','[]','双佩雷文拂手香。',48,'宋词/ci.song.6000.json','["双佩雷文拂手香。", "青纱衫子淡梳妆。", "冰姿绰约自生凉。", "虚掉玉钗惊翡翠，缓移兰棹趁鸳鸯。", "鬓鬟风乱绿云长。"]'),
('song-ci-947','浣溪沙','蔡伸','宋','宋词','song-ci','浣溪沙','[]','玉趾弯弯一折弓。',48,'宋词/ci.song.6000.json','["玉趾弯弯一折弓。", "秋波剪碧滟双瞳。", "浅颦轻笑意无穷。", "夜静拥炉熏督耨，月明飞棹采芙蓉。", "别来欢事少人同。"]'),
('song-ci-948','浣溪沙','蔡伸','宋','宋词','song-ci','浣溪沙','[]','苹末风轻入夜凉。',48,'宋词/ci.song.6000.json','["苹末风轻入夜凉。", "飞桥画阁跨方塘。", "月移花影上回廊。", "粲枕随钗云鬓乱，红绵扑粉玉肌香。", "起来携手看鸳鸯。"]'),
('song-ci-949','浣溪沙','蔡伸','宋','宋词','song-ci','浣溪沙','[]','窗外疏篁对节金。',48,'宋词/ci.song.6000.json','["窗外疏篁对节金。", "画桥新绿一篙深。", "沈沈清夜对横参。", "酒晕半消红玉脸，云鬟轻制小犀簪。", "梦回陈迹杳难寻。"]'),
('song-ci-950','浣溪沙','蔡伸','宋','宋词','song-ci','浣溪沙','[]','沙上寒鸥接翼飞。',48,'宋词/ci.song.6000.json','["沙上寒鸥接翼飞。", "潮生潮落水东西。", "征船鸣橹趁潮归。", "望断碧云无锦字，谩题红叶有新诗。", "黄昏微雨倚阑时。"]'),
('song-ci-951','浣溪沙','蔡伸','宋','宋词','song-ci','浣溪沙','[]','漠漠新田绿未齐。',48,'宋词/ci.song.6000.json','["漠漠新田绿未齐。", "柳阴阴下水平堤。", "竹间时有乳鸦啼。", "云敛屏山横枕畔，夜阑璧月转林西。", "玉芝香里彩鸳栖。"]'),
('song-ci-952','浣溪沙','蔡伸','宋','宋词','song-ci','浣溪沙','[]','紫燕双双掠水飞。',48,'宋词/ci.song.6000.json','["紫燕双双掠水飞。", "廉纤小雨未成泥。", "篱边开尽野蔷薇。", "会少离多终有恨，暂来还去益堪悲。", "后期重约采莲时。"]'),
('song-ci-953','浣溪沙','蔡伸','宋','宋词','song-ci','浣溪沙','[]','窄窄霜绡稳称身。',48,'宋词/ci.song.6000.json','["窄窄霜绡稳称身。", "强临歌酒惨离魂。", "故人相遇益伤神。", "断雨残云千里隔，琼枝璧月四时新。", "为君留取镜中春。"]'),
('song-ci-954','浣溪沙','蔡伸','宋','宋词','song-ci','浣溪沙','[]','且斗尊前见在身。',48,'宋词/ci.song.6000.json','["且斗尊前见在身。", "昔游如梦可销魂。", "玉容依约旧精神。", "千里重来人事改，一杯相属意还新。", "韶华不减洞中春。"]'),
('song-ci-955','浣溪沙','蔡伸','宋','宋词','song-ci','浣溪沙','[]','木似文犀感月华。',48,'宋词/ci.song.6000.json','["木似文犀感月华。", "寸根移种自仙家。", "春兰秋菊浪矜夸。", "玉露初零秋夜永，幽香直入小窗纱。", "此时风月独输他。"]'),
('song-ci-956','浣溪沙','蔡伸','宋','宋词','song-ci','浣溪沙','[]','叶剪玻璃芯糁金。',48,'宋词/ci.song.6000.json','["叶剪玻璃芯糁金。", "清香端不数琼沈。", "独将高韵冠芗林。", "千里江山新梦后，一天风露小庭深。", "主人归兴已骎骎。"]'),
('song-ci-957','浣溪沙','蔡伸','宋','宋词','song-ci','浣溪沙','[]','浅褐衫儿寿带藤。',48,'宋词/ci.song.6000.json','["浅褐衫儿寿带藤。", "碾花如意枕冠轻。", "凤鞋弓小称娉婷。", "约略梳妆随事好，出尘标韵出尘清。", "一枝梅映玉壶冰。"]'),
('song-ci-958','浣溪沙','蔡伸','宋','宋词','song-ci','浣溪沙','[]','窗外桃花烂熳开。',48,'宋词/ci.song.6000.json','["窗外桃花烂熳开。", "年时曾伴玉人来。", "一枝斜插凤皇钗。", "今日重来人事改，花前无语独徘徊。", "凄凉怀抱可怜哉。"]'),
('song-ci-959','虞美人','蔡伸','宋','宋词','song-ci','虞美人','[]','瑶琴一弄清商怨。',66,'宋词/ci.song.6000.json','["瑶琴一弄清商怨。", "楼外桐阴转。", "月华澄淡露华浓。", "寂寞小池烟水、冷芙蓉。", "攀花撷翠当时事。", "绿叶同心字。", "有情还解忆人无。", "过尽寒沙新雁、甚无书。"]'),
('song-ci-960','虞美人','蔡伸','宋','宋词','song-ci','虞美人','[]','飞梁石径关山路。',66,'宋词/ci.song.6000.json','["飞梁石径关山路。", "惨淡秋容暮。", "一行新雁破寒空。", "肠断碧云千里、水溶溶。", "鸾衾欲展谁堪共。", "帘幕霜华重。", "鸭炉香尽锦屏中。", "幽梦今宵何许、与君同。"]'),
('song-ci-961','虞美人','蔡伸','宋','宋词','song-ci','虞美人','[]','红尘匹马长安道。',66,'宋词/ci.song.6000.json','["红尘匹马长安道。", "人与花俱老。", "缓垂鞭袖过平康。", "散尽高阳、零落少年场。", "朱弦重理相思调。", "无奈知音少。", "十年如梦尽堪伤。", "乐事如今、回首做凄凉。"]'),
('song-ci-962','虞美人','蔡伸','宋','宋词','song-ci','虞美人','[]','彩旗摇曳樯乌转。',66,'宋词/ci.song.6000.json','["彩旗摇曳樯乌转。", "鹢首征帆展。", "高城楼观暮云平。", "叠鼓凝笳都在、断肠声。", "绿窗朱户空回首。", "明月还依旧。", "乱山无数水茫茫。", "谁念塞垣风物、㬠凄惶。"]'),
('song-ci-963','虞美人','蔡伸','宋','宋词','song-ci','虞美人','[]','堆琼滴露冰壶莹。',66,'宋词/ci.song.6000.json','["堆琼滴露冰壶莹。", "楼外天如镜。", "水晶双枕衬云鬟。", "卧看千山明月、听潺湲。", "渡江桃叶分飞后。", "马上犹回首。", "邮亭今夜月空圆。", "不似当时携手、对婵娟。"]'),
('song-ci-964','虞美人','蔡伸','宋','宋词','song-ci','虞美人','[]','碧溪曾寄流红字。',66,'宋词/ci.song.6000.json','["碧溪曾寄流红字。", "忍话当时事。", "重来种种尽堪悲。", "有酒盈杯、聊为故人持。", "夜闲剪烛西窗语。", "怀抱今如许。", "尊前莫讶两依依。", "绿鬓朱颜、不似少年时。"]'),
('song-ci-965','虞美人','蔡伸','宋','宋词','song-ci','虞美人','[]','鸾屏绣被香云拥。',66,'宋词/ci.song.6000.json','["鸾屏绣被香云拥。", "平帖幽闺梦。", "觉来重试古龙涎。", "深炷玉炉、烧气不烧烟。", "匆匆人去三更也。", "月到回廊下。", "出门无语送郎时。", "泪共一天风露、湿罗衣。"]'),
('song-ci-966','生查子','蔡伸','宋','宋词','song-ci','生查子','[]','画堂初见伊，明月当满窗。',48,'宋词/ci.song.6000.json','["画堂初见伊，明月当满窗。", "今夜月如眉，话别河桥畔。", "重见约中秋，莫负于飞愿。", "免使月圆时，两处空肠断。"]'),
('song-ci-967','生查子','蔡伸','宋','宋词','song-ci','生查子','[]','霜寒月满窗，夜永人无寐。',48,'宋词/ci.song.6000.json','["霜寒月满窗，夜永人无寐。", "绛腊有馀情，偏照鸳鸯被。", "看尽旧时书，洒尽今生泪。", "衙鼓已三更，还是和衣睡。"]'),
('song-ci-968','生查子','蔡伸','宋','宋词','song-ci','生查子','[]','金壶插玉芝，人面交相照。',48,'宋词/ci.song.6000.json','["金壶插玉芝，人面交相照。", "花影满方床，翠叠屏山杳。", "风月亦多情，特地今宵好。", "尽道夜初长，弹指东窗晓。"]'),
('song-ci-969','生查子','蔡伸','宋','宋词','song-ci','生查子','[]','几番花信风，数点笼丝雨。',48,'宋词/ci.song.6000.json','["几番花信风，数点笼丝雨。", "并辔踏香尘，选胜东郊路。", "韶华转首空，谁解留春住。", "幸到绿尊前，且作莺花主。"]'),
('song-ci-970','生查子','蔡伸','宋','宋词','song-ci','生查子','[]','银缸委坠红，碧锁朦胧晓。',48,'宋词/ci.song.6000.json','["银缸委坠红，碧锁朦胧晓。", "别泪洒金徽，一曲情多少。", "邮亭今夜长，明月香帏悄。", "纵使梦相逢，何处寻蓬岛。"]'),
('song-ci-971','南歌子','蔡伸','宋','宋词','song-ci','南歌子','[]','萧寺疏锺断，虚堂夜气清。',62,'宋词/ci.song.6000.json','["萧寺疏锺断，虚堂夜气清。", "凉蟾偏向小明窗。", "露井碧梧寒叶、颤秋声。", "幽恨人谁问，孤衾泪独横。", "此时风月此时情。", "拟倩蓝桥归梦、见云英。"]'),
('song-ci-972','南歌子','蔡伸','宋','宋词','song-ci','南歌子','[]','远水澄明绿，孤云暗淡愁。',62,'宋词/ci.song.6000.json','["远水澄明绿，孤云暗淡愁。", "白苹红蓼满汀洲。", "肠断圆蟾空照、木兰舟。", "节物伤羁旅，归程叹滞留。", "佳期已误小红楼。", "赖得今年犹有、闰中秋。"]'),
('song-ci-973','南歌子','蔡伸','宋','宋词','song-ci','南歌子','[]','恨入眉峰翠，寒生酒晕红。',62,'宋词/ci.song.6000.json','["恨入眉峰翠，寒生酒晕红。", "临期凝泪洒西风。", "须信世间无物、似情浓。", "玉蹬敲霜月，金钲伴晓锺。", "凄凉古驿乱山重。", "今夜拥衾无寐、与君同。"]'),
('song-ci-974','南乡子','蔡伸','宋','宋词','song-ci','南乡子','["\u592a\u6e56"]','天外雨初收。',66,'宋词/ci.song.6000.json','["天外雨初收。", "风紧云轻已变秋。", "邂逅故人同一笑，迟留。", "聚散人生宜自谋。", "去路指南州。", "万顷云涛一叶舟。", "莫话太湖波浪险，归休。", "人在溪边正倚楼。"]'),
('song-ci-975','南乡子','蔡伸','宋','宋词','song-ci','南乡子','[]','木落雁南翔。',66,'宋词/ci.song.6000.json','["木落雁南翔。", "锦鲤殷勤为渡江。", "泪墨银钩相忆字，成行。", "滴损云笺小凤皇。", "陈事费思量。", "回首烟波卷夕阳。", "尽道凭书聊破恨，难忘。", "及至书来更断肠。"]'),
('song-ci-976','菩萨蛮','蔡伸','宋','宋词','song-ci','菩萨蛮','[]','鸳鸯枕上云堆绿。',52,'宋词/ci.song.6000.json','["鸳鸯枕上云堆绿。", "兰膏微润知新沐。", "开帐对华灯。", "见郎双眼明。", "锦衾香馥郁。", "槛竹敲寒玉。", "何物最无情。", "晓鸡咿喔声。"]'),
('song-ci-977','菩萨蛮','蔡伸','宋','宋词','song-ci','菩萨蛮','[]','杏花零落清明雨。',52,'宋词/ci.song.6000.json','["杏花零落清明雨。", "卷帘双燕来还去。", "枕上玉芙蓉。", "暖香堆锦红。", "翠翘金钿雀。", "蝉鬓慵疏掠。", "心事一春闲。", "黛眉颦远山。"]'),
('song-ci-978','菩萨蛮','蔡伸','宋','宋词','song-ci','菩萨蛮','[]','飞英不向枝头住。',52,'宋词/ci.song.6000.json','["飞英不向枝头住。", "等闲又送春归去。", "云幄翠阴浮。", "长随日脚流。", "玉箫吹凤怨。", "惊起楼中燕。", "飞去自双双。", "恼人空断肠。"]'),
('song-ci-979','菩萨蛮','蔡伸','宋','宋词','song-ci','菩萨蛮','["\u957f\u6c5f"]','水光山影浮空碧。',52,'宋词/ci.song.6000.json','["水光山影浮空碧。", "柳丝摇曳春无力。", "柳岸系行舟。", "吹箫忆旧游。", "旧游堪更忆。", "望断迷南北。", "千古恨悠悠。", "长江空自流。"]'),
('song-ci-980','菩萨蛮','蔡伸','宋','宋词','song-ci','菩萨蛮','[]','当时携手今千里。',52,'宋词/ci.song.6000.json','["当时携手今千里。", "可堪重到相逢地。", "触目尽关心。", "流莺尚好音。", "无人知我意。", "只有涓涓泪。", "寂寞到斜阳。", "罗衣裛旧香。"]'),
('song-ci-981','菩萨蛮','蔡伸','宋','宋词','song-ci','菩萨蛮','[]','鸣茄叠鼓催双桨。',52,'宋词/ci.song.6000.json','["鸣茄叠鼓催双桨。", "扁舟稳泛桃花浪。", "别泪洒东风。", "前欢如梦中。", "梦魂无定据。", "不到相逢处。", "纵使梦相逢。", "香闺岂解同。"]'),
('song-ci-982','菩萨蛮','蔡伸','宋','宋词','song-ci','菩萨蛮','[]','金铺半掩银瞻满。',52,'宋词/ci.song.6000.json','["金铺半掩银瞻满。", "个人应恨归来晚。", "轧轧橹声迟。", "那知心已飞。", "迎门一笑粲。", "娇困横波慢。", "偎倚绿窗前。", "今宵人月圆。"]'),
('song-ci-983','菩萨蛮','蔡伸','宋','宋词','song-ci','菩萨蛮','[]','双双紫燕来华屋。',52,'宋词/ci.song.6000.json','["双双紫燕来华屋。", "雨馀芳草池塘绿。", "一夜摆花风。", "莺花满树红。", "杯深君莫诉。", "醉袖歌金缕。", "无奈惜花心。", "老来情转深。"]'),
('song-ci-984','菩萨蛮','蔡伸','宋','宋词','song-ci','菩萨蛮','[]','朝来一陈狂风雨。',52,'宋词/ci.song.6000.json','["朝来一陈狂风雨。", "春光已作堂堂去。", "茂绿满繁枝。", "青梅结子时。", "攀枝惊晼晚。", "乐事孤心眼。", "正是惜春归。", "那堪怨别离。"]'),
('song-ci-985','菩萨蛮','蔡伸','宋','宋词','song-ci','菩萨蛮','[]','凝羞隔水抛红豆。',52,'宋词/ci.song.6000.json','["凝羞隔水抛红豆。", "嫩桃如脸腰如柳。", "心事暗明期。", "阳台云雨迷。", "玉楼花似雪。", "花上朦胧月。", "挥泪执柔荑。", "匆匆话别时。"]'),
('song-ci-986','菩萨蛮','蔡伸','宋','宋词','song-ci','菩萨蛮','[]','花冠鼓翼东方动。',52,'宋词/ci.song.6000.json','["花冠鼓翼东方动。", "兰闺惊破辽阳梦。", "翠被小屏山。", "晓窗灯影残。", "并头双燕语。", "似诉横塘雨。", "风雨晓寒多。", "征人可奈何。"]'),
('song-ci-987','忆秦娥','蔡伸','宋','宋词','song-ci','忆秦娥','[]','湖光碧。',56,'宋词/ci.song.6000.json','["湖光碧。", "春花秋月无今昔。", "无今昔。", "十年往事，尽成陈迹。", "玉箫声断云屏隔。", "山遥水远长相忆。", "长相忆。", "一生怀抱，为君牵役。"]'),
('song-ci-988','忆秦娥','蔡伸','宋','宋词','song-ci','忆秦娥','[]','花阴月。',56,'宋词/ci.song.6000.json','["花阴月。", "兰堂夜宴神仙客。", "神仙客。", "江梅标韵，海棠颜色。", "良辰佳会诚难得。", "花前一醉君休惜。", "君休惜。", "楚台云雨，今夕何夕。"]'),
('song-ci-989','清平乐','蔡伸','宋','宋词','song-ci','清平乐','[]','彩舟双橹。',54,'宋词/ci.song.6000.json','["彩舟双橹。", "六月临平路。", "小雨轻风消晚暑。", "绕岸荷花无数。", "玉人璨枕方床。", "遥知待月西厢。", "昨夜有情风月，今宵特地凄凉。"]'),
('song-ci-990','清平乐','蔡伸','宋','宋词','song-ci','清平乐','[]','南窗月满。',54,'宋词/ci.song.6000.json','["南窗月满。", "绣被堆香暖。", "苦恨春宵更漏短。", "应讶郎归又晚。", "征帆初落桥边。", "迎门一笑嫣然。", "今夜流霞共酌，何妨金盏垂莲。"]'),
('song-ci-991','清平乐','蔡伸','宋','宋词','song-ci','清平乐','[]','明眸秀色。',54,'宋词/ci.song.6000.json','["明眸秀色。", "肌理凝香雪。", "罗绮丛中标韵别。", "捧酒歌声清越。", "不辞醉脸潮红。", "却愁归骑匆匆。", "回首绿窗朱户，断肠明月清风。"]'),
('song-ci-992','谒金门','蔡伸','宋','宋词','song-ci','谒金门','[]','溪声咽。',53,'宋词/ci.song.6000.json','["溪声咽。", "溪上有人离别。", "别语叮咛和泪说。", "罗巾沾泪血。", "尽做刚肠如铁。", "到此也应愁绝。", "回首断山帆影灭。", "画船空载月。"]'),
('song-ci-993','谒金门','蔡伸','宋','宋词','song-ci','谒金门','[]','相思切。',53,'宋词/ci.song.6000.json','["相思切。", "触目只供愁绝。", "好梦惊回清漏咽。", "烛残香穗结。", "长恨南楼明月。", "只解照人离缺。", "同倚朱栏飞大白。", "今宵风月别。"]'),
('song-ci-994','忆王孙','蔡伸','宋','宋词','song-ci','忆王孙','[]','凉生冰簟怯衣单。',36,'宋词/ci.song.6000.json','["凉生冰簟怯衣单。", "明月楼高空画栏。", "满院啼螀人未眠。", "掩重关。", "乌鹊南飞风露寒。"]'),
('song-ci-995','阮郎归','蔡伸','宋','宋词','song-ci','阮郎归','[]','烟笼寒水暝禽栖。',56,'宋词/ci.song.6000.json','["烟笼寒水暝禽栖。", "满庭红叶飞。", "兰堂寂寂画帘垂。", "霜浓更漏迟。", "鸳被冷，麝香微。", "强敧单枕时。", "西窗看尽月痕移。", "此情君怎知。"]'),
('song-ci-996','柳梢青','蔡伸','宋','宋词','song-ci','柳梢青','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','数声鶗鴂。',61,'宋词/ci.song.6000.json','["数声鶗鴂。", "可怜又是，春归时节。", "满院东风，海棠铺绣，梨花飘雪。", "丁香露泣残枝，算未比、愁肠寸结。", "自是休文，多情多感，不干风月。"]'),
('song-ci-997','柳梢青','蔡伸','宋','宋词','song-ci','柳梢青','[]','子规啼月。',61,'宋词/ci.song.6000.json','["子规啼月。", "幽衾梦断，销魂时节。", "枕上斑斑，枝头点点，染成清血。", "凄凉断雨残云，算此恨、文君更切。", "老去情怀，春来况味，那禁离别。"]'),
('song-ci-998','柳梢青','蔡伸','宋','宋词','song-ci','柳梢青','[]','联璧寻春，踏青尚意，年时携手。',59,'宋词/ci.song.6000.json','["联璧寻春，踏青尚意，年时携手。", "此际重来，可怜还是，年时时候。", "阴阴柳下人家，人面桃花似旧。", "但原年年，春风有信，人心长久。"]'),
('song-ci-999','好事近','蔡伸','宋','宋词','song-ci','好事近','[]','花露滴香红，花低漏声初歇。',53,'宋词/ci.song.6000.json','["花露滴香红，花低漏声初歇。", "人似一枝梅瘦，照冰壶清彻。", "翠娥云鬓为谁容，虫丝宝奁结。", "可惜一春憔悴，负满怀风月。"]'),
('song-ci-0','好事近','蔡伸','宋','宋词','song-ci','好事近','[]','十幅健帆风，天意巧催行客。',53,'宋词/ci.song.7000.json','["十幅健帆风，天意巧催行客。", "极目五湖云浪，泛满空秋色。", "玉人应怪误佳期，凝恨正脉脉。", "锦鳞为传尺素，报兰舟消息。"]'),
('song-ci-1','卜算子','蔡伸','宋','宋词','song-ci','卜算子','[]','风雨送春归，寂寞花空委。',52,'宋词/ci.song.7000.json','["风雨送春归，寂寞花空委。", "枝上红稀地上多，万点随流水。", "翠黛敛春愁，照影临清泚。", "应念韶华惜蕣颜，洒遍胭脂泪。"]'),
('song-ci-2','卜算子','蔡伸','宋','宋词','song-ci','卜算子','[]','小阁枕清流，一霎莲塘雨。',52,'宋词/ci.song.7000.json','["小阁枕清流，一霎莲塘雨。", "风递幽香入槛来，枕簟全无暑。", "遐想似花人，阅岁音尘阻。", "物是人非空断肠，梦入芳洲路。"]'),
('song-ci-3','卜算子','蔡伸','宋','宋词','song-ci','卜算子','[]','玉斧斫冰轮，中有乘鸾女。',52,'宋词/ci.song.7000.json','["玉斧斫冰轮，中有乘鸾女。", "鬓乱钗横襟袖凉，只恐轻飞举。", "青冥缥缈间，自有吹箫侣。", "不向巫山十二峰，朝暮为云雨。"]'),
('song-ci-4','卜算子','蔡伸','宋','宋词','song-ci','卜算子','[]','前度月圆时，月下相携手。',52,'宋词/ci.song.7000.json','["前度月圆时，月下相携手。", "今夜天边月又圆，夜色如清昼。", "风月浑依旧。", "水馆空回首。", "明夜归来试问伊，曾解思量否。"]'),
('song-ci-5','卜算子','蔡伸','宋','宋词','song-ci','卜算子','[]','重重雪外山，渺渺烟中路。',52,'宋词/ci.song.7000.json','["重重雪外山，渺渺烟中路。", "路转山横无尽愁，正是分携处。", "望极锦中书，肠断鱼中素。", "锦素沈沈两未期，鱼雁空相误。"]'),
('song-ci-6','卜算子','蔡伸','宋','宋词','song-ci','卜算子','[]','春事付莺花，曾是莺花主。',52,'宋词/ci.song.7000.json','["春事付莺花，曾是莺花主。", "醉拍春衫金缕衣，只向花间住。", "密意君听取。", "莫逐风来去。", "若是真心待于飞，云里千条路。"]'),
('song-ci-7','小重山','蔡伸','宋','宋词','song-ci','小重山','[]','楼外江山展翠屏。',70,'宋词/ci.song.7000.json','["楼外江山展翠屏。", "沈沈虹影畔，彩舟横。", "一尊别酒为君倾。", "留不住，风色太无情。", "斜日半山明。", "画栏重倚处，独销凝。", "片帆回首在青冥。", "人不见，千里暮云平。"]'),
('song-ci-8','小重山','蔡伸','宋','宋词','song-ci','小重山','[]','澹澹秋容烟水寒。',70,'宋词/ci.song.7000.json','["澹澹秋容烟水寒。", "楼高清夜永，倚阑干。", "玉人不见坐长叹。", "箫声远，明月满空山。", "遐想绿云鬟。", "青冥风露冷，独乘鸾。", "别时容易见时难。", "凭孤枕，聊复梦蝉娟。"]'),
('song-ci-9','小重山','蔡伸','宋','宋词','song-ci','小重山','[]','流水桃花小洞天。',70,'宋词/ci.song.7000.json','["流水桃花小洞天。", "壶中春不老，胜尘寰。", "霞衣鹤氅并桃冠。", "新装好，风韵愈飘然。", "功行满三千。", "婴儿并姹女，炼成丹。", "刘郎曾约共升仙。", "十个月，养个小金坛。"]'),
('song-ci-10','小重山','蔡伸','宋','宋词','song-ci','小重山','[]','楼上风高翠袖寒。',70,'宋词/ci.song.7000.json','["楼上风高翠袖寒。", "碧云笼淡日，照阑干。", "绿杨芳草恨绵绵。", "长亭路，何处认征鞍。", "晓镜懒重看。", "鬓云堆凤髻，任阑珊。", "鸾衾鸳枕小屏山。", "人如玉，忍负一春闲。"]'),
('song-ci-11','踏莎行','蔡伸','宋','宋词','song-ci','踏莎行','[]','佩解江皋，魂消南浦。',68,'宋词/ci.song.7000.json','["佩解江皋，魂消南浦。", "人生惟有别离苦。", "别时容易见时难，算来却是无情语。", "百计留君，留君不住。", "留君不住君须去。", "望君频问梦中来，免教肠断巫山雨。"]'),
('song-ci-12','踏莎行','蔡伸','宋','宋词','song-ci','踏莎行','[]','如是我闻，金仙出世。',68,'宋词/ci.song.7000.json','["如是我闻，金仙出世。", "一超直入如来地。", "慈悲方便济群生，端严妙相谁能比。", "四众归依，悉皆欢喜。", "有情同赴龙华会。", "无忧帐里结良缘，麽诃修哩修修哩。"]'),
('song-ci-13','踏莎行','蔡伸','宋','宋词','song-ci','踏莎行','[]','客里光阴，伤离情味。',68,'宋词/ci.song.7000.json','["客里光阴，伤离情味。", "玉觞未举心先醉。", "临岐莫怪苦留连，樯乌转处人千里。", "恨写新声，云笺密寄。", "短封难尽心中事。", "凭君看取纸痕斑，分明总是离人泪。"]'),
('song-ci-14','踏莎行','蔡伸','宋','宋词','song-ci','踏莎行','[]','落日归云，寒空断雁。',68,'宋词/ci.song.7000.json','["落日归云，寒空断雁。", "吴波浅淡山平远。", "丹青写出在霜缣，佳人特地栽团扇。", "渔艇孤烟，酒旗幽院。", "些儿景趣君休羡。", "五湖归去共扁舟，何如早早酬深愿。"]'),
('song-ci-15','踏莎行','蔡伸','宋','宋词','song-ci','踏莎行','[]','水满青钱，烟滋翠葆。',68,'宋词/ci.song.7000.json','["水满青钱，烟滋翠葆。", "残英满地无人扫。", "先来羁思乱如云，无端更被春酲恼。", "叠叠遥山，绵绵远道。", "凭阑满目唯芳草。", "莫惊青鬓点秋霜，卢郎已分愁中老。"]'),
('song-ci-16','踏莎行','蔡伸','宋','宋词','song-ci','踏莎行','[]','玉质孤高，天姿明慧。',68,'宋词/ci.song.7000.json','["玉质孤高，天姿明慧。", "了无一点尘凡气。", "白莲空殿锁幽芳，亭亭独占秋光里。", "一切见闻，不可思议。", "我今有分亲瞻礼。", "愿垂方便济众生，他时同赴龙华会。"]'),
('song-ci-17','定风波','蔡伸','宋','宋词','song-ci','定风波','[]','一曲骊歌酒一锺。',73,'宋词/ci.song.7000.json','["一曲骊歌酒一锺。", "可怜分袂太匆匆。", "百计留君留不住。", "□去。", "满川烟暝满帆风。", "目断魂销人不见。", "但见。", "青山隐隐水浮空。", "拟把一襟相忆泪。", "试□。", "云笺密洒付飞鸿。"]'),
('song-ci-18','定风波','蔡伸','宋','宋词','song-ci','定风波','[]','老去情锺不自持。',70,'宋词/ci.song.7000.json','["老去情锺不自持。", "篸花酌酒送春归。", "玉貌冰姿人窈窕。", "一笑。", "清狂岂减少年时。", "欲上香车俱脉脉，半帘花影月平西。", "待得酒醒人已去。", "凝伫。", "断云残雨尽堪悲。"]'),
('song-ci-19','点绛唇','蔡伸','宋','宋词','song-ci','点绛唇','[]','水绕孤城，乱山深锁横江路。',50,'宋词/ci.song.7000.json','["水绕孤城，乱山深锁横江路。", "帆归别浦。", "苒苒兰皋暮。", "人在天涯，雁背南云去。", "空凝伫。", "凤楼何处。", "烟霭迷津渡。"]'),
('song-ci-20','点绛唇','蔡伸','宋','宋词','song-ci','点绛唇','[]','香雪飘零，暖风著柳笼丝雨。',50,'宋词/ci.song.7000.json','["香雪飘零，暖风著柳笼丝雨。", "恼人情绪。", "春事还如许。", "宝勒朱轮，共结寻芳侣。", "东郊路。", "乱红深处。", "醉拍黄金缕。"]'),
('song-ci-21','点绛唇','蔡伸','宋','宋词','song-ci','点绛唇','[]','背壁灯残，卧听檐雨难成寐。',50,'宋词/ci.song.7000.json','["背壁灯残，卧听檐雨难成寐。", "井梧飘坠。", "历历蛩声细。", "数尽更筹。", "滴尽罗巾泪。", "如何睡。", "甫能得睡。", "梦到相思地。"]'),
('song-ci-22','点绛唇','蔡伸','宋','宋词','song-ci','点绛唇','[]','月缺花残，世间乐事难双美。',50,'宋词/ci.song.7000.json','["月缺花残，世间乐事难双美。", "夜来相对。", "把酒弹轻泪。", "一点情锺，销尽英雄气。", "樊笼外。", "五湖烟水。", "好作扁舟计。"]'),
('song-ci-23','点绛唇','蔡伸','宋','宋词','song-ci','点绛唇','[]','玉笋持杯，敛红颦翠歌金缕。',50,'宋词/ci.song.7000.json','["玉笋持杯，敛红颦翠歌金缕。", "彩鸳戢羽。", "未免群鸡妒。", "我为情多，愁听多情语。", "君休诉。", "两心坚固。", "云里千条路。"]'),
('song-ci-24','点绛唇','蔡伸','宋','宋词','song-ci','点绛唇','[]','人面桃花，去年今日津亭见。',50,'宋词/ci.song.7000.json','["人面桃花，去年今日津亭见。", "瑶琴锦荐。", "一弄清商怨。", "金日重来，不见如花面。", "空肠断。", "乱红千片。", "流水天涯远。"]'),
('song-ci-25','点绛唇','蔡伸','宋','宋词','song-ci','点绛唇','[]','梅雨初晴，画栏开遍忘忧草。',50,'宋词/ci.song.7000.json','["梅雨初晴，画栏开遍忘忧草。", "兰堂清窈。", "高柳新蝉噪。", "枕上芙蓉，如梦还惊觉。", "匀妆了。", "背人微笑。", "风入玲珑罩。"]'),
('song-ci-26','点绛唇','蔡伸','宋','宋词','song-ci','点绛唇','[]','帐外华灯，翠屏花影参差满。',50,'宋词/ci.song.7000.json','["帐外华灯，翠屏花影参差满。", "锦衣香暖。", "苦恨春宵短。", "画角声中，云雨还轻散。", "河桥畔。", "月华如练。", "回首成肠断。"]'),
('song-ci-27','点绛唇','蔡伸','宋','宋词','song-ci','点绛唇','[]','绿萼冰花，数枝清影横疏牖。',50,'宋词/ci.song.7000.json','["绿萼冰花，数枝清影横疏牖。", "玉肌清瘦。", "夜久轻寒透。", "忍使孤芳，攀折他人手。", "人归后。", "断肠回首。", "只有香盈袖。"]'),
('song-ci-28','点绛唇','蔡伸','宋','宋词','song-ci','点绛唇','[]','解绂朝天，满城桃李繁阴市。',50,'宋词/ci.song.7000.json','["解绂朝天，满城桃李繁阴市。", "彩舟难驻。", "忍听骊歌举。", "协赞中兴，圣意方倾注。", "从今去。", "五云深处。", "稳步沙堤路。"]'),
('song-ci-29','点绛唇','蔡伸','宋','宋词','song-ci','点绛唇','[]','云雨匆匆，洞房当日曾相遇。',50,'宋词/ci.song.7000.json','["云雨匆匆，洞房当日曾相遇。", "暂来还去。", "无计留春住。", "宝瑟重调，静听莺弦语。", "休轻负。", "绮窗朱户。", "好做风光主。"]'),
('song-ci-30','昭君怨','蔡伸','宋','宋词','song-ci','昭君怨','[]','一曲云和松响。',47,'宋词/ci.song.7000.json','["一曲云和松响。", "多少离愁心上。", "寂寞掩屏帷。", "泪沾衣。", "最是销魂处。", "夜夜绮窗风雨。", "风雨伴愁眠。", "夜如年。"]'),
('song-ci-31','醉落魄・一斛珠','蔡伸','宋','宋词','song-ci','醉落魄・一斛珠','[]','波纹如縠。',67,'宋词/ci.song.7000.json','["波纹如縠。", "池塘雨后添新绿。", "海棠初绽红生肉。", "双燕归来，还认旧巢宿。", "凝情凭暖阑干曲。", "新愁无限伤心目。", "谁人月下吹横玉。", "惊起鸳鸯，飞去自相逐。"]'),
('song-ci-32','醉落魄・一斛珠','蔡伸','宋','宋词','song-ci','醉落魄・一斛珠','[]','霜华摇落。',67,'宋词/ci.song.7000.json','["霜华摇落。", "亭亭皓月侵朱箔。", "梦回敧枕听残角。", "一片寒声，风送入寥廓。", "眼前风月都如昨。", "独眠无奈情怀恶。", "凭肩携手于飞约。", "料想人人，终是赋情薄。"]'),
('song-ci-33','醉落魄・一斛珠','蔡伸','宋','宋词','song-ci','醉落魄・一斛珠','[]','明眸秀色。',67,'宋词/ci.song.7000.json','["明眸秀色。", "双蛾巧画春山碧。", "盈盈标韵倾瑶席。", "一见尊前，宛是旧相识。", "深期密语虽端的。", "良宵无奈成轻掷。", "忍教只恁空相忆。", "得入手来，无限好则剧。"]'),
('song-ci-34','醉落魄・一斛珠','蔡伸','宋','宋词','song-ci','醉落魄・一斛珠','[]','阳关声咽。',67,'宋词/ci.song.7000.json','["阳关声咽。", "清歌响断云屏隔。", "溪山依旧连空碧。", "昨日主人，今日是行客。", "绿窗朱户应如昔。", "回头往事成陈迹。", "后期总便无端的。", "月下风前，应也解相忆。"]'),
('song-ci-35','极相思','蔡伸','宋','宋词','song-ci','极相思','[]','碧檐鸣玉玎珰。',60,'宋词/ci.song.7000.json','["碧檐鸣玉玎珰。", "金锁小兰房。", "楼高夜永，飞霜满院，璧月沈缸。", "云雨不成巫峡梦，望仙乡、烟水茫茫。", "风前月底，登高念远，无限凄凉。"]'),
('song-ci-36','极相思','蔡伸','宋','宋词','song-ci','极相思','[]','相思情味堪伤。',60,'宋词/ci.song.7000.json','["相思情味堪伤。", "谁与话衷肠。", "明朝见也，桃花人面，碧藓回廊。", "别后相逢唯有梦，梦回时、展转思量。", "不如早睡，今宵魂梦，先到伊行。"]'),
('song-ci-37','玉楼春','蔡伸','宋','宋词','song-ci','玉楼春','[]','碧桃溪上蓝桥路。',64,'宋词/ci.song.7000.json','["碧桃溪上蓝桥路。", "寂寞朱门闲院宇。", "粉墙疏竹弄清蟾，玉砌红蕉宜夜雨。", "个中人是吹箫侣。", "花底深盟曾共语。", "人生乐在两知心，此意此生君记取。"]'),
('song-ci-38','玉楼春','蔡伸','宋','宋词','song-ci','玉楼春','[]','星河风露经年别。',64,'宋词/ci.song.7000.json','["星河风露经年别。", "月照离亭花似雪。", "宝钗鸾镜会重逢，花里同眠今夜月。", "月华依旧当时节。", "细把离肠和泪说。", "人生只合镇长圆，休似月圆圆又缺。"]'),
('song-ci-39','长相思','蔡伸','宋','宋词','song-ci','长相思','[]','我心坚。',44,'宋词/ci.song.7000.json','["我心坚。", "你心坚。", "各自心坚石也穿。", "谁言相见难。", "小窗前。", "月婵娟。", "玉困花柔并枕眠。", "今宵人月圆。"]'),
('song-ci-40','长相思','蔡伸','宋','宋词','song-ci','长相思','[]','锦衾香。',44,'宋词/ci.song.7000.json','["锦衾香。", "玉枕双。", "昨夜深深小洞房。", "回头已断肠。", "背兰缸。", "梦仙乡。", "风撼梧桐雨洒窗。", "今宵好夜长。"]'),
('song-ci-41','长相思','蔡伸','宋','宋词','song-ci','长相思','[]','村姑儿。',44,'宋词/ci.song.7000.json','["村姑儿。", "红袖衣。", "初发黄梅插稻时。", "双双女伴随。", "长歌诗。", "短歌诗。", "歌里真情恨别离。", "休言伊不知。"]'),
('song-ci-42','西地锦','蔡伸','宋','宋词','song-ci','西地锦','[]','寂寞悲秋怀抱。',56,'宋词/ci.song.7000.json','["寂寞悲秋怀抱。", "掩重门悄悄。", "清风皓月，朱阑画阁，双鸳池沼。", "不忍今宵重到。", "惹离愁多少。", "蓬山路杳，蓝桥信阻，黄花空老。"]'),
('song-ci-43','归田乐','蔡伸','宋','宋词','song-ci','归田乐','[]','风生苹末莲香细。',58,'宋词/ci.song.7000.json','["风生苹末莲香细。", "新浴晚凉天气。", "犹自倚朱阑，波面双双彩鸳戏。", "鸾钗委坠云堆髻。", "谁会此时情意。", "冰簟玉琴横，还是月明人千里。"]'),
('song-ci-44','七娘子','蔡伸','宋','宋词','song-ci','七娘子','[]','天涯触目伤离绪。',68,'宋词/ci.song.7000.json','["天涯触目伤离绪。", "登临况值秋光暮。", "手拈黄花，凭谁分付。", "雍雍雁落蒹葭浦。", "凭高目断桃溪路。", "屏山楼外青无数。", "绿水红桥，锁窗朱户。", "如今总是销魂处。"]'),
('song-ci-45','感皇恩','蔡伸','宋','宋词','song-ci','感皇恩','[]','酒晕衬横波，玉肌香透。',81,'宋词/ci.song.7000.json','["酒晕衬横波，玉肌香透。", "轻袅腰肢妒垂柳。", "臂宽金钏，且是不干春瘦。", "拈金双合字，无心绣。", "鬒云半堕，金钗欲溜。", "罗袂残香忍重嗅。", "渡江桃叶，肠断为谁招手。", "倚阑凝望久，眉空斗。"]'),
('song-ci-46','感皇恩','蔡伸','宋','宋词','song-ci','感皇恩','[]','膏雨晓来晴，海棠红透。',81,'宋词/ci.song.7000.json','["膏雨晓来晴，海棠红透。", "碧草池塘袅金柳。", "王孙何在，不念玉容消瘦。", "日长深院静，帘垂绣。", "璨枕堕钗，粉痕轻溜。", "玉鼎龙涎记同嗅。", "钿筝重理，心事谩凭纤手。", "素弦弹不尽，眉峰斗。"]'),
('song-ci-47','减字木兰花','蔡伸','宋','宋词','song-ci','减字木兰花','[]','彤庭龙尾。',52,'宋词/ci.song.7000.json','["彤庭龙尾。", "礼备天颜知有喜。", "九奏初传。", "耳冷人间十七年。", "盈成持守。", "仁德如春渐九有。", "三辅名州。", "好整笙歌结胜游。"]'),
('song-ci-48','减字木兰花','蔡伸','宋','宋词','song-ci','减字木兰花','[]','船回沙尾。',52,'宋词/ci.song.7000.json','["船回沙尾。", "几误红窗听鹊喜。", "尺素空传。", "转首相逢又隔年。", "寒灯独守。", "玉笋持杯宁复有。", "秀水南州。", "徒使幽人作梦游。"]'),
('song-ci-49','减字木兰花','蔡伸','宋','宋词','song-ci','减字木兰花','[]','多情多病。',52,'宋词/ci.song.7000.json','["多情多病。", "玉貌疲来愁览镜。", "门掩东风。", "零落桃花满地红。", "重帘不卷。", "愁睹杏梁双语燕。", "强拂瑶琴。", "一曲幽兰泪满襟。"]'),
('song-ci-50','减字木兰花','蔡伸','宋','宋词','song-ci','减字木兰花','[]','金风玉露。',52,'宋词/ci.song.7000.json','["金风玉露。", "喜鹊桥成牛女渡。", "天宇沈沈。", "一夕佳期两意深。", "琼签报曙。", "忍使飙轮容易去。", "明日如今。", "想见君心似我心。"]'),
('song-ci-51','减字木兰花','蔡伸','宋','宋词','song-ci','减字木兰花','[]','锦屏人醉。',52,'宋词/ci.song.7000.json','["锦屏人醉。", "玉暖香融春有味。", "今日兰舟。", "魂梦还随绿水流。", "高城望断。", "无奈城中人不见。", "斜倚妆楼。", "恨入眉峰两点愁。"]'),
('song-ci-52','渔家傲','蔡伸','宋','宋词','song-ci','渔家傲','[]','烟锁池塘秋欲暮。',78,'宋词/ci.song.7000.json','["烟锁池塘秋欲暮。", "细细前香，直到双栖处。", "并枕东窗听夜雨。", "偎金缕。", "云深不见来时路。", "晓色朦胧人去住。", "香覆重帘，密密闻私语。", "日断征帆归别浦。", "空凝伫。", "苔痕绿印金莲步。"]'),
('song-ci-53','西楼子・相见欢','蔡伸','宋','宋词','song-ci','西楼子・相见欢','[]','楼前流水悠悠。',45,'宋词/ci.song.7000.json','["楼前流水悠悠。", "驻行舟。", "满目寒云衰草、使人愁。", "多少恨，多少泪，谩迟留。", "何似蓦然拚舍、去来休。"]'),
('song-ci-54','西楼子・相见欢','蔡伸','宋','宋词','song-ci','西楼子・相见欢','[]','红靴玉带葳蕤。',45,'宋词/ci.song.7000.json','["红靴玉带葳蕤。", "翠绡衣。", "并辔垂鞭妆影、照清溪。", "长亭路。", "停骑处。", "晚凉时。", "空有许多明月、伴双栖。"]'),
('song-ci-55','御街行','蔡伸','宋','宋词','song-ci','御街行','[]','东君不锁寻芳路。',92,'宋词/ci.song.7000.json','["东君不锁寻芳路。", "曾是莺花主。", "有情风月可怜宵，犹记绿窗朱户。", "十年空想，春风面杳，无计凭鳞羽。", "凄凉怀抱今如许。", "天与重相遇。", "不应还向楚峰前，朝暮为云为雨。", "算来各把，平生分付，也不是、恶著处。"]'),
('song-ci-56','上阳春・蓦山溪','蔡伸','宋','宋词','song-ci','上阳春・蓦山溪','[]','好在章台杨柳。',56,'宋词/ci.song.7000.json','["好在章台杨柳。", "不禁春瘦。", "淡烟微雨曲尘丝，锁一点、眉头皱。", "忆自灞陵别后。", "青青依旧。", "万丝千缕太多情，忍攀折、行人手。"]'),
('song-ci-57','临江仙','蔡伸','宋','宋词','song-ci','临江仙','[]','繁杏枝头蜂蝶乱，香风阖坐微闻。',68,'宋词/ci.song.7000.json','["繁杏枝头蜂蝶乱，香风阖坐微闻。", "靓妆浓艳任东君。", "无情风雨，春事已平分。", "珍重主人留客意，夜阑秉烛开尊。", "何须歌韵遏行云。", "羽觞交劝，挥麈细论文。"]'),
('song-ci-58','临江仙','蔡伸','宋','宋词','song-ci','临江仙','[]','昨夜中秋今夕望，十分桂影团圆。',68,'宋词/ci.song.7000.json','["昨夜中秋今夕望，十分桂影团圆。", "玉人相对绿尊前。", "素娥有恨，应是妒蝉娟。", "人静小庭风露冷，歌声特地清圆。", "醉红醺脸髻鬟偏。", "翠裙轻皱，端的为留仙。"]'),
('song-ci-59','临江仙','蔡伸','宋','宋词','song-ci','临江仙','[]','帘幕深深清昼永，玉人不耐春寒。',68,'宋词/ci.song.7000.json','["帘幕深深清昼永，玉人不耐春寒。", "镂牙棋子缕金圆。", "象盘雅戏，相对小窗前。", "隔打直行尖曲路，教人费尽机关。", "局中胜负定谁偏。", "饶伊使幸，毕竟我赢先。"]'),
('song-ci-60','临江仙','蔡伸','宋','宋词','song-ci','临江仙','[]','仙品不同桃李艳，移来月窟云乡。',68,'宋词/ci.song.7000.json','["仙品不同桃李艳，移来月窟云乡。", "幽姿绰约道家妆。", "绿云堆髻，娇额半涂黄。", "可但乍凉风月下，饶伊独占秋光。", "雨中别有恼人香。", "错教萧史，肠断忆巫阳。"]'),
('song-ci-61','临江仙','蔡伸','宋','宋词','song-ci','临江仙','[]','琪树鸾栖花露重，依稀兰洞风光。',68,'宋词/ci.song.7000.json','["琪树鸾栖花露重，依稀兰洞风光。", "玉人相对自生凉。", "翠鬟琼佩，绰约蕊珠妆。", "宝瑟声沈清梦觉，夜阑明月幽窗。", "可堪襟袂惹馀香。", "断云残雨，何处认高唐。"]'),
('song-ci-62','临江仙','蔡伸','宋','宋词','song-ci','临江仙','[]','记得南楼三五夜，曾听凤管昭华。',70,'宋词/ci.song.7000.json','["记得南楼三五夜，曾听凤管昭华。", "曾前此际重兴嗟。", "素娥端有恨，烟霭等闲遮。", "珍重主人留客意，厌厌缓引流霞。", "夜间银汉淡天涯。", "亭亭丹桂现，耿耿玉绳斜。"]'),
('song-ci-63','临江仙','蔡伸','宋','宋词','song-ci','临江仙','[]','青润奇峰名韫玉，温其质并琼瑶。',70,'宋词/ci.song.7000.json','["青润奇峰名韫玉，温其质并琼瑶。", "中分瀑布泻云涛。", "双峦呈翠色，气象两相高。", "珍重幽人诚好事，绿窗聊助风骚。", "寄言俗客莫相嘲。", "物轻人意重，千里赠鹅毛。"]'),
('song-ci-64','鹧鸪天','蔡伸','宋','宋词','song-ci','鹧鸪天','[]','脉脉柔情不自持。',64,'宋词/ci.song.7000.json','["脉脉柔情不自持。", "浅颦轻笑百般宜。", "尊前唱歇黄金缕，一点春愁入翠眉。", "流蕙盼，捧瑶卮。", "借君歌扇写新诗。", "浮花谩说惊郎目，不似东风第一枝。"]'),
('song-ci-65','惜奴娇','蔡伸','宋','宋词','song-ci','惜奴娇','[]','隔阔多时，算彼此、难存济。',93,'宋词/ci.song.7000.json','["隔阔多时，算彼此、难存济。", "咫尺地、千山万水。", "眼眼相看，要说话、都无计。", "只是。", "唱曲儿、词中认意。", "雪意垂垂，更刮地、寒风起。", "怎禁这几夜意。", "未散痴心，便指望、长偎倚。", "只替。", "那火桶儿、与奴暖被。"]'),
('song-ci-66','行香子','蔡伸','宋','宋词','song-ci','行香子','[]','珠露初零。',84,'宋词/ci.song.7000.json','["珠露初零。", "天宇澄明。", "正闲阶、皎月亭亭。", "更阑人静，烟敛风清。", "更井边桐，一叶叶，做秋声。", "斗帐鸾屏。", "翠被华茵。", "梦回时、酒力初醒。", "绿云堆枕，红玉生春。", "且打叠起，龙牙簟，竹夫人。"]'),
('song-ci-67','一翦梅','蔡伸','宋','宋词','song-ci','一翦梅','[]','堆枕乌云堕翠翘。',72,'宋词/ci.song.7000.json','["堆枕乌云堕翠翘。", "午梦惊回，满眼春娇。", "嬛嬛一袅楚宫腰。", "那更春来，玉减香消。", "柳下朱门傍小桥。", "几度红窗，误认鸣镳。", "断肠风月可怜宵。", "忍使恹恹，两处无聊。"]'),
('song-ci-68','一翦梅','蔡伸','宋','宋词','song-ci','一翦梅','[]','高宴华堂夜向阑。',72,'宋词/ci.song.7000.json','["高宴华堂夜向阑。", "急管飞霜，羯鼓声乾。", "仙人掌上水晶盘。", "回按凌波，舞袖弓弯。", "曲罢凝娇整翠鬟。", "玉笋持杯，巧笑嫣然。", "为君一醉倒金船。", "只恐醒来，人隔云山。"]'),
('song-ci-69','一翦梅','蔡伸','宋','宋词','song-ci','一翦梅','[]','夜永虚堂烛影寒。',70,'宋词/ci.song.7000.json','["夜永虚堂烛影寒。", "斗转春来，又是明年。", "异乡怀抱只凄然。", "尊酒相逢且自宽。", "天际孤云云外山。", "梦绕觚稜，日下长安。", "功名已觉负初心，羞对菱花，绿鬓成斑。"]'),
('song-ci-70','六么令','蔡伸','宋','宋词','song-ci','六么令','[]','梅英飘雪，弱柳弄新绿。',112,'宋词/ci.song.7000.json','["梅英飘雪，弱柳弄新绿。", "泠泠画桥流水，风静波如縠。", "长记扁舟共载，偶近旗亭宿。", "渺云横玉。", "鸳鸯枕上，听彻新翻数般曲。", "此际魂清梦冷，绣被香芬馥。", "因念多感情怀，触处伤心目。", "自是今宵独寐，怎不添愁蹙。", "如今心足。", "风前月下，赖有斯人慰幽独。"]'),
('song-ci-71','镇西・小镇西犯','蔡伸','宋','宋词','song-ci','镇西・小镇西犯','[]','秋风吹暗雨，重衾寒透。',98,'宋词/ci.song.7000.json','["秋风吹暗雨，重衾寒透。", "伤心听、晓钟残漏。", "凝情久。", "记红窗夜雪，促膝围炉，交杯劝酒。", "如今顿孤欢偶。", "念别后。", "菱花清镜里。", "眉峰暗斗。", "想标容、怎禁销瘦。", "忍回首。", "但云笺妙墨，鸳锦啼妆，依然似旧。", "临风泪沾襟袖。"]'),
('song-ci-72','看花回','蔡伸','宋','宋词','song-ci','看花回','[]','夜久凉生，庭院漏声频促。',122,'宋词/ci.song.7000.json','["夜久凉生，庭院漏声频促。", "念昔胜游旧地，对画阁层峦，雨馀烟簇。", "新诗暗藏小字，霜刀刊翠竹。", "携素手、细绕回塘，芰荷香里彩鸳宿。", "别后想、香销腻玉。", "带围减、钏宽金粟。", "虽有鳞鸿锦素，柰事与心违，佳期难卜。", "拟解愁肠万结，唯凭尊酒绿。", "望天涯断魂处，醉拍阑干曲。"]'),
('song-ci-73','诉衷情','蔡伸','宋','宋词','song-ci','诉衷情','[]','亭亭秋水玉芙蓉。',54,'宋词/ci.song.7000.json','["亭亭秋水玉芙蓉。", "天际水浮空。", "碧云望中空暮，人在广寒宫。", "双缕枕，曲屏风。", "小房栊。", "可怜今夜，明月清风，无计君同。"]'),
('song-ci-74','浪淘沙','蔡伸','宋','宋词','song-ci','浪淘沙','[]','楼下水潺湲。',64,'宋词/ci.song.7000.json','["楼下水潺湲。", "楼外屏山。", "淡烟笼月晚凉天。", "曾共玉人携素手，同倚阑干。", "云散梦难圆。", "幽恨绵绵。", "旧游重到忍重看。", "负你一生多少泪，月下花前。"]'),
('song-ci-75','如梦令','蔡伸','宋','宋词','song-ci','如梦令','[]','人静重门深亚。',40,'宋词/ci.song.7000.json','["人静重门深亚。", "朱阁画帘高挂。", "人与月俱圆，月色波光相射。", "潇洒。", "潇洒。", "人月长长今夜。"]'),
('song-ci-76','如梦令','蔡伸','宋','宋词','song-ci','如梦令','[]','今夜行云何处。',40,'宋词/ci.song.7000.json','["今夜行云何处。", "还是月华当午。", "倚遍曲阑桥，望断锦屏归路。", "空去。", "空去。", "梦到绿窗朱户。"]'),
('song-ci-77','愁倚阑・春光好','蔡伸','宋','宋词','song-ci','愁倚阑・春光好','[]','伤春晚，送春归。',52,'宋词/ci.song.7000.json','["伤春晚，送春归。", "步云溪。", "绿叶同心双小字，记曾题。", "楼外红日平西。", "长亭路、烟草萋萋。", "云雨不成新梦后，倚阑时。"]'),
('song-ci-78','愁倚阑・春光好','蔡伸','宋','宋词','song-ci','愁倚阑・春光好','[]','天如水，月如钩。',52,'宋词/ci.song.7000.json','["天如水，月如钩。", "正新秋。", "月影参差人窈窕，小红楼。", "如今往事悠悠。", "楼前水、肠断东流。", "旧物忍看金约腕，玉搔头。"]'),
('song-ci-79','愁倚阑・春光好','蔡伸','宋','宋词','song-ci','愁倚阑・春光好','[]','一番雨，一番凉。',52,'宋词/ci.song.7000.json','["一番雨，一番凉。", "夜初长。", "满院蛩吟人不寝，月侵廊。", "木犀微绽幽芳。", "西风透、窈窕红窗。", "恰似个人鸳被里，玉肌香。"]'),
('song-ci-80','望江南・忆江南','蔡伸','宋','宋词','song-ci','望江南・忆江南','[]','花落尽，寂寞委残红。',64,'宋词/ci.song.7000.json','["花落尽，寂寞委残红。", "蝶帐梦回空晓月，凤楼人去谩东风。", "春事已成空。", "闲伫立，□□水溶溶。", "云锁乱山横惨淡，烟笼绿树晚溟濛。", "却在泪痕中。"]'),
('song-ci-81','春光好','蔡伸','宋','宋词','song-ci','春光好','[]','鸾屏掩，翠衾香。',53,'宋词/ci.song.7000.json','["鸾屏掩，翠衾香。", "小兰房。", "回首当时云雨梦，两难忘。", "如今水远山长。", "凭鳞翼、难叙衷肠。", "况是教人无可恨，一味思量。"]'),
('song-ci-82','风流子','蔡伸','宋','宋词','song-ci','风流子','[]','韶华惊晼晚，青春老、倦客惜年芳。',134,'宋词/ci.song.7000.json','["韶华惊晼晚，青春老、倦客惜年芳。", "庭樾荫浓，半藏莺语，畹兰花减，时有蜂忙。", "粉墙低，嫩岚滋翠葆，零露湿残妆。", "风暖昼长，柳绵吹尽，澹烟微雨，梅子初黄。", "洛浦音容远，书空漫惆怅，往事悲凉。", "无奈锦鳞杳杳，不渡横塘。", "念蝴蝶梦回，子规声里，半窗斜月，一枕馀香。", "拟待自宽，除非铁做心肠。"]'),
('song-ci-83','朝中措','蔡伸','宋','宋词','song-ci','朝中措','[]','章台杨柳月依依。',58,'宋词/ci.song.7000.json','["章台杨柳月依依。", "飞絮送春归。", "院宇日长人静，园林绿暗红稀。", "庭前花谢了，行云散后，物是人非。", "唯有一襟清泪，凭阑洒遍残枝。"]'),
('song-ci-84','朝中措','蔡伸','宋','宋词','song-ci','朝中措','[]','雨馀清镜湛秋容。',57,'宋词/ci.song.7000.json','["雨馀清镜湛秋容。", "屏展九华峰。", "万里闲云散尽，半规凉月当空。", "楼高夜永，凭阑笑语，此际谁同。", "端有妙人携手，け然归路凌风。"]'),
('song-ci-85','侍香金童','蔡伸','宋','宋词','song-ci','侍香金童','[]','宝马行春，缓辔随油壁。',78,'宋词/ci.song.7000.json','["宝马行春，缓辔随油壁。", "念一瞬、韶光堪重惜。", "还是去年同醉日。", "客里情怀，倍添凄恻。", "记南城、锦径名园曾遍历。", "更柳下、人家似织。", "此际凭阑愁脉脉。", "满目江山，暮云空碧。"]'),
('song-ci-86','江城子','蔡伸','宋','宋词','song-ci','江城子','[]','碧厨文簟小窗前。',86,'宋词/ci.song.7000.json','["碧厨文簟小窗前。", "乍更阑。", "□□□。", "乌鹊南飞，秋意渐凄然。", "满院蛩吟风露下，人窈窕，月蝉娟。", "双星旧约又经年。", "信谁传。", "恨绵绵。", "□隔明河，长作断肠仙。", "争似秦楼萧史伴，瑶台路，共乘鸾。"]'),
('song-ci-87','西江月','蔡伸','宋','宋词','song-ci','西江月','[]','翡翠蒙金衫子，缕尘如意冠儿。',58,'宋词/ci.song.7000.json','["翡翠蒙金衫子，缕尘如意冠儿。", "持杯轻按遏云词。", "别是出尘风味。", "莫羡双星旧约，愿谐明月佳期。", "凭肩密语两心知。", "一棹五湖烟水。"]'),
('song-ci-88','苍梧谣・归字谣','蔡伸','宋','宋词','song-ci','苍梧谣・归字谣','[]','天。',20,'宋词/ci.song.7000.json','["天。", "休使圆蟾照客眠。", "人何在，桂影自婵娟。"]'),
('song-ci-89','采桑子','蔡伸','宋','宋词','song-ci','采桑子','[]','奇花不比寻常艳，独步南州。',52,'宋词/ci.song.7000.json','["奇花不比寻常艳，独步南州。", "往事悠悠。", "辽鹤重来忆梦游。", "仙翁不改青青眼，一醉迟留。", "妙墨银钩。", "题作人间第一流。"]'),
('song-ci-90','洞仙歌','蔡伸','宋','宋词','song-ci','洞仙歌','[]','莺莺燕燕。',103,'宋词/ci.song.7000.json','["莺莺燕燕。", "本是于飞伴。", "风月佳时阻幽愿。", "但人心坚固后，天也怜人，相逢处、依旧桃花人面。", "绿窗携手，帘幕重重，烛影摇红夜将半。", "对尊前如梦，欲语魂惊，语未竟、已觉衣襟泪满。", "我只为、相思特特来，这度更休推，后回相见。"]'),
('song-ci-91','瑞鹤仙','蔡伸','宋','宋词','song-ci','瑞鹤仙','[]','玉猊香谩爇。',127,'宋词/ci.song.7000.json','["玉猊香谩爇。", "叹瓶沈簪断，紫箫声绝。", "丹青挂寒壁。", "细端详，宛是旧时标格。", "音容望极。", "奈弱水、蓬山路隔。", "似瑶林琼树，韶华正好，一枝先折。", "凄切。", "相思情味，镜中绿鬓，看成华发。", "临风对月。", "空罗袂，搵清血。", "待随群逐队，开眉一笑，除你心肠是铁。", "看今生，为伊烦恼，甚时是彻。"]'),
('song-ci-92','采桑子','何','宋','宋词','song-ci','采桑子','[]','百花丛里花君子，取信东君。',52,'宋词/ci.song.7000.json','["百花丛里花君子，取信东君。", "取信东君。", "名策花中第一勋。", "结成宝鼎和羹味，多谢东君。", "多谢东君。", "香遍还应号令春。"]'),
('song-ci-93','虞美人','何','宋','宋词','song-ci','虞美人','[]','分香帕子揉蓝腻。',66,'宋词/ci.song.7000.json','["分香帕子揉蓝腻。", "欲去殷勤惠。", "重来直待牡丹时。", "只恐花知、知后故开迟。", "别来看尽闲桃李。", "日日阑干倚。", "催花无计问东风。", "梦作一双蝴蝶、绕芳丛。"]'),
('song-ci-94','失调名','何','宋','宋词','song-ci','失调名','[]','便饶你、漫天索价，待我略地酬伊。',16,'宋词/ci.song.7000.json','["便饶你、漫天索价，待我略地酬伊。"]'),
('song-ci-95','失调名','何','宋','宋词','song-ci','失调名','[]','细雨共斜风，作轻寒。',10,'宋词/ci.song.7000.json','["细雨共斜风，作轻寒。"]'),
('song-ci-96','一剪梅・一翦梅','郑刚中','宋','宋词','song-ci','一剪梅・一翦梅','[]','汉粉重番内样妆。',68,'宋词/ci.song.7000.json','["汉粉重番内样妆。", "新染冰肌，浅浅莺黄。", "广寒宫迥阻归期，襟袖空馀暗淡香。", "江路迢迢楚塞长。", "梦里题诗欲寄将。", "觉来斜月又沈西，一点檀心，半染微霜。"]'),
('song-ci-97','临江仙','韩世忠','宋','宋词','song-ci','临江仙','[]','冬看山林萧疏净，春来地润花浓。',71,'宋词/ci.song.7000.json','["冬看山林萧疏净，春来地润花浓。", "少年衰老与山同。", "世间争名利，富贵与贫穷。", "荣贵非干长生药，清闲是不死门风。", "劝君识取主人公。", "单方只一味，尽在不言中。"]'),
('song-ci-98','南乡子','韩世忠','宋','宋词','song-ci','南乡子','[]','人有几何般。',65,'宋词/ci.song.7000.json','["人有几何般。", "富贵荣华总是闲。", "自古英雄都如梦，为官。", "宝玉妻男宿业缠。", "年迈衰残。", "鬓发苍浪骨髓乾。", "不道山林有好处，贪欢。", "只恐痴迷误了贤。"]'),
('song-ci-99','更漏子','黄大舆','宋','宋词','song-ci','更漏子','[]','怜宋玉、许王昌。',14,'宋词/ci.song.7000.json','["怜宋玉、许王昌。", "东西邻短墙。"]'),
('song-ci-100','虞美人','黄大舆','宋','宋词','song-ci','虞美人','[]','世间离恨何时了。',66,'宋词/ci.song.7000.json','["世间离恨何时了。", "不为英雄少。", "楚歌声起霸图休。", "玉帐佳人血泪、满东流。", "葛荒葵老芜城暮。", "玉貌知何处。", "至今芳草解婆娑。", "只有当时魂魄、未消磨。"]'),
('song-ci-101','水调歌头','王灼','宋','宋词','song-ci','水调歌头','["\u957f\u6c5f"]','长江飞鸟外，明月众星中。',114,'宋词/ci.song.7000.json','["长江飞鸟外，明月众星中。", "今来古往如此，人事几秋风。", "又对团团红树，独跨蹇驴归去，山水澹丰容。", "远色动愁思，不见两诗翁。", "酒如渑，谈如绮，气如虹。", "当时痛饮狂醉，只许赏心同。", "响绝光沈休问，俯仰之间陈迹，我亦老飘蓬。", "望久碧云晚，一雁度寒空。"]'),
('song-ci-102','渔家傲','王灼','宋','宋词','song-ci','渔家傲','[]','漠漠郊原荒宿草。',72,'宋词/ci.song.7000.json','["漠漠郊原荒宿草。", "黄花趁得秋风早。", "万里岷峨归梦到。", "东篱好。", "未应花似行人老。", "古往今来成一笑。", "为君醉里销沈了。", "不用登临敧短帽。", "愁绝□。", "吴霜点鬓教谁扫。"]'),
('song-ci-103','醉花阴','王灼','宋','宋词','song-ci','醉花阴','[]','平生五色江淹笔。',62,'宋词/ci.song.7000.json','["平生五色江淹笔。", "合占金闺籍。", "桃李满城春，恨□屏□，只作三年客。", "画船暂系河桥侧。", "一醉分南北。", "惆怅酒醒时，雨笠风蓑，似旧无人识。"]'),
('song-ci-104','清平乐','王灼','宋','宋词','song-ci','清平乐','[]','东风归早。',54,'宋词/ci.song.7000.json','["东风归早。", "已绿瀛洲草。", "紫殿红楼春正好。", "杨柳半和烟袅。", "玉舆遍绕花行。", "初闻百啭新莺。", "历历因风传去，千门万户春声。"]'),
('song-ci-105','清平乐','王灼','宋','宋词','song-ci','清平乐','[]','坠红飘絮。',54,'宋词/ci.song.7000.json','["坠红飘絮。", "收拾春归去。", "长恨春归无觅处。", "心事顾谁分付。", "卢家小苑回塘。", "于飞多少鸳鸯。", "纵使东墙隔断，莫愁应念王昌。"]'),
('song-ci-106','点绛唇','王灼','宋','宋词','song-ci','点绛唇','[]','休惜馀春，试来把酒留春住。',50,'宋词/ci.song.7000.json','["休惜馀春，试来把酒留春住。", "问春无语。", "帘卷西山雨。", "一掬愁心，强欲登高赋。", "山无数。", "烟波无数。", "不放春归去。"]'),
('song-ci-107','浣溪沙','王灼','宋','宋词','song-ci','浣溪沙','[]','一样婵娟别样清。',48,'宋词/ci.song.7000.json','["一样婵娟别样清。", "眼明初识董双成。", "香风随步过帘旌。", "笑捧玉觞频劝客，浣溪沙里转新声。", "花间侧听有流莺。"]'),
('song-ci-108','虞美人','王灼','宋','宋词','song-ci','虞美人','[]','别来杨柳团轻絮。',66,'宋词/ci.song.7000.json','["别来杨柳团轻絮。", "摆撼春风去。", "小园桃李却依依。", "犹自留花不发、待郎归。", "枝头便觉层层好。", "信是花相恼。", "觥船一棹百分空。", "拚了如今醉倒、闹香中。"]'),
('song-ci-109','虞美人','王灼','宋','宋词','song-ci','虞美人','[]','姚黄真是花中主。',66,'宋词/ci.song.7000.json','["姚黄真是花中主。", "个个寻芳去。", "春光能有几多时。", "莫遣无花空折、断肠枝。", "蜂媒蝶使争撩乱。", "应妒传觞缓。", "问花端的为谁开。", "拟作移春小槛、载归来。"]'),
('song-ci-110','菩萨蛮','王灼','宋','宋词','song-ci','菩萨蛮','[]','风柔日薄江村路。',52,'宋词/ci.song.7000.json','["风柔日薄江村路。", "一鞭又逐春光去。", "胡蝶作团飞。", "竹间桃李枝。", "醉魂招不得。", "一半随春色。", "桃李□无多。", "其如风日何。"]'),
('song-ci-111','好事近','王灼','宋','宋词','song-ci','好事近','[]','小砑碧霞笺，不见近来消息。',53,'宋词/ci.song.7000.json','["小砑碧霞笺，不见近来消息。", "玉骨瘦无一把，又不成空忆。", "炉熏歇尽烛花残，佳梦了难得。", "二十五声秋点，最知人端的。"]'),
('song-ci-112','长相思','王灼','宋','宋词','song-ci','长相思','[]','来匆匆。',44,'宋词/ci.song.7000.json','["来匆匆。", "去匆匆。", "短梦无凭春又空。", "难随郎马踪。", "山重重。", "水重重。", "飞絮流云西复东。", "音书何处通。"]'),
('song-ci-113','酒泉子','王灼','宋','宋词','song-ci','酒泉子','[]','锦水花林，前度刘郎行乐处，当时桃李卧莓苔。',53,'宋词/ci.song.7000.json','["锦水花林，前度刘郎行乐处，当时桃李卧莓苔。", "又重来。", "今年菊蕊为君开。", "赖有诗情浑似旧，西风斜日上高台。", "醉千回。"]'),
('song-ci-114','恨来迟','王灼','宋','宋词','song-ci','恨来迟','[]','柳暗汀洲，最春深处，小宴初开。',64,'宋词/ci.song.7000.json','["柳暗汀洲，最春深处，小宴初开。", "似泛宅浮家，水平风软，咫尺蓬莱。", "更劝君、吸尽紫霞杯。", "醉看鸾凤徘徊。", "正洞里桃花，盈盈一笑，依旧怜才。"]'),
('song-ci-115','春光好','王灼','宋','宋词','song-ci','春光好','[]','和醉梦，上峥嵘。',52,'宋词/ci.song.7000.json','["和醉梦，上峥嵘。", "忆娉婷。", "回首锦江烟一色，不分明。", "翻为离别牵情。", "娇啼外、没句丁宁。", "紫陌绿窗多少恨，两难平。"]'),
('song-ci-116','南歌子','王灼','宋','宋词','song-ci','南歌子','["\u897f\u6e56"]','命啸无人啸，含娇何处娇。',62,'宋词/ci.song.7000.json','["命啸无人啸，含娇何处娇。", "江南烟水太迢迢。", "璧月琼枝空想、夜和朝。", "目断肠随断，魂销骨更销。", "琐窗风雨不相饶。", "犹似西湖一枕、听寒潮。"]'),
('song-ci-117','画堂春','王灼','宋','宋词','song-ci','画堂春','[]','暖风和雨暗楼台。',55,'宋词/ci.song.7000.json','["暖风和雨暗楼台。", "馀寒巧作愁媒。", "半春怀抱向谁开。", "忍泪千回。", "断梦已随烟篆，醉魂空殢琼杯。", "小窗瞥见一枝梅。", "疑误君来。"]'),
('song-ci-118','七娘子','王灼','宋','宋词','song-ci','七娘子','[]','花明雾暗非花雾。',72,'宋词/ci.song.7000.json','["花明雾暗非花雾。", "似春屏、短梦无凭据。", "夜月将来，晓灯催去。", "半衾馀暖空留住。", "情柔意密愁千缕。", "想一声、鸡唱东城路。", "暂作行云，暂为行雨。", "阳台望极人何处。"]'),
('song-ci-119','减字木兰花','王灼','宋','宋词','song-ci','减字木兰花','[]','飞霞半缕。',52,'宋词/ci.song.7000.json','["飞霞半缕。", "收尽一天风和雨。", "可惜黄昏。", "残角疏钟要断魂。", "双鱼传信。", "只道横塘消息近。", "心事悠悠。", "同向春风各自愁。"]'),
('song-ci-120','一落索','王灼','宋','宋词','song-ci','一落索','[]','昨夜封枝寒雪。',56,'宋词/ci.song.7000.json','["昨夜封枝寒雪。", "暗堆残叶。", "佳人醉里插钗梁，更不问、眠时节。", "绣被重重夜彻。", "烛光明灭。", "枕旁争听落檐声，更不问、醒时节。"]'),
('song-ci-121','丑奴儿・采桑子','王灼','宋','宋词','song-ci','丑奴儿・采桑子','[]','东风已有归来信，先返梅魂。',52,'宋词/ci.song.7000.json','["东风已有归来信，先返梅魂。", "雪斗纷纷。", "更引蟾光过璧门。", "绿衣小凤枝头语，我有嘉宾。", "急泛清尊。", "莫待江南烂漫春。"]'),
('song-ci-122','减字木兰花','陈袭善','宋','宋词','song-ci','减字木兰花','[]','江南二月。',52,'宋词/ci.song.7000.json','["江南二月。", "犹有枝头千点雪。", "邀上芳尊。", "却占东君一半春。", "尊前眼底。", "南国风光都在此。", "移过江来。", "从此江南不复开。"]'),
('song-ci-123','渔家傲','陈袭善','宋','宋词','song-ci','渔家傲','["\u897f\u6e56"]','鹫岭峰前阑独倚。',72,'宋词/ci.song.7000.json','["鹫岭峰前阑独倚。", "愁眉蹙损愁肠碎。", "红粉佳人伤别袂。", "情何已。", "登山临水年年是。", "常记同来今独至。", "孤舟晚扬湖光里。", "衰草斜阳无限意。", "谁与寄。", "西湖水是相思泪。"]'),
('song-ci-124','丑奴儿・采桑子','曾乾曜','宋','宋词','song-ci','丑奴儿・采桑子','[]','蓦地厮看时。',77,'宋词/ci.song.7000.json','["蓦地厮看时。", "赤怕那、迪功郎儿。", "气岸昂昂因权县，厅子叫道，宣教请后，有无限威仪。", "先自不相知。", "取奉著、剗地胡挥。", "甚时得归京里去，两省八座，横行正任，却会嫌卑。"]'),
('song-ci-125','点绛唇','孙','宋','宋词','song-ci','点绛唇','[]','烟洗风梳，司花先放江梅吐。',50,'宋词/ci.song.7000.json','["烟洗风梳，司花先放江梅吐。", "竹村沙路。", "脉脉摇寒雨。", "醉魄吟魂，无著清香处。", "愁如缕。", "系春不住。", "又折冰枝去。"]'),
('song-ci-126','卜算子','如晦','宋','宋词','song-ci','卜算子','[]','有意送春归，无计留春住。',52,'宋词/ci.song.7000.json','["有意送春归，无计留春住。", "毕竟年年用著来，何似休归去。", "目断楚天遥，不见春归路。", "风急桃花也似愁，点点飞红雨。"]'),
('song-ci-127','菩萨蛮','孙舣','宋','宋词','song-ci','菩萨蛮','[]','一声羌管吹呜咽。',52,'宋词/ci.song.7000.json','["一声羌管吹呜咽。", "玉溪夜半梅翻雪。", "江月正茫茫。", "断桥流水香。", "含章春欲暮。", "落日千山雨。", "一点著枝酸。", "吴姬先齿寒。"]'),
('song-ci-128','倦寻芳','潘汾','宋','宋词','song-ci','倦寻芳','[]','兽环半掩，鸳甃无尘，庭院潇洒。',118,'宋词/ci.song.7000.json','["兽环半掩，鸳甃无尘，庭院潇洒。", "树色沈沈，春尽燕娇莺姹。", "梦草池塘清渐满，海棠轩槛红相亚。", "听箫声，记秦楼夜约，彩鸾齐跨。", "渐迤逦、更催银箭，何处贪欢，犹系骄马。", "旋剪灯花，两点翠眉谁画。", "香灭羞回空帐里，月高犹在重帘下。", "恨疏狂，待归来、碎揉花打。"]'),
('song-ci-129','贺新郎','潘汾','宋','宋词','song-ci','贺新郎','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','篆缕销香鼎。',142,'宋词/ci.song.7000.json','["篆缕销香鼎。", "翠沈沈、庭阴转午，画堂人静。", "芳草王孙知何处，惟有杨花糁径。", "正玉枕、瞢腾初醒。", "门外残红春已去，镇无聊、殢酒厌厌病。", "云髻亸，未忺整。", "江南旧事休重省。", "但天涯、寻消问息，断鸿难倩。", "月满西楼凭阑久，依旧归期未定。", "便只恐、瓶沈金井。", "嘶骑不来银烛暗，枉教人、立尽梧桐影。", "谁伴我，对鸾镜。"]'),
('song-ci-130','孟家蝉','潘汾','宋','宋词','song-ci','孟家蝉','[]','向卖花担上，落絮桥边，春思难禁。',120,'宋词/ci.song.7000.json','["向卖花担上，落絮桥边，春思难禁。", "正暖日温风里，斗采遍香心。", "夜夜稳栖芳草，还处处、先亸春禽。", "满园林。", "梦觉南华，直到如今。", "情深。", "记那人小扇、扑得归来，绣在罗襟。", "芳意赠谁，应费万线千针。", "谩道滕王画得，枉谢客、多少清吟。", "影沈沈。", "舞入梨花，何处相寻。"]'),
('song-ci-131','花心动','潘汾','宋','宋词','song-ci','花心动','[]','啼鸟惊心，怨年华，羞看杏梢桃萼。',127,'宋词/ci.song.7000.json','["啼鸟惊心，怨年华，羞看杏梢桃萼。", "映柳小桥，芳草闲庭，处处旧游如昨。", "断肠人在东风里，遮不尽、几重帘幕。", "旧巢稳，呢喃燕子，笑人漂泊。", "应是素肌瘦削。", "空望断天涯，信音难托。", "半污泪痕，重整馀香，夜夜翠衾寒薄。", "倦游只怕春归去，怎忍见、水流花落。", "梦魂远，韶华又还过却。"]'),
('song-ci-132','玉蝴蝶','潘汾','宋','宋词','song-ci','玉蝴蝶','[]','睡起日高莺啭，画帘低卷，花影重重。',124,'宋词/ci.song.7000.json','["睡起日高莺啭，画帘低卷，花影重重。", "醉眼羞抬，娇困犹自未惺忪。", "绣床近、强来描翠，妆镜掩、不肯匀红。", "锦屏空。", "对花无语，独怨春风。", "匆匆。", "庾郎去后，香销玉减，是事疏慵。", "纵蛮笺封了，何处问鳞鸿。", "眼中泪、万行难尽，眉上恨、一点偏浓。", "杳无踪。", "夜来惟有，幽梦相逢。"]'),
('song-ci-133','丑奴儿慢・采桑子慢','潘汾','宋','宋词','song-ci','丑奴儿慢・采桑子慢','[]','愁春未醒，还是清和天气。',110,'宋词/ci.song.7000.json','["愁春未醒，还是清和天气。", "对浓绿阴中庭院，燕语莺啼。", "数点新荷翠钿，轻泛水平池。", "一帘风絮，才晴又雨，梅子黄时。", "忍记那回，玉人娇困，初试单衣。", "共携手、红窗描绣，画扇题诗。", "怎有如今，半床明月两天涯。", "章台何处，应是为我，蹙损双眉。"]'),
('song-ci-134','忆王孙','李重元','宋','宋词','song-ci','忆王孙','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','萋萋芳草忆王孙。',36,'宋词/ci.song.7000.json','["萋萋芳草忆王孙。", "柳外楼高空断魂。", "杜宇声声不忍闻。", "欲黄昏。", "雨打梨花深闭门。"]'),
('song-ci-135','忆王孙','李重元','宋','宋词','song-ci','忆王孙','[]','风蒲猎猎小池塘。',36,'宋词/ci.song.7000.json','["风蒲猎猎小池塘。", "过雨荷花满院香。", "沈李浮瓜冰雪凉。", "竹方床。", "针线慵拈午梦长。"]'),
('song-ci-136','忆王孙','李重元','宋','宋词','song-ci','忆王孙','[]','飕飕风冷荻花秋。',36,'宋词/ci.song.7000.json','["飕飕风冷荻花秋。", "明月斜侵独倚楼。", "十二珠帘不上钩。", "黯凝眸。", "一点渔灯古渡头。"]'),
('song-ci-137','忆王孙','李重元','宋','宋词','song-ci','忆王孙','[]','彤云风扫雪初晴。',36,'宋词/ci.song.7000.json','["彤云风扫雪初晴。", "天外孤鸿三两声。", "独拥寒衾不忍听。", "月笼明。", "窗外梅花瘦影横。"]'),
('song-ci-138','贺新郎','李玉','宋','宋词','song-ci','贺新郎','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','篆缕销金鼎。',142,'宋词/ci.song.7000.json','["篆缕销金鼎。", "醉沈沈、庭阴转午，画堂人静。", "芳草王孙知何处，惟有杨花糁径。", "渐玉枕、腾腾春醒。", "帘外残红春已透，镇无聊、殢酒厌厌病。", "云鬓乱，未忺整。", "江南旧事休重省。", "遍天涯、寻消问息，断鸿难倩。", "月满西楼凭栏久，依旧归期未定。", "又只恐、瓶沈金井。", "嘶骑不来银烛暗，枉教人、立尽梧桐影。", "谁伴我，对鸾镜。"]'),
('song-ci-139','小重山','吴淑姬1','宋','宋词','song-ci','小重山','[]','谢了荼䕷春事休。',70,'宋词/ci.song.7000.json','["谢了荼䕷春事休。", "无多花片子，缀枝头。", "庭槐影碎被风揉。", "莺虽老，声尚带娇羞。", "独自倚妆楼。", "一川烟草浪，衬云浮。", "不如归去下帘钩。", "心儿小，难著许多愁。"]'),
('song-ci-140','惜分飞','吴淑姬1','宋','宋词','song-ci','惜分飞','[]','岸柳依依拖金缕。',58,'宋词/ci.song.7000.json','["岸柳依依拖金缕。", "是我朝来别处。", "惟有多情絮。", "故来衣上留人住。", "两眼啼红空弹与。", "未见桃花又去。", "一片征帆举。", "断肠遥指苕溪路。"]'),
('song-ci-141','祝英台近','吴淑姬1','宋','宋词','song-ci','祝英台近','[]','粉痕销，芳信断，好梦又无据。',95,'宋词/ci.song.7000.json','["粉痕销，芳信断，好梦又无据。", "病酒无聊，敧枕听春雨。", "断肠曲曲屏山，温温沈水，都是旧、看承人处。", "久离阻。", "应念一点芳心，闲愁知几许。", "偷照菱花，清瘦自羞觑。", "可堪梅子酸时，杨花飞絮，乱莺闹、催将春去。"]'),
('song-ci-142','失调名','吴淑姬1','宋','宋词','song-ci','失调名','[]','尘满妆台。',5,'宋词/ci.song.7000.json','["尘满妆台。"]'),
('song-ci-143','最高楼','柳富','宋','宋词','song-ci','最高楼','[]','人间最苦，最苦是分离。',99,'宋词/ci.song.7000.json','["人间最苦，最苦是分离。", "伊爱我，我怜伊。", "青草岸头人独立，画船东去橹声迟。", "楚天低，回望处，两依依。", "后会也知俱有愿，未知何日是佳期。", "心下事、乱如丝。", "好天良夜还虚过，辜负我、两心知。", "愿伊家，衷肠在，一双飞。"]'),
('song-ci-144','失调名','王幼玉','宋','宋词','song-ci','失调名','[]','粉面羞搽泪满腮。',8,'宋词/ci.song.7000.json','["粉面羞搽泪满腮。"]'),
('song-ci-145','渔家傲','李生','宋','宋词','song-ci','渔家傲','[]','庭院黄昏人悄悄。',72,'宋词/ci.song.7000.json','["庭院黄昏人悄悄。", "两情暗约谁知道。", "咫尺蓬山难一到。", "明月照。", "潜身只得听言笑。", "特地嗟吁传密耗。", "芳衷要使郎心表。", "此际归来愁不少。", "萦怀抱。", "卿卿销得人烦恼。"]'),
('song-ci-146','极相思令・极相思','谭意哥','宋','宋词','song-ci','极相思令・极相思','[]','湘东最是得春先。',61,'宋词/ci.song.7000.json','["湘东最是得春先。", "和气暖如绵。", "清明过了，残花巷陌，犹见秋千。", "对景感时情绪乱，这密意、翠羽空传。", "风前月下，花时永昼，洒泪何言。"]'),
('song-ci-147','长相思令・长相思','谭意哥','宋','宋词','song-ci','长相思令・长相思','[]','旧燕初归，梨花满院，迤逦天气融和。',126,'宋词/ci.song.7000.json','["旧燕初归，梨花满院，迤逦天气融和。", "新晴巷陌，是处轻车骏马，禊饮笙歌。", "旧赏人非，对佳时、一向乐少愁多。", "远意沈沈，幽闺独自颦蛾。", "正消黯、无言自感，凭高远意，空寄烟波。", "从来美事，因甚天教，两处多磨。", "开怀强笑，向新来、宽却衣罗。", "似恁他、人怪憔悴，甘心总为伊呵。"]'),
('song-ci-148','极相思','李氏1','宋','宋词','song-ci','极相思','[]','日红疏翠密晴暄。',60,'宋词/ci.song.7000.json','["日红疏翠密晴暄。", "初夏困人天。", "风流滋味，伤怀尽在，花下风前。", "后约已知君定，这心绪、尽日悬悬。", "鸳鸯两处，清宵最苦，月甚先圆。"]'),
('song-ci-149','南乡子','花仲胤','宋','宋词','song-ci','南乡子','[]','顿首起情人。',66,'宋词/ci.song.7000.json','["顿首起情人。", "即日恭维问好音。", "接得彩笺词一首，堪惊。", "题起词名恨转生。", "展转意多情。", "寄与音书不志诚。", "不写伊川题尹字，无心。", "料想伊家不要人。"]'),
('song-ci-150','伊川令・伊州令','花仲胤妻','宋','宋词','song-ci','伊川令・伊州令','[]','西风昨夜穿帘幕。',58,'宋词/ci.song.7000.json','["西风昨夜穿帘幕。", "闺院添消索。", "最是梧桐零落。", "迤逦秋光过却。", "人情音信难托。", "鱼雁成耽阁。", "教奴独自守空房，泪珠与、灯花共落。"]'),
('song-ci-151','失调名','花仲胤妻','宋','宋词','song-ci','失调名','[]','奴启情人勿见罪。',39,'宋词/ci.song.7000.json','["奴启情人勿见罪。", "闲将小书作尹字。", "情人不解其中意。", "问伊间别几多时。", "身边少个人儿。"]'),
('song-ci-152','期夜月','刘浚','宋','宋词','song-ci','期夜月','[]','金钩花绶系双月。',137,'宋词/ci.song.7000.json','["金钩花绶系双月。", "腰肢软低折。", "揎皓腕，萦绣结。", "轻盈宛转，妙若凤鸾飞越。", "无别。", "香檀急扣转清切。", "翻纤手飘瞥。", "催画鼓，追脃管，锵洋雅奏，尚与众音为节。", "当时妙选舞袖，慧性雅资，名为殊绝。", "满座倾心注目，不甚窥回雪。", "纤怯。", "逡巡一曲霓裳彻。", "汗透鲛绡肌润，教人传香粉，媚容秀发。", "宛降蕊珠宫阙。"]'),
('song-ci-153','卜算子','施酒监','宋','宋词','song-ci','卜算子','[]','相逢情便深，恨不相逢早。',54,'宋词/ci.song.7000.json','["相逢情便深，恨不相逢早。", "识尽千千万万人，终不似、伊家好。", "别你登长道。", "转更添烦恼。", "楼外朱楼独倚阑，满目围芳草。"]'),
('song-ci-154','卜算子','乐婉','宋','宋词','song-ci','卜算子','[]','相思似海深，旧事如天远。',55,'宋词/ci.song.7000.json','["相思似海深，旧事如天远。", "泪滴千千万万行，更使人愁断肠。", "要见无因见，了拚终难拚。", "若是前生未有缘，待重结、来生愿。"]'),
('song-ci-155','江神子・江城子','虞某','宋','宋词','song-ci','江神子・江城子','[]','相逢只怕有分离。',86,'宋词/ci.song.7000.json','["相逢只怕有分离。", "许多时。", "暗为期。", "常是眉来眼去、惹猜疑。", "何似总休拈弄上，轻咳嗽、有人知。", "终须买个小船儿。", "任风吹。", "尽东西。", "假使天涯海角、也相随。", "纵被江神收领了，离不得、我和伊。"]'),
('song-ci-156','失调名','巴谈','宋','宋词','song-ci','失调名','[]','正月月尽夕。',76,'宋词/ci.song.7000.json','["正月月尽夕。", "芭蕉船一只。", "灯盏两只明辉辉，内里更有筵席。", "奉劝郎君小娘子。", "饱吃莫形迹。", "每年只有今日日。", "愿我做来称意。", "奉劝郎君小娘子。", "空去送穷鬼。", "空去送穷鬼。"]'),
('song-ci-157','清平乐','杨师纯','宋','宋词','song-ci','清平乐','[]','羞娥浅浅。',54,'宋词/ci.song.7000.json','["羞娥浅浅。", "秋水如刀剪。", "窗下无人自针线。", "不觉郎来身畔。", "相将携手鸳帏。", "匆匆不许多时。", "耳畔告郎低语，共郎莫使人知。"]'),
('song-ci-158','清平乐','杨师纯','宋','宋词','song-ci','清平乐','[]','小庭春院。',54,'宋词/ci.song.7000.json','["小庭春院。", "睡起花阴转。", "往事旧欢离思远。", "柳絮随风难管。", "等闲屈指当时。", "阑干几曲谁知。", "为问春风桃李，而今子满芳枝。"]'),
('song-ci-159','渔家傲','杨端臣','宋','宋词','song-ci','渔家傲','[]','有个人人情不久。',72,'宋词/ci.song.7000.json','["有个人人情不久。", "而今已落他人手。", "见说近来伊也瘦。", "好教受。", "看谁似我能撋就。", "莲脸能匀眉黛皱。", "相思泪滴残妆透。", "总是自家为事谬。", "从今后。", "这回断了心先有。"]'),
('song-ci-160','渔家傲','杨端臣','宋','宋词','song-ci','渔家傲','[]','楼鼓数声人迹散。',72,'宋词/ci.song.7000.json','["楼鼓数声人迹散。", "马蹄不响街尘软。", "门户深深扃小院。", "帘不卷。", "背灯尽烛红条短。", "归路恍如春梦断。", "千愁万恨知河限。", "昨夜月华明似练。", "花影畔。", "算来惟有嫦娥见。"]'),
('song-ci-161','阮郎归','杨端臣','宋','宋词','song-ci','阮郎归','[]','□□今日那人家。',56,'宋词/ci.song.7000.json','["□□今日那人家。", "琐窗红影斜。", "髻云散乱不胜花。", "偷匀残脸霞。", "梁燕老，石榴花。", "佳期今已差。", "凭阑思想入天涯。", "暮云重叠遮。"]'),
('song-ci-162','失调名','聂胜琼','宋','宋词','song-ci','失调名','[]','无计留君住。',14,'宋词/ci.song.7000.json','["无计留君住。", "奈何无计随君去。"]'),
('song-ci-163','鹧鸪天','聂胜琼','宋','宋词','song-ci','鹧鸪天','[]','玉惨花愁出凤城。',64,'宋词/ci.song.7000.json','["玉惨花愁出凤城。", "莲花楼下柳青青。", "尊前一唱阳关后，别个人人第五程。", "寻好梦，梦难成。", "况谁知我此时情。", "枕前泪共帘前雨，隔个窗儿滴到明。"]'),
('song-ci-164','燕归梁','赵才卿','宋','宋词','song-ci','燕归梁','[]','细柳营中有亚夫。',61,'宋词/ci.song.7000.json','["细柳营中有亚夫。", "华宴簇名姝。", "雅歌长许佐投壶。", "无一日、不欢娱。", "汉王拓境思名将，捧飞诏欲登途。", "从前密约尽成虚。", "空赢得、泪流珠。"]'),
('song-ci-165','雨中花慢','任','宋','宋词','song-ci','雨中花慢','[]','事往人离，还似暮峡归云，陇上流泉。',117,'宋词/ci.song.7000.json','["事往人离，还似暮峡归云，陇上流泉。", "奈向分罗带，已断么弦。", "长记歌时酒畔，难忘月夕花前。", "相携手处，琼楼珠户，触目依然。", "从来惯共，锦衾屏枕，长效比翼文鸳。", "谁念我、而今清夜，常是孤眠。", "入户不如飞絮，傍怀争及炉烟。", "这回休也，一生心性，为你萦牵。"]'),
('song-ci-166','朝中措','都下妓','宋','宋词','song-ci','朝中措','[]','屏山栏槛倚晴空。',57,'宋词/ci.song.7000.json','["屏山栏槛倚晴空。", "山色有无中。", "手种庭前桃李，别来几度春风。", "文章宰相，挥毫万字，一饮千锺。", "行乐不须年少，尊前看取仙翁。"]'),
('song-ci-167','沁园春','李弥逊','宋','宋词','song-ci','沁园春','[]','敧枕深轩，散帙虚堂，畏景屡移。',140,'宋词/ci.song.7000.json','["敧枕深轩，散帙虚堂，畏景屡移。", "渐披襟临水，搘床就月，莲香拂面，竹色侵衣。", "压玉为醪，折荷当盏，卧看银潢星四垂。", "人归后，伴饥蝉自语，宿鸟相依。", "痴儿。", "莫蹈危机。", "悟四十九年都尽非。", "任纡朱拖紫，围金佩玉，青钱流地，白璧如坻。", "富贵浮云，身名零露，事事无心归便归。", "秋风动，正吴淞月冷，莼长鲈肥。"]'),
('song-ci-168','永遇乐','李弥逊','宋','宋词','song-ci','永遇乐','[]','曲径通幽，小亭依翠，春事才过。',128,'宋词/ci.song.7000.json','["曲径通幽，小亭依翠，春事才过。", "看笋成竿，等花著果，永昼供闲坐。", "苍苍晚色，临渊小立，引首暮鸥飞堕。", "悄无人，一溪山影，可惜被渠分破。", "百年似梦，一身如寄，南北去留皆可。", "我自知鱼，け然濠上，不问鱼非我。", "隔篱呼取，举杯对影，有唱更凭谁和。", "知渊明，清流临赋，得似恁麽。"]'),
('song-ci-169','永遇乐','李弥逊','宋','宋词','song-ci','永遇乐','[]','五十劳生，紫髯霜换，白日驹过。',128,'宋词/ci.song.7000.json','["五十劳生，紫髯霜换，白日驹过。", "闭户推愁，缘崖避俗，壁角团蒲坐。", "提壶人至，竹根同卧，醉帽尽从敧堕。", "梦惊回，满身疏影，露滴月斜云破。", "无人自酌，有邀皆去，我笑两翁多可。", "忍冻吟诗，典衣沽酒，二子应嗤我。", "两忘一笑，调同今古，谁道郢歌无和。", "后之人，犹今视昔，有能继麽。"]'),
('song-ci-170','念奴娇','李弥逊','宋','宋词','song-ci','念奴娇','[]','瑶池倒影，露华浓、群玉峰峦如洗。',121,'宋词/ci.song.7000.json','["瑶池倒影，露华浓、群玉峰峦如洗。", "明镜平铺秋水净，寒锁一天空翠。", "荷芰风摇，苹蘩波动，惊起鱼龙戏。", "扶疏桂影，十分光照人世。", "谁似。", "老子痴顽，胡床危坐，自引壶觞醉。", "斗转参横歌未彻，屋角乌飞星坠。", "对影三人，停杯一问，谁会骑鲸意。", "金牛何处，玉楼高耸十二。"]'),
('song-ci-171','念奴娇','李弥逊','宋','宋词','song-ci','念奴娇','[]','风帘弄影，正闲堂永昼，香销人寂。',120,'宋词/ci.song.7000.json','["风帘弄影，正闲堂永昼，香销人寂。", "轧轧邻机芳思乱，愁入回文新织。", "燕蹴巢泥，莺喧庭柳，好梦无踪迹。", "那堪春事，背人何计留得。", "谁似爱酒南邻，岸巾坦腹，醉踏西山碧。", "彩笔阳春传雁足，催我飞觞浮白。", "老去情怀，凭君试看，鬓上秋霜色。", "故园千里，月华空照相忆。"]'),
('song-ci-172','念奴娇','李弥逊','宋','宋词','song-ci','念奴娇','["\u9ec4\u9e64\u697c"]','楚天木落，际平芜千里，寒霜凝碧。',120,'宋词/ci.song.7000.json','["楚天木落，际平芜千里，寒霜凝碧。", "鄂渚波横何处是，当日孙郎赤壁。", "黄耳音稀，白云望远，又见春消息。", "嘉辰长记，谢池梅蕊初摘。", "遥想黄鹤楼高，兰阶丝管沸，传觞如织。", "倦客心驰归路绕，不及南飞双翼。", "固著斑衣，重翻锦字，寄远供新拍。", "明年欢侍，寿期应献千百。"]'),
('song-ci-173','三段子・宝鼎现','李弥逊','宋','宋词','song-ci','三段子・宝鼎现','[]','层林烟霁，巨壁天半，鸿飞无路。',192,'宋词/ci.song.7000.json','["层林烟霁，巨壁天半，鸿飞无路。", "云断处、两山之间，十万琅玕环翠羽。", "转秀谷、枕苹花汀溆。", "短柳疏篱向暮。", "看卧垄牛归，横舟人去，平芜鸥鹭。", "并游不见鞭鸾侣。", "只僧前、松子随步。", "回径险、凌风遐想，小憩清泉敧茂树。", "正笋蕨、过如苏新雨。", "矶下游鱼可数。", "纵窈窕、云关长启，寂寂谁争子所。", "世上丹毂朱缨，春梦觉、南柯何许。", "况荣枯无定，中有欢离愁聚。", "尽笑我、诧盘中趣。", "为续昌黎赋。", "会有人，秣马膏车，相属一尊清醑。"]'),
('song-ci-174','水调歌头','李弥逊','宋','宋词','song-ci','水调歌头','[]','清夜月当午，轩户踏层冰。',114,'宋词/ci.song.7000.json','["清夜月当午，轩户踏层冰。", "楼高百尺，缥缈天阙敞云扃。", "万里风摇玉树，吹我衣裾零乱，寒入骨毛轻。", "径欲乘之去，高兴送青冥。", "神仙说，功名事，两难成。", "苇汀筠岫深处，端可寄馀龄。", "身外营营姑置，对景掀髯一笑，引手接飞萤。", "且尽杯中物，日出事还生。"]'),
('song-ci-175','水调歌头','李弥逊','宋','宋词','song-ci','水调歌头','[]','安石寓丝竹，方朔杂诙谐。',114,'宋词/ci.song.7000.json','["安石寓丝竹，方朔杂诙谐。", "昂霄气概，古来无地可容才。", "不见骑鲸仙伯，唾手功名事了，猿鹤与同侪。", "有意谢轩冕，无计避嫌猜。", "静中乐，山照座，月浮杯。", "忘形湛辈，一笑丘壑写高怀。", "只恐天催玉斧，为破烟尘昏翳，人自日边来。", "东阁动诗兴，莫待北枝开。"]'),
('song-ci-176','水调歌头','李弥逊','宋','宋词','song-ci','水调歌头','[]','松柏渐成趣，红紫勿齐开。',114,'宋词/ci.song.7000.json','["松柏渐成趣，红紫勿齐开。", "花神靳惜芳事，日日待公来。", "遥想金葵侧处，素月华灯相照，妆影满歌台。", "馀韵写宫徵，飞落远山隈。", "逃禅客，尊中尽，厌长斋。", "且愁风絮，断送春色揽离怀。", "命驾何妨千里，只恐行云碍辙，直磴插崔嵬。", "手拍阳春唱，隔岸借残杯。"]'),
('song-ci-177','水调歌头','李弥逊','宋','宋词','song-ci','水调歌头','[]','不见隐君子，一月比三秋。',114,'宋词/ci.song.7000.json','["不见隐君子，一月比三秋。", "惊涛如许，梦魂无路绝横流。", "安得如云长翮，命驾不须千里，上下逐君游。", "此计杳难就，注目倚江楼。", "西风里，多少恨，寄歌头。", "飞奴接翼，为我三度下南州。", "正是天寒日暮，独钓一江残雪，风猎碧莎裘。", "和子浩然句，一酌散千忧。"]'),
('song-ci-178','水调歌头','李弥逊','宋','宋词','song-ci','水调歌头','[]','不上长安道，霜鬓几惊秋。',114,'宋词/ci.song.7000.json','["不上长安道，霜鬓几惊秋。", "故人何在，时序欺我去如流。", "赏对洛滨仙伯，共说芗林佳致，魂梦与追游。", "更唱中秋句，得月上东楼。", "云岩底，秋香下，楚江头。", "十年笑傲，真是骑鹤上扬州。", "却忆金门联辔，晓殿催班同到，高拱翠云裘。", "明月今千里，何计缓离忧。"]'),
('song-ci-179','水调歌头','李弥逊','宋','宋词','song-ci','水调歌头','[]','白发闽江上，几度过中秋。',114,'宋词/ci.song.7000.json','["白发闽江上，几度过中秋。", "阴晴相半，曾见玉塔卧寒流。", "不似今年三五，皎皎冰轮初上，天阙恍神游。", "下视人间世，万户水明楼。", "贤公子，追乐事，占鳌头。", "酒酣喝月，腰鼓百面打凉州。", "沈醉尽扶红袖，不管风摇仙掌，零露湿轻裘。", "但恐尊中尽，身外复何忧。"]'),
('song-ci-180','蓦山溪','李弥逊','宋','宋词','song-ci','蓦山溪','[]','冲寒山意，未放江头树。',102,'宋词/ci.song.7000.json','["冲寒山意，未放江头树。", "老去恨春迟，数花期、朝朝暮暮。", "疏英冷蕊，也为有情忙，深夜月，小庭中，绝胜西城路。", "调元妙手，便是春来处。", "酝造十分香，更暖借、毫端烟雨。", "狂歌醉客，小摘问东风，花谢后，子成时，趁得和羹否。"]'),
('song-ci-181','蓦山溪','李弥逊','宋','宋词','song-ci','蓦山溪','[]','竹边柳外，两两寒梅树。',102,'宋词/ci.song.7000.json','["竹边柳外，两两寒梅树。", "疏影上帘栊，似却□、一枝横暮。", "玉肌瘦损，有恨不禁春，萦冰佩，整风裳，怅望瑶台路。", "我来胜赏，持酒花深处。", "天晓酿幽香，正一霎、如酥小雨。", "江山得助，臭味许谁同，长安远，故人疏，梦到江南否。"]'),
('song-ci-182','昆明池・金明池','李弥逊','宋','宋词','song-ci','昆明池・金明池','[]','帐锦笼庭，囊香飘榭，过了芳时强半。',149,'宋词/ci.song.7000.json','["帐锦笼庭，囊香飘榭，过了芳时强半。", "觅残红、蜂须趁日，占新绿、莺喉咤暖。", "数花期、望得春来，春去也、把酒南山谁伴。", "更帘幕垂垂，恼人飞絮，乱落一轩风晚。", "手拍狂歌挥醉碗。", "笑浪走江头，几逢归燕。", "忆黄华、曾吹纱帽，讶彩楼、催攽纨扇。", "功名事、於我如云，谩赢得星星，满簪霜换。", "向棠棣华间，鶺鴒原上，莫厌尊罍频来见。"]'),
('song-ci-183','十月桃','李弥逊','宋','宋词','song-ci','十月桃','[]','浮云无定，任春风万点，吹上寒枝。',122,'宋词/ci.song.7000.json','["浮云无定，任春风万点，吹上寒枝。", "砌外珑璁，暗香夜透帘帏。", "闲情最宜酒伴，胜黄昏、冷月清溪。", "风流谢傅，梦到华胥，长是相随。", "似凝愁、不语谁知。", "芳思乱微酸，已带离离。", "传语花神，任教横竹三吹。", "枝头要看如豆，趁和羹、百卉开时。", "十分金蕊，先与东君，一笑相期。"]'),
('song-ci-184','十月桃','李弥逊','宋','宋词','song-ci','十月桃','[]','一枝三四，弄疏英秀色，特地生寒。',122,'宋词/ci.song.7000.json','["一枝三四，弄疏英秀色，特地生寒。", "刻楮三年，谩夸煮石成丹。", "梨花带雨难并，似玉妃、寂寞微潸。", "瑶台空阔，露下星坠，零乱风鬟。", "记前回、拥盖西园。", "花信被山烟，著意邀阑。", "盏面横斜，大家月底颓然。", "如今万点难缀，共苍苔、打合成班。", "诗翁何似，劝春莫交，粉淡香残。"]'),
('song-ci-185','声声慢','李弥逊','宋','宋词','song-ci','声声慢','[]','龙涎染就，沈水薰成，分明乱屑琼瑰。',119,'宋词/ci.song.7000.json','["龙涎染就，沈水薰成，分明乱屑琼瑰。", "一朵才开，人家千里须知。", "花儿大则不大，有许多、潇洒清奇。", "较量尽，诮胜如末利，赛过酴醿。", "更被秋光断送，微放些月照，著阵风吹。", "恼杀多情，猛拚沈醉酬伊。", "朝朝暮暮守定，尽忙时、也不分离。", "睡梦里，胆瓶儿、枕畔数枝。"]'),
('song-ci-186','永遇乐','李弥逊','宋','宋词','song-ci','永遇乐','[]','一水如绳，两山如翼，绿野如绣。',128,'宋词/ci.song.7000.json','["一水如绳，两山如翼，绿野如绣。", "松院干霄，筠庄枕浪，揽尽溪山秀。", "水南水北，竹舆兰棹，来往月宵花昼。", "问人间、天上何处，更寻大围小有。", "人言拒梗，功成仙去，丹鼎夜寒光透。", "唤取云英，炼成石髓，日月齐长久。", "烦君挟我，朝元真阙，两翼羽轻风骤。", "此时看，小茅峰顶，有云贯斗。"]'),
('song-ci-187','满庭芳','李弥逊','宋','宋词','song-ci','满庭芳','[]','荷背翻黄，蕉心滴翠，雨洗庭院无尘。',117,'宋词/ci.song.7000.json','["荷背翻黄，蕉心滴翠，雨洗庭院无尘。", "断云缺处，矫首望冰轮。", "迤逦天垂四幕，星杓淡、河汉横银。", "笙歌散，风帘自上，寒水满楼明。", "刘郎方得计，钗摇绣户，枕并华裀。", "笑狂客无眠，坐听锺鲸。", "明月中秋一梦，临鸳甃、三绕殷勤。", "清光里，持杯对影，风月两兼并。"]'),
('song-ci-188','水龙吟','李弥逊','宋','宋词','song-ci','水龙吟','[]','化工收拾芳菲，晕酥翦彩迎春禊。',126,'宋词/ci.song.7000.json','["化工收拾芳菲，晕酥翦彩迎春禊。", "江山影里，泰阶星聚，重寻古意。", "曲水流觞，晚林张宴，竹边花外。", "倩飞英衬地，繁枝障日，游丝驻，羲和旆。", "雪避清歌自止。", "放一钩、玉沈寒水。", "西园飞盖，东山携妓，古今无愧。", "闻道东君，商量花蕊，作明年计。", "待公归，独运丹青妙手，忆山阴醉。"]'),
('song-ci-189','洞仙歌','李弥逊','宋','宋词','song-ci','洞仙歌','[]','断桥斜路，又是春来也。',103,'宋词/ci.song.7000.json','["断桥斜路，又是春来也。", "仙掌挼云半开谢。", "尽凝酥砌粉，不似真香，分明对、冰雪肌肤姑射。", "天涯伤老大，万斛新愁，一笑端须问花借。", "纵广平冷淡，铁石心肠，未拚得、花里风前月下。", "为传语、游蜂缓经营，且留与山翁，醉吟清夜。"]'),
('song-ci-190','洞仙歌','李弥逊','宋','宋词','song-ci','洞仙歌','[]','残烟薄雾，杖东风排遣。',101,'宋词/ci.song.7000.json','["残烟薄雾，杖东风排遣。", "收拾轻寒做轻暖。", "问墙偶屋角，多少青红，春不语，行处随人近远。", "穿帘花影乱，金鸭香温，幽梦醒时午禽啭。", "任抛书推枕，嚼蕊攀条，暗消了、清愁一半。", "且莫放、浮云蔽晴晖，怕惹起羁人，望中凝恋。"]'),
('song-ci-191','江神子・江城子','李弥逊','宋','宋词','song-ci','江神子・江城子','[]','梦中北去又南来。',86,'宋词/ci.song.7000.json','["梦中北去又南来。", "饱风埃。", "鬓华衰。", "浮木飞蓬，踪迹为谁催。", "自笑自悲还自误，一杯酒，鼻如雷。", "晓舆行处觉春回。", "屑琼瑰。", "糁□苔。", "病眼冲寒，欲闭又还开。", "近水人家篱落畔，遥认得，一枝梅。"]'),
('song-ci-192','感皇恩','李弥逊','宋','宋词','song-ci','感皇恩','[]','入夜月华清，中天方好。',81,'宋词/ci.song.7000.json','["入夜月华清，中天方好。", "更著山光两相照。", "星稀云净，玉树惊乌三绕。", "广寒风陆近，秋光老。", "老山高胜，飞尘不到。", "亭上仙翁自昏晓。", "短封新唱，字字令人绝倒。", "待凭书寄恨，归鸿少。"]'),
('song-ci-193','浣溪沙','王以宁','宋','宋词','song-ci','浣溪沙','[]','艾胜迎薰寿缕长。',48,'宋词/ci.song.7000.json','["艾胜迎薰寿缕长。", "碧篘酒泛绿蒲香。", "万家喜气在都粱。", "小阁幽轩新料理，舞衫歌扇且传觞。", "看君飞步上明光。"]'),
('song-ci-194','浣溪沙','王以宁','宋','宋词','song-ci','浣溪沙','[]','招福宫中第几真。',48,'宋词/ci.song.7000.json','["招福宫中第几真。", "餐花辟谷小夫人。", "天翁新与玉麒麟。", "我识外家西府相，玉壶冰雪照青春。", "小郎风骨已凌云。"]'),
('song-ci-195','踏莎行','王以宁','宋','宋词','song-ci','踏莎行','[]','梦褥光宗，河东右族。',68,'宋词/ci.song.7000.json','["梦褥光宗，河东右族。", "向来到耳声华熟。", "游从两世纪金兰，风流二阮居南北。", "今夕何辰，相亲灯烛。", "一廛我愿依韦曲。", "长君未可赋骊驹，山人莫为蒲轮促。"]'),
('song-ci-196','踏莎行','王以宁','宋','宋词','song-ci','踏莎行','[]','我自山中，渔樵冷族。',68,'宋词/ci.song.7000.json','["我自山中，渔樵冷族。", "一丘一壑平生熟。", "朅来江海寄馀生，心兵语阱频奔北。", "九里灵河，十分光烛。", "分辉借润须邻曲。", "柳家兄弟莫瞋人，狂奴小户元低促。"]'),
('song-ci-197','踏莎行','王以宁','宋','宋词','song-ci','踏莎行','[]','位正三槐，光生九族。',68,'宋词/ci.song.7000.json','["位正三槐，光生九族。", "人间一梦黄粱熟。", "迩来荆楚地行仙，卜居深在延原北。", "笑问从前，谁调玉烛。", "当筵鲍老那能曲。", "山中饮酒是生涯，欲归未果成烦促。"]'),
('song-ci-198','感皇恩','王以宁','宋','宋词','song-ci','感皇恩','["\u6d1e\u5ead\u6e56"]','千古洞庭湖，百川争注。',81,'宋词/ci.song.7000.json','["千古洞庭湖，百川争注。", "雪浪银涛正如许。", "骑鲸诗客，浩气决云飞雾。", "背人歌欸乃，凌空去。", "我欲从公，翩然鹄举。", "未愿人间相君雨。", "笭箸短棹，是我平身真语。", "个中烟景好，烦公句。"]'),
('song-ci-199','庆双椿・浣溪沙','王以宁','宋','宋词','song-ci','庆双椿・浣溪沙','[]','问政山头景气嘉。',48,'宋词/ci.song.7000.json','["问政山头景气嘉。", "仙家绿酒荐菖芽。", "仙郎玉女共乘槎。", "学士文章舒锦绣，夫人冠帔烂云霞。", "寿香来是道人家。"]'),
('song-ci-200','渔家傲','王以宁','宋','宋词','song-ci','渔家傲','[]','往事闲思人共怕。',72,'宋词/ci.song.7000.json','["往事闲思人共怕。", "十年塞上烟尘亚。", "百万铁衣驰铁马。", "都弄罢。", "八风断送归莲社。", "卖药得钱休教化。", "归来醉卧蜗牛舍。", "一颗明珠元不夜。", "非待借。", "神光穿透诸天下。"]'),
('song-ci-201','好事近','王以宁','宋','宋词','song-ci','好事近','[]','诗客少微家，世有斗南人杰。',53,'宋词/ci.song.7000.json','["诗客少微家，世有斗南人杰。", "一段素襟清韵，似玉壶冰雪。", "怀中卿相饱经纶，况是好时节。", "我有太平歌颂，待形容贤业。"]'),
('song-ci-202','好事近','王以宁','宋','宋词','song-ci','好事近','[]','白石读书房，世有斗南人杰。',53,'宋词/ci.song.7000.json','["白石读书房，世有斗南人杰。", "一段素襟清韵，似玉壶冰雪。", "仙家赤酒荐交梨，道眼况超越。", "来往十州三岛，跨一轮新月。"]'),
('song-ci-203','虞美人','王以宁','宋','宋词','song-ci','虞美人','["\u6d1e\u5ead\u6e56"]','归来峰下霜如水。',66,'宋词/ci.song.7000.json','["归来峰下霜如水。", "明月三千里。", "幽人独立瞰长淮。", "谁棹扁舟一叶、趁潮来。", "洞庭湖上银涛观。", "忆我烟蓑伴。", "此身天地一浮萍。", "去国十年华发、欲星星。"]'),
('song-ci-204','浣溪沙','王以宁','宋','宋词','song-ci','浣溪沙','[]','快雨疏风六月凉。',48,'宋词/ci.song.7000.json','["快雨疏风六月凉。", "貂蝉人著彩衣裳。", "肃然心拜玉炉香。", "相国趣还调鼎鼐，潘舆指日下潇湘。", "秋来江上接归航。"]'),
('song-ci-205','南歌子','王以宁','宋','宋词','song-ci','南歌子','[]','未折江南柳，先开陇上梅。',62,'宋词/ci.song.7000.json','["未折江南柳，先开陇上梅。", "绿情红意到根荄。", "昨夜春随和气、已归来。", "忠力扶昌运，冲和保圣胎。", "阳功阴德好栽培。", "他日骑鲸仙路、指蓬莱。"]'),
('song-ci-206','鹧鸪天','王以宁','宋','宋词','song-ci','鹧鸪天','["\u9ec4\u6cb3"]','瑞雪当空舞素英。',64,'宋词/ci.song.7000.json','["瑞雪当空舞素英。", "玳筵收得满金瓶。", "洗教双眼明如镜，看取黄河几度清。", "龟畀寿，鹤为形。", "年年长愿见仪刑。", "他年林下逢彭祖，唤作谁家小后生。"]'),
('song-ci-207','法驾导引','陈与义','宋','宋词','song-ci','法驾导引','[]','朝元路，朝元路，同驾玉华君。',36,'宋词/ci.song.7000.json','["朝元路，朝元路，同驾玉华君。", "千乘载花红一色，人间遥指是祥云。", "回望海光新。"]'),
('song-ci-208','法驾导引','陈与义','宋','宋词','song-ci','法驾导引','[]','东风起，东风起，海上百花摇。',36,'宋词/ci.song.7000.json','["东风起，东风起，海上百花摇。", "十八风鬟云半动，飞花和雨著轻绡。", "归路碧迢迢。"]'),
('song-ci-209','法驾导引','陈与义','宋','宋词','song-ci','法驾导引','[]','帘漠漠，帘漠漠，天澹一帘秋。',36,'宋词/ci.song.7000.json','["帘漠漠，帘漠漠，天澹一帘秋。", "自洗玉舟斟白醴，月华微映是空舟。", "歌罢海西流。"]'),
('song-ci-210','虞美人','陈与义','宋','宋词','song-ci','虞美人','[]','十年花底承潮露。',66,'宋词/ci.song.7000.json','["十年花底承潮露。", "看到江南树。", "洛阳城里又东风。", "未必桃花得似、旧时红。", "胭脂睡起春才好。", "应恨人空老。", "心情虽在只吟诗。", "白发刘郎孤负、可怜枝。"]'),
('song-ci-211','忆秦娥','陈与义','宋','宋词','song-ci','忆秦娥','["\u6d1e\u5ead\u6e56"]','鱼龙舞。',56,'宋词/ci.song.7000.json','["鱼龙舞。", "湘君欲下潇湘浦。", "潇湘浦。", "兴亡离合，乱波平楚。", "独无尊酒酬端午。", "移舟来听明山雨。", "明山雨。", "白头孤客，洞庭怀古。"]'),
('song-ci-212','临江仙','陈与义','宋','宋词','song-ci','临江仙','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','高咏楚词酬午日，天涯节序匆匆。',70,'宋词/ci.song.7000.json','["高咏楚词酬午日，天涯节序匆匆。", "榴花不似舞裙红。", "无人知此意，歌罢满帘风。", "万事一身伤老矣，戌葵凝笑墙东。", "酒杯深浅去年同。", "试浇桥下水，今夕到湘中。"]'),
('song-ci-213','虞美人','陈与义','宋','宋词','song-ci','虞美人','[]','张帆欲去仍搔首。',66,'宋词/ci.song.7000.json','["张帆欲去仍搔首。", "更醉君家酒。", "吟诗日日待春风。", "及至桃花开后、却匆匆。", "歌声频为行人咽。", "记著尊前雪。", "明朝酒醒大江流。", "满载一船离恨、向衡州。"]'),
('song-ci-214','点绛唇','陈与义','宋','宋词','song-ci','点绛唇','[]','寒食今年，紫阳山下蛮江左。',50,'宋词/ci.song.7000.json','["寒食今年，紫阳山下蛮江左。", "竹篱烟锁。", "何处求新火。", "不解乡音，只怕人嫌我。", "愁无那。", "短歌谁和。", "风动梨花朵。"]'),
('song-ci-215','虞美人','陈与义','宋','宋词','song-ci','虞美人','[]','超然堂上闲宾主。',66,'宋词/ci.song.7000.json','["超然堂上闲宾主。", "不受人间暑。", "冰盘围坐此州无。", "却有一瓶和露、玉芙蕖。", "亭亭风骨凉生牖。", "消尽尊中酒。", "酒阑明月转城西。", "照见纱巾藜杖、带香归。"]'),
('song-ci-216','渔家傲','陈与义','宋','宋词','song-ci','渔家傲','[]','今日山头云欲举。',72,'宋词/ci.song.7000.json','["今日山头云欲举。", "青蛟素凤移时舞。", "行到石桥闻细雨。", "听还住。", "风吹却过溪西去。", "我欲寻诗宽久旅。", "桃花落尽春无所。", "渺渺篮舆穿翠楚。", "悠然处。", "高林忽送黄鹂语。"]'),
('song-ci-217','虞美人','陈与义','宋','宋词','song-ci','虞美人','[]','扁舟三日秋塘路。',66,'宋词/ci.song.7000.json','["扁舟三日秋塘路。", "平度荷花去。", "病夫因病得来游。", "更值满川微雨、洗新秋。", "去年长恨拿舟晚。", "空见残荷满。", "今年何以报君恩。", "一路繁花相送、过青墩。"]'),
('song-ci-218','浣溪沙','陈与义','宋','宋词','song-ci','浣溪沙','[]','送了栖鸦复暮钟。',48,'宋词/ci.song.7000.json','["送了栖鸦复暮钟。", "栏干生影曲屏东。", "卧看孤鹤驾天风。", "起舞一尊明月下，秋空如水酒如空。", "谪仙已去与谁同。"]'),
('song-ci-219','玉楼春','陈与义','宋','宋词','song-ci','玉楼春','[]','山人本合居岩岭。',64,'宋词/ci.song.7000.json','["山人本合居岩岭。", "聊问支郎分半境。", "残年藜杖与纶巾，八尺庭中时弄影。", "呼儿汲水添茶鼎。", "甘胜吴山山下井。", "一瓯清露一炉云，偏觉平生今日永。"]'),
('song-ci-220','清平乐','陈与义','宋','宋词','song-ci','清平乐','[]','黄衫相倚。',54,'宋词/ci.song.7000.json','["黄衫相倚。", "翠葆层层底。", "八月江南风日美。", "弄影山腰水尾。", "楚人未识孤妍。", "离骚遗恨千年。", "无住庵中新事，一枝唤起幽禅。"]'),
('song-ci-221','定风波','陈与义','宋','宋词','song-ci','定风波','[]','九日登临有故常。',73,'宋词/ci.song.7000.json','["九日登临有故常。", "随晴随雨一传觞。", "多病题诗无好句。", "孤负。", "黄花今日十分黄。", "记得眉山文翰老。", "曾道。", "四时佳节是重阳。", "江海满前怀古意。", "谁会。", "阑干三抚独凄凉。"]'),
('song-ci-222','菩萨蛮','陈与义','宋','宋词','song-ci','菩萨蛮','[]','南轩面对芙蓉浦。',52,'宋词/ci.song.7000.json','["南轩面对芙蓉浦。", "宜风宜月还宜雨。", "红少绿多时。", "帘前光景奇。", "绳床乌木几。", "尽日繁香里。", "睡起一篇新。", "与花为主人。"]'),
('song-ci-223','南柯子・南歌子','陈与义','宋','宋词','song-ci','南柯子・南歌子','[]','矫矫千年鹤，茫茫万里风。',62,'宋词/ci.song.7000.json','["矫矫千年鹤，茫茫万里风。", "阑干三面看秋空。", "背插浮屠千尺、冷烟中。", "林坞村村暗，溪流处处通。", "此间何似玉霄峰。", "遥望蓬莱依约、晚云东。"]'),
('song-ci-224','临江仙','陈与义','宋','宋词','song-ci','临江仙','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','忆昔午桥桥上饮，坐中多是豪英。',70,'宋词/ci.song.7000.json','["忆昔午桥桥上饮，坐中多是豪英。", "长沟流月去无声。", "杏花疏影里，吹笛到天明。", "二十馀年如一梦，此身虽在堪惊。", "闲登小阁看新晴。", "古今多少事，渔唱起三更。"]'),
('song-ci-225','临江仙','杜大中妾','宋','宋词','song-ci','临江仙','[]','彩凤随鸦。',5,'宋词/ci.song.7000.json','["彩凤随鸦。"]'),
('song-ci-226','临江仙','刘彤','宋','宋词','song-ci','临江仙','[]','千里长安名利客，轻离轻散寻常。',70,'宋词/ci.song.7000.json','["千里长安名利客，轻离轻散寻常。", "难禁三月好风光。", "满阶芳草绿，一片杏花香。", "记得年时临上马，看人眼泪汪汪。", "如今不忍更思量。", "恨无千日酒，空断九回肠。"]'),
('song-ci-227','满庭芳','僧儿','宋','宋词','song-ci','满庭芳','[]','团菊苞金，丛兰减翠，画成秋暮风烟。',118,'宋词/ci.song.7000.json','["团菊苞金，丛兰减翠，画成秋暮风烟。", "使君归去，千里倍潸然。", "两度朱幡雁水，全胜得、陶侃当年。", "如何见，一时盛事，都在送行篇。", "愁烦。", "梳洗懒，寻思陪宴，把月湖边。", "有多少、风流往事萦牵。", "闻道霓旌羽驾，看看是、玉局神仙。", "应相许，冲云破雾，一到洞中天。"]'),
('song-ci-228','满江红','胡仔','宋','宋词','song-ci','满江红','[]','泛宅浮家，何处好、苕溪清境。',112,'宋词/ci.song.7000.json','["泛宅浮家，何处好、苕溪清境。", "占云山万叠，烟波千顷。", "茶灶笔床浑不用，雪蓑月笛偏相称。", "争不教、二纪赋归来，甘幽屏。", "红尘事，谁能省。", "青霞志，方高引。", "任家风舴艋，生涯笭箸。", "三尺鲈鱼真好脍，一瓢春酒宜闲饮。", "问此时、怀抱向谁论，惟箕颍。"]'),
('song-ci-229','水龙吟','胡仔','宋','宋词','song-ci','水龙吟','[]','梦寒绡帐春风晓，檀枕半堆香髻。',127,'宋词/ci.song.7000.json','["梦寒绡帐春风晓，檀枕半堆香髻。", "辘轳初转，阑干鸣玉，咿哑惊起。", "眠鸭凝烟，舞鸾翻镜，影开秋水。", "解低鬟试整，牙床对立，香丝乱、云撒地。", "纤手犀梳落处，腻无声、重盘鸦翠。", "兰膏匀渍，冷光欲溜，鸾钗易坠。", "年少偏娇，髻多无力，恼人风味。", "理云裾下阶，含情不语，笑折花枝戏。"]'),
('song-ci-230','好事近','王昂','宋','宋词','song-ci','好事近','[]','喜气拥朱门，光动绮罗香陌。',53,'宋词/ci.song.7000.json','["喜气拥朱门，光动绮罗香陌。", "行到紫微花下，悟身非凡客。", "不须脂粉涴天真，嫌怕太红白。", "留取黛眉浅处，画章台春色。"]'),
('song-ci-231','贺新郎','张元干','宋','宋词','song-ci','贺新郎','[]','曳杖危楼去。',142,'宋词/ci.song.7000.json','["曳杖危楼去。", "斗垂天、沧波万顷，月流烟渚。", "扫尽浮云风不定，未放扁舟夜渡。", "宿燕落、寒芦深处。", "怅望关河空吊影，正人间、鼻息鸣鼍鼓。", "谁伴我，醉中舞。", "十年一梦扬州路。", "倚高寒、愁生故国，气吞骄虏。", "要斩楼兰三尺剑，遗恨琵琶旧语。", "谩暗涩、铜华尘土。", "唤取谪仙平章看，过苕溪、尚许垂纶否。", "风浩荡，欲飞举。"]'),
('song-ci-232','贺新郎','张元干','宋','宋词','song-ci','贺新郎','[]','梦绕神州路。',142,'宋词/ci.song.7000.json','["梦绕神州路。", "怅秋风、连营画角，故宫离黍。", "底事昆仑倾砥柱。", "九地黄流乱注。", "聚万落、千村狐兔。", "天意从来高难问，况人情、老易悲如许。", "更南浦，送君去。", "凉生岸柳催残暑。", "耿斜河、疏星淡月，断云微度。", "万里江山知何处。", "回首对床夜语。", "雁不到、书成谁与。", "目尽青天怀今古，肯儿曹、恩怨相尔汝。", "举大白，听金缕。"]'),
('song-ci-233','满江红','张元干','宋','宋词','song-ci','满江红','[]','春水迷天，桃花浪、几番风恶。',115,'宋词/ci.song.7000.json','["春水迷天，桃花浪、几番风恶。", "云乍起、远山遮尽，晚风还作。", "绿卷芳洲生杜若。", "数帆带雨烟中落。", "傍向来、沙觜共停桡，伤飘泊。", "寒犹在，衾偏薄。", "肠欲断，愁难著。", "倚篷窗无寐，引杯孤酌。", "寒食清明都过却。", "最怜轻负年时约。", "想小楼、终日望归舟，人如削。"]'),
('song-ci-234','兰陵王','张元干','宋','宋词','song-ci','兰陵王','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','卷朱箔。',159,'宋词/ci.song.7000.json','["卷朱箔。", "朝雨轻阴乍阁。", "阑干外，烟柳弄晴，芳草侵阶映红药。", "东风妒花恶。", "吹落。", "梢头嫩萼。", "屏山掩，沈水倦熏，中酒心情怕杯勺。", "寻思旧京洛。", "正年少疏狂，歌笑迷著。", "障泥油壁催梳掠。", "曾驰道同载，上林携手，灯夜初过早共约。", "又争信漂泊。", "寂寞。", "念行乐。", "甚粉淡衣襟，音断弦索。", "琼枝璧月春如昨。", "怅别后华表，那回双鹤。", "相思除是，向醉里、暂忘却。"]'),
('song-ci-235','兰陵王','张元干','宋','宋词','song-ci','兰陵王','[]','绮霞散。',158,'宋词/ci.song.7000.json','["绮霞散。", "空碧留晴向晚。", "东风里，天气困人，时节秋千闭深院。", "帘旌翠波飐。", "窗影残红一线。", "春光巧，花脸柳腰，勾引芳菲闹莺燕。", "闲愁费消遣。", "想娥绿轻晕，鸾鉴新怨。", "单衣欲试寒犹浅。", "羞衾凤空展，塞鸿难托，谁问潜宽旧带眼。", "念人似天远。", "迷恋。", "画堂宴。", "看最乐王孙，浓艳争劝。", "兰膏宝篆春宵短。", "拥檀板底唱，玉杯重暖。", "众中先醉，谩倚栏、早梦见。"]'),
('song-ci-236','念奴娇','张元干','宋','宋词','song-ci','念奴娇','[]','江天雨霁，正露荷擎翠，风槐摇绿。',120,'宋词/ci.song.7000.json','["江天雨霁，正露荷擎翠，风槐摇绿。", "试问秦楼今夜里，愁到阑干几曲。", "笑拈黄花，重题红叶，无奈归期促。", "暮云千里，桂花初绽寒玉。", "有谁伴我凄凉，除非分付与，杯中醽醁。", "水本无情山又远，回首烟波云木。", "梦绕西园，魂飞南浦，自古情难足。", "旧游何处，落霞空映孤鹜。"]'),
('song-ci-237','念奴娇','张元干','宋','宋词','song-ci','念奴娇','[]','蕊香深处，逢上巳、生怕花飞红雨。',121,'宋词/ci.song.7000.json','["蕊香深处，逢上巳、生怕花飞红雨。", "万点胭脂遮翠袖，谁识黄昏凝伫。", "烧烛呈妆，传杯绕槛，莫放春归去。", "垂丝无语，见人浑似羞妒。", "修禊当日兰亭，群贤弦管里，英姿如许。", "宝靥罗衣，应未有、许多阳台神女。", "气涌三山，醉听五鼓，休更分今古。", "壶中天地，大家著意留住。"]'),
('song-ci-238','念奴娇','张元干','宋','宋词','song-ci','念奴娇','[]','吴松初冷，记垂虹南望，残日西沈。',120,'宋词/ci.song.7000.json','["吴松初冷，记垂虹南望，残日西沈。", "秋入青冥三万顷，蟾影吞尽湖阴。", "玉斧为谁，冰轮如许，宫阙想寒深。", "人间奇观，古今豪士悲吟。", "苍弁丹颊仙翁，淮山风露底，曾赋幽寻。", "老去专城仍好客，时拥歌吹登临。", "坐揖龙江，举杯相属，桂子落波心。", "一声猿啸，醉来虚籁千林。"]'),
('song-ci-239','念奴娇','张元干','宋','宋词','song-ci','念奴娇','[]','秋风万里，湛银潢清影，冰轮寒色。',120,'宋词/ci.song.7000.json','["秋风万里，湛银潢清影，冰轮寒色。", "八月灵槎乘兴去，织女机边为客。", "山拥鸡林，江澄鸭绿，四顾沧溟窄。", "醉来横吹，数声悲愤谁测。", "飘荡贝阙珠宫，群龙惊睡起，冯夷波激。", "云气苍茫吟啸处，龟吼鲸奔天黑。", "回首当时，蓬莱方丈，好个归消息。", "而今图画，谩教千古传得。"]'),
('song-ci-240','念奴娇','张元干','宋','宋词','song-ci','念奴娇','[]','寒绡素壁，露华浓、群玉峰峦如洗。',120,'宋词/ci.song.7000.json','["寒绡素壁，露华浓、群玉峰峦如洗。", "明镜池开秋水净，冷浸一天空翠。", "荷芰波生，菰蒲风动，惊起鱼龙戏。", "山河影里，十分光照人世。", "谁似老子痴顽，胡床敧坐，自引壶觞醉。", "醉里悲歌歌未彻，屋角乌飞星坠。", "对影三人，停杯一问，谁解骑鲸意。", "玉京何处，翠楼空锁十二。"]'),
('song-ci-241','念奴娇','张元干','宋','宋词','song-ci','念奴娇','[]','垂虹望极，扫太虚纤翳，明河翻雪。',120,'宋词/ci.song.7000.json','["垂虹望极，扫太虚纤翳，明河翻雪。", "一碧天光波万顷，涌出广寒宫阙。", "好事浮家，不辞百里，俱载如花颊。", "琴高双鲤，鼎来同醉孤绝。", "浩荡今夕风烟，人间天上，别似寻常月。", "陶冶三高千古恨，赏我中秋清节。", "八十仙翁，雅宜图画，写取横江楫。", "平生奇观，梦回犹竦毛发。"]'),
('song-ci-242','石州慢','张元干','宋','宋词','song-ci','石州慢','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','寒水依痕，春意渐回，沙际烟阔。',123,'宋词/ci.song.7000.json','["寒水依痕，春意渐回，沙际烟阔。", "溪梅晴照生香，冷芯数枝争发。", "天涯旧恨，试看几许消魂，长亭门外山重叠。", "不尽眼中青，是愁来时节。", "情切。", "画楼深闭，想见东风，暗销肌雪。", "辜负枕前云雨，尊前花月。", "心期切处，更有多少凄凉，殷勤留与归时说。", "到得却相逢，恰经年离别。"]'),
('song-ci-243','石州慢','张元干','宋','宋词','song-ci','石州慢','["\u957f\u6c5f"]','雨急云飞，惊散暮鸦，微弄凉月。',123,'宋词/ci.song.7000.json','["雨急云飞，惊散暮鸦，微弄凉月。", "谁家疏柳低迷，几点流萤明灭。", "夜帆风使，满湖烟水苍茫，菰蒲零乱秋声咽。", "梦断酒醒时，倚危樯清绝。", "心折。", "长庚光怒，群盗纵横，逆胡猖獗。", "欲挽天河，一洗中原膏血。", "两宫何处，塞垣只隔长江，唾壶空击悲歌缺。", "万里想龙沙，泣孤臣吴越。"]'),
('song-ci-244','永遇乐','张元干','宋','宋词','song-ci','永遇乐','[]','月仄金盆，江萦罗带，凉飙天际。',128,'宋词/ci.song.7000.json','["月仄金盆，江萦罗带，凉飙天际。", "摩诘丹青，营丘平远，一望穷千里。", "白鸥盟在，黄粱梦破，投老此心如水。", "耿无眠、披衣顾影，乍闻绕阶络纬。", "百年倦客，三生习气，今古到头谁是。", "夜色苍茫，浮云灭没，举世方熟寐。", "谁人著眼，放神八极，逸想寄尘寰外。", "独凭栏、鸡鸣日上，海山雾起。"]'),
('song-ci-245','永遇乐','张元干','宋','宋词','song-ci','永遇乐','[]','飞观横空，众山绕甸，江面相照。',128,'宋词/ci.song.7000.json','["飞观横空，众山绕甸，江面相照。", "曲槛披风，虚檐挂月，据尽登临要。", "有时巾屦，访公良夜，坐我半天林杪。", "揽浮丘、飘飘衣袂，相与似游蓬岛。", "主人胜度，文章英妙，合住北扉西沼。", "何事十年，风洒露沐，不厌江山好。", "曲屏端有，吹箫人在，同倚暮云清晓。", "乘除了、人间宠辱，付之一笑。"]'),
('song-ci-246','八声甘州','张元干','宋','宋词','song-ci','八声甘州','[]','倚凌空飞观，展营丘卧轴恍移时。',118,'宋词/ci.song.7000.json','["倚凌空飞观，展营丘卧轴恍移时。", "渐微云点缀，参横斗转，野阔天垂。", "草树萦回岛屿，杳霭数峰低。", "共此一尊月，顾影为谁。", "俯仰乾坤今古，正嫩凉生处，浓露初扉。", "据胡床残夜，唯我与公知。", "念老去、风流未减，见向来、人物几兴衰。", "身长健，何妨游戏，莫问栖迟。"]'),
('song-ci-247','八声甘州','张元干','宋','宋词','song-ci','八声甘州','["\u897f\u6e56"]','记当年共饮，醉画船、摇碧罥花钗。',119,'宋词/ci.song.7000.json','["记当年共饮，醉画船、摇碧罥花钗。", "问苍颜华发，烟蓑雨笠，何事重来。", "看尽人情物态，冷眼只堪咍。", "赖有西湖在，洗我尘埃。", "夜久波光山色，间澹妆浓抹，冰鉴云开。", "更潮头千丈，江海两崔嵬。", "晓凉生、荷香扑面，洒天边、风露逼襟怀。", "谁同赏，通宵无寐，斜月低回。"]'),
('song-ci-248','水调歌头','张元干','宋','宋词','song-ci','水调歌头','[]','落景下青嶂，高浪卷沧洲。',114,'宋词/ci.song.7000.json','["落景下青嶂，高浪卷沧洲。", "平生颇惯，江海掀舞木兰舟。", "百二山河空壮。", "底事中原尘涨。", "丧乱几时休。", "泽畔行吟处，天地一沙鸥。", "想元龙，犹高卧，百尺楼。", "林风酹酒，堪笑淡话觅封侯。", "老去英雄不见。", "惟与渔樵为伴。", "回首得无忧。", "莫道三伏热，便是五湖秋。"]'),
('song-ci-249','水调歌头','张元干','宋','宋词','song-ci','水调歌头','[]','闰馀有何好，一岁两中秋。',114,'宋词/ci.song.7000.json','["闰馀有何好，一岁两中秋。", "滕王高阁曾醉，月涌大江流。", "今夜钓龙台上，还似当时逢闰，佳句记英游。", "看山兼看月，登阁复登楼。", "别离久，今古恨，大刀头。", "老来长是清梦，宛在旧神州。", "遐想芗林风味，瓮里自倾春色，不用贳貂裘。", "笑我成何事，搔首谩私忧。"]'),
('song-ci-250','水调歌头','张元干','宋','宋词','song-ci','水调歌头','[]','缥缈九仙阁，壮观在人间。',114,'宋词/ci.song.7000.json','["缥缈九仙阁，壮观在人间。", "凉飙乍起，四围晴黛入阑干。", "已过中秋时候。", "便是菊花重九。", "为寿一尊欢。", "今古登高意，玉帐正清闲。", "引三巴，连五岭，控百蛮。", "元戎小队，旧游曾记并龙山。", "闽峤尤宽南顾。", "闻道天边玉露。", "持橐诏新颁。", "且拥笙歌醉，廊庙更徐还。"]'),
('song-ci-251','水调歌头','张元干','宋','宋词','song-ci','水调歌头','[]','平日几经过，重到更留连。',114,'宋词/ci.song.7000.json','["平日几经过，重到更留连。", "黄尘乌帽，觉来眼界忽醒然。", "坐见如云秋稼，莫问鸡虫得失，鸿鹄下翩翩。", "四海九洲大，何地著飞仙。", "吸湖光，吞蟾影，倚天圆。", "胸中万顷空旷，清夜炯无眠。", "要识世间闲处，自有尊前深趣，且唱钓鱼船。", "调鼎他年事，妙手看烹鲜。"]'),
('song-ci-252','水调歌头','张元干','宋','宋词','song-ci','水调歌头','[]','雨断翻惊浪，山瞑拥归云。',114,'宋词/ci.song.7000.json','["雨断翻惊浪，山瞑拥归云。", "麦秋天气，聊泛征棹泊江村。", "不羡腰间金印，却爱吾庐高枕，无事闭柴门。", "搔首烟波上，老去任乾坤。", "白纶巾，玉麈尾，一杯春。", "性灵陶冶，我辈犹要个中人。", "莫变姓名吴市，且向渔樵争席，与世共浮沈。", "目送飞鸿去，何用画麒麟。"]'),
('song-ci-253','水调歌头','张元干','宋','宋词','song-ci','水调歌头','[]','露下菱歌远，萤傍藕花流。',114,'宋词/ci.song.7000.json','["露下菱歌远，萤傍藕花流。", "临溪堂上，望中依旧柳边洲。", "晚暑冰肌沾汗，新浴香绵扑粉，湘簟月华浮。", "长记开朱户，不寐待归舟。", "恍重来，思往事，搅离愁。", "天涯何处，未应容易此身休。", "莫问吴霜点鬓，细与蛮笺封恨，相见转绸缪。", "云雨阳台梦，河汉鹊桥秋。"]'),
('song-ci-254','水调歌头','张元干','宋','宋词','song-ci','水调歌头','[]','万里冰轮满，千丈玉盘浮。',114,'宋词/ci.song.7000.json','["万里冰轮满，千丈玉盘浮。", "广寒宫殿，西望湖海冷光流。", "扫尽长空纤翳，散乱疏林清影，风露迫人愁。", "徐步行歌去，危坐莫眠休。", "问孤蓬，缘底事，苦淹留。", "倦游回首，向来云卧两星周。", "此夜此生长好，明月明年何处，归兴在南州。", "老境一伧父，异县四中秋。"]'),
('song-ci-255','水调歌头','张元干','宋','宋词','song-ci','水调歌头','[]','袖手看飞雪，高卧过残冬。',114,'宋词/ci.song.7000.json','["袖手看飞雪，高卧过残冬。", "飘然底事春到，先我逐孤鸿。", "挟取笔端风雨，快写胸中丘壑，不肯下樊笼。", "大笑了今古，乘兴便西东。", "一尊酒，知何处，又相逢。", "奴星结柳，与君同送五家穷。", "好是橘封千户，正恐楼高百尺，湖海有元龙。", "目光在牛背，马耳射东风。"]'),
('song-ci-256','水调歌头','张元干','宋','宋词','song-ci','水调歌头','["\u897f\u6e56"]','放浪形骸外，憔悴山泽癯。',114,'宋词/ci.song.7000.json','["放浪形骸外，憔悴山泽癯。", "倒冠落佩，此心不待白髭须。", "聊复脱身鹓鹭，未暇先寻水竹，矫首汉庭疏。", "长夏啖丹荔，两纪傲闲居。", "忽风飘，连雨打，向西湖。", "藕花深处，尚能同载曲生无。", "听子谈天舌本，浇我书空胸次，醉卧踏冰壶。", "毕竟凌烟像，何似辋川图。"]'),
('song-ci-257','水调歌头','张元干','宋','宋词','song-ci','水调歌头','[]','柱策松江上，举酒酹三高。',114,'宋词/ci.song.7000.json','["柱策松江上，举酒酹三高。", "此生飘荡，往来身世两徒劳。", "长羡五湖烟艇，好是秋风鲈脍，笠泽久蓬蒿。", "想像英灵在，千古傲云涛。", "俯沧浪，舌空旷，恍神交。", "解衣盘礴，政须一笑属吾曹。", "洗尽人间尘土，扫去胸中冰炭，痛饮读离骚。", "纵有垂天翼，何用钓连鳌。"]'),
('song-ci-258','水调歌头','张元干','宋','宋词','song-ci','水调歌头','[]','今夕定何夕，秋垂满东瓯。',114,'宋词/ci.song.7000.json','["今夕定何夕，秋垂满东瓯。", "悲凉怀抱，何事还倍去年愁。", "万里碧空如洗，寒浸十分明月，帘卷玉波流。", "非是经年别，一岁两中秋。", "坐中庭，风露下，冷飕飕。", "素娥无语相对，尊酒且迟留。", "琴罢不堪幽怨，遥想三山影外，人倚夜深楼。", "矫首望霄汉，云海路悠悠。"]'),
('song-ci-259','水调歌头','张元干','宋','宋词','song-ci','水调歌头','["\u5cb3\u9633\u697c"]','最乐贤王子，今岁好中秋。',114,'宋词/ci.song.7000.json','["最乐贤王子，今岁好中秋。", "夜深珠履，举杯相属尽名流。", "宿雨乍开银汉，洗出玉蟾秋色，人在广寒游。", "浩荡山河影，偏照岳阳楼。", "露华浓，君恩重，判扶头。", "霓旌星节，已随丝管下皇州。", "满座烛光花礼，笑罥乌巾同醉，谁问负薪裘。", "月转檐牙晓，高枕更无忧。"]'),
('song-ci-260','水调歌头','张元干','宋','宋词','song-ci','水调歌头','[]','举手钓鳌客，削迹种瓜侯。',114,'宋词/ci.song.7000.json','["举手钓鳌客，削迹种瓜侯。", "重来吴会三伏，行见五湖秋。", "耳畔风波摇荡，身外功名飘忽，何路射旄头。", "孤负男儿志，怅望故园愁。", "梦中原，挥老泪，遍南州。", "元龙湖海豪气，百尺卧高楼。", "短发霜黏两鬓，清夜盆倾一雨，喜听瓦鸣沟。", "犹有壮心在，付与百川流。"]'),
('song-ci-261','水调歌头','张元干','宋','宋词','song-ci','水调歌头','[]','戎虏乱中夏，星历一周天。',114,'宋词/ci.song.7000.json','["戎虏乱中夏，星历一周天。", "干戈未定，悲咤河洛尚腥膻。", "万里两宫无路。", "政仰君王神武。", "愿数中兴年。", "吾道尊洙泗，何暇议伊川。", "吕公子，三世相，在凌烟。", "诗名独步，焉用儿辈更毛笺。", "好去承明谠论。", "照映金狨带稳。", "恩与荔枝偏。", "回首东山路，池阁醉双莲。"]'),
('song-ci-262','风流子','张元干','宋','宋词','song-ci','风流子','[]','飞观插雕粱。',136,'宋词/ci.song.7000.json','["飞观插雕粱。", "凭虚起、缥缈五云乡。", "对山滴翠岚，两眉浓黛，水分双派，满眼波光。", "曲栏干外，汀烟轻冉冉，莎草细茫茫。", "无数钓舟，最宜烟雨，有如图画，浑似潇湘。", "使君行乐处，秦筝弄哀怨，云鬓分行。", "心醉一缸春色，满座疑香。", "有天涯倦客，尊前回首，听彻伊川，恼损柔肠。", "不似碧潭双剑，犹解相将。"]'),
('song-ci-263','鱼游春水','张元干','宋','宋词','song-ci','鱼游春水','[]','芳洲生苹芷。',105,'宋词/ci.song.7000.json','["芳洲生苹芷。", "宿雨收晴浮暖翠。", "烟光如洗，几片花飞点泪。", "清镜空馀白发添，新恨谁传红绫寄。", "溪涨岸痕，浪吞沙尾。", "老去情怀易醉。", "十二栏干慵遍倚。", "双凫人惯风流，功名万里。", "梦想浓妆碧云边，目断归帆夕阳里。", "何时送客，更临春水。"]'),
('song-ci-264','宝鼎现','张元干','宋','宋词','song-ci','宝鼎现','[]','山庄图画，锦囊吟咏，胸中丘壑。',193,'宋词/ci.song.7000.json','["山庄图画，锦囊吟咏，胸中丘壑。", "年少日、如虹豪气，吐凤词华浑忘却。", "便袖手、向岩前溪畔，种满烟梢雾箨。", "想别墅平泉，当时草木，风流如昨。", "瘦藤闲倚看锄药。", "双芒鞋、雨后常著。", "目送处、飞鸿灭没，谁问蓬蒿争燕雀。", "乍霁月、望松云南渡，短艇敧沙夜泊。", "正万里清冥，千林虚籁，从渠缯缴。", "携幼尚有筠丁，谁会得、人生行乐。", "岸帻纶巾归去，深户相迷翠幕。", "恐未免、上凌烟阁。", "好在秋天鹗。", "念小山丛桂，今宵狂客，不胜杯勺。"]'),
('song-ci-265','祝英台近','张元干','宋','宋词','song-ci','祝英台近','[]','枕霞红，钗燕坠。',95,'宋词/ci.song.7000.json','["枕霞红，钗燕坠。", "花露殢云髻。", "粉淡香残，犹带宿酲睡。", "画檐红日三竿，慵窥鸾鉴，长是倚、春风无力。", "又经岁。", "玉腕条脱轻松，羞郎见憔悴。", "何事秋来，容易又分袂。", "可堪疏雨梧桐，空阶络纬，背人处、偷弹珠泪。"]'),
('song-ci-266','朝中措','张元干','宋','宋词','song-ci','朝中措','[]','花阴如坐木兰船。',57,'宋词/ci.song.7000.json','["花阴如坐木兰船。", "风露正娟娟。", "翠盖匝庭芳影，青蛟平地飞涎。", "春撩狂兴，香迷痛饮，中圣中贤。", "携取一枝同梦，从他五夜如年。"]'),
('song-ci-267','蝶恋花','张元干','宋','宋词','song-ci','蝶恋花','[]','窗暗窗明昏又晓。',70,'宋词/ci.song.7000.json','["窗暗窗明昏又晓。", "百岁光阴，老去难重少。", "四十归来犹赖早。", "浮名浮利都经了。", "时把青铜闲自照。", "华发苍颜，一任傍人笑。", "不会参禅并学道。", "但知心下无烦恼。"]'),
('song-ci-268','蝶恋花','张元干','宋','宋词','song-ci','蝶恋花','[]','燕去莺来春又到。',70,'宋词/ci.song.7000.json','["燕去莺来春又到。", "花落花开，几度池塘草。", "歌舞筵中人易老。", "闭门打坐安闲好。", "败意常多如意少。", "著甚来由，入闹寻烦恼。", "千古是非浑忘了。", "有时独自掀髯笑。"]'),
('song-ci-269','沁园春','张元干','宋','宋词','song-ci','沁园春','[]','神水华池，汞铅凝结，虎龙往来。',140,'宋词/ci.song.7000.json','["神水华池，汞铅凝结，虎龙往来。", "问子前午后，阳销阴长，自然炉鼎，何用安排。", "灵宝玄门，烟萝真境，三日庚生兑户开。", "泥丸透，尽周天火候，平步仙阶。", "蓬莱。", "直上瑶台。", "看海变桑田飞暮埃。", "念尘劳良苦，流光易度，明珠难得，白骨成堆。", "位极人臣，功高今古，总蹈危机吞祸胎。", "争知我，办青鞋布袜，雁荡天台。"]'),
('song-ci-270','沁园春','张元干','宋','宋词','song-ci','沁园春','[]','敧枕深轩，散帙虚堂，畏景屡移。',140,'宋词/ci.song.7000.json','["敧枕深轩，散帙虚堂，畏景屡移。", "渐披襟临水，搘床就月，莲香拂面，竹色侵衣。", "压玉为醪，折荷当盏，卧看银潢星四垂。", "人归后，任肌蝉自啸，宿鸟相依。", "痴儿。", "莫道危机。", "悟三十九年都尽非。", "任纡朱拖紫，围金佩玉，青钱流地，白璧如坻。", "富贵浮云，身名零露，事事无心归便归。", "秋风动，正吴松月冷，莼长鲈肥。"]'),
('song-ci-271','临江仙','张元干','宋','宋词','song-ci','临江仙','["\u897f\u6e56"]','玉立清标消晚暑，胸中一段冰壶。',70,'宋词/ci.song.7000.json','["玉立清标消晚暑，胸中一段冰壶。", "画船归去醉歌珠。", "微云收未尽，残月炯如初。", "鸳鹭行间催阔步，秋来乘兴凫趋。", "烦君为我问西湖。", "不知疏影畔，许我结茅无。"]'),
('song-ci-272','临江仙','张元干','宋','宋词','song-ci','临江仙','[]','莺唤屏山惊睡起，娇多须要郎扶。',70,'宋词/ci.song.7000.json','["莺唤屏山惊睡起，娇多须要郎扶。", "荼䕷斗帐罢熏炉。", "翠穿珠落索，香泛玉流苏。", "长记枕痕销醉色，日高犹倦妆梳。", "一枝春瘦想如初。", "梦迷芳草路，望断素鳞书。"]'),
('song-ci-273','临江仙','张元干','宋','宋词','song-ci','临江仙','[]','十日篱边犹袖手，天教冷地藏香。',70,'宋词/ci.song.7000.json','["十日篱边犹袖手，天教冷地藏香。", "王孙风味最难忘。", "逃禅留坐客，度曲出宫妆。", "判却为花今夜醉，大家且泛鹅黄。", "人心休更问炎凉。", "从渠簪发短，还我引杯长。"]'),
('song-ci-274','临江仙','张元干','宋','宋词','song-ci','临江仙','[]','露坐榕阴须痛饮，从渠叠鼓频催。',70,'宋词/ci.song.7000.json','["露坐榕阴须痛饮，从渠叠鼓频催。", "暮山新月两徘徊。", "离愁秋水远，醉眼晓帆开。", "泛宅浮家游戏去，流行坎止忘怀。", "江边鸥鹭莫相猜。", "上林消息好，鸿雁已归来。"]'),
('song-ci-275','醉落魄・一斛珠','张元干','宋','宋词','song-ci','醉落魄・一斛珠','[]','浮家泛宅。',67,'宋词/ci.song.7000.json','["浮家泛宅。", "旧游记霅溪踪迹。", "此生已是天涯隔。", "投老谁知，还作三吴客。", "故人怪我疏髯黑。", "醉来犹似丁年日。", "光阴未肯成虚掷。", "蜀魄声中，著处有春色。"]'),
('song-ci-276','醉落魄・一斛珠','张元干','宋','宋词','song-ci','醉落魄・一斛珠','[]','绿枝红萼。',67,'宋词/ci.song.7000.json','["绿枝红萼。", "江南芳信年年约。", "竹舆路转溪桥角。", "晴日烘香，的皪疏篱落。", "玉台粉面铅华薄。", "画堂长记深罗幕。", "惜花老去情犹著。", "客里惊春，生怕东风恶。"]'),
('song-ci-277','醉落魄・一斛珠','张元干','宋','宋词','song-ci','醉落魄・一斛珠','[]','一枝冰萼。',67,'宋词/ci.song.7000.json','["一枝冰萼。", "鬓云低度横波约。", "醉扶曾罥乌巾角。", "长是春来，肠断宝钗落。", "罗衣乍怯香风薄。", "夜深花困遮垂幕。", "不堪往事寻思著。", "休问尊前，客恶主人恶。"]'),
('song-ci-278','醉落魄・一斛珠','张元干','宋','宋词','song-ci','醉落魄・一斛珠','[]','云鸿影落。',67,'宋词/ci.song.7000.json','["云鸿影落。", "风吹小艇敧沙泊。", "津亭古木浓阴合。", "一枕滩声，客睡何曾著。", "天涯万里情怀恶。", "年华垂暮犹离索。", "佳人想见猜疑错。", "莫数归期，已负当时约。"]'),
('song-ci-279','南歌子','张元干','宋','宋词','song-ci','南歌子','[]','凉月今宵满，晴空万里宽。',62,'宋词/ci.song.7000.json','["凉月今宵满，晴空万里宽。", "素娥应念老夫闲。", "特地中秋著意、照人间。", "香雾云鬟湿，清辉玉臂寒。", "休教凝伫向更阑。", "飘下桂华闻早、大家看。"]'),
('song-ci-280','南歌子','张元干','宋','宋词','song-ci','南歌子','[]','远树留残雪，寒江照晚晴。',62,'宋词/ci.song.7000.json','["远树留残雪，寒江照晚晴。", "分明江上数峰青。", "倚槛旧愁新恨、一时生。", "春意来无际，归舟去有程。", "道人元自没心情。", "楚梦只因沈醉、等闲成。"]'),
('song-ci-281','南歌子','张元干','宋','宋词','song-ci','南歌子','[]','玉露团寒菊，秋风入败荷。',62,'宋词/ci.song.7000.json','["玉露团寒菊，秋风入败荷。", "缭墙南畔曲池涡。", "天迥遥岑倒影、落层波。", "月转檐牙短，更传漏箭多。", "醉来归去意如何。", "只为地偏心远、惯弦歌。"]'),
('song-ci-282','南歌子','张元干','宋','宋词','song-ci','南歌子','[]','桂魄分馀晕，檀香破紫心。',62,'宋词/ci.song.7000.json','["桂魄分馀晕，檀香破紫心。", "高鬟松绾鬓云侵。", "又被兰膏香染、色沈沈。", "指印纤纤粉，钗横隐隐金。", "更阑云雨凤帷深。", "长是枕前不见、殢人寻。"]'),
('song-ci-283','卜算子','张元干','宋','宋词','song-ci','卜算子','[]','的皪数枝斜，冰雪萦馀态。',52,'宋词/ci.song.7000.json','["的皪数枝斜，冰雪萦馀态。", "烛外尊前满眼春，风味年年在。", "老去惜花深，醉里愁多㬠。", "冷蕊孤芳底处愁，少个人人戴。"]'),
('song-ci-284','卜算子','张元干','宋','宋词','song-ci','卜算子','[]','凉气入熏笼，暗影敧花砌。',54,'宋词/ci.song.7000.json','["凉气入熏笼，暗影敧花砌。", "紫玉谁人三弄寒，细吹断、江梅意。", "花底湿春衣，隔坐风轻递。", "却笑笙箫缑岭人，明日偷垂泪。"]'),
('song-ci-285','卜算子','张元干','宋','宋词','song-ci','卜算子','[]','风露湿行云，沙水迷归艇。',52,'宋词/ci.song.7000.json','["风露湿行云，沙水迷归艇。", "卧看明河月满空，斗挂苍山顶。", "万古只青天，多事悲人境。", "起舞闻鸡酒未醒，潮落秋江冷。"]'),
('song-ci-286','卜算子','张元干','宋','宋词','song-ci','卜算子','[]','芳信着寒梢，影入花光画。',52,'宋词/ci.song.7000.json','["芳信着寒梢，影入花光画。", "玉立风前万里春，雪艳江天夜。", "谁折暗香来，故把新篘泻。", "记得偎人并照时，鬓乱斜枝惹。"]'),
('song-ci-287','浣溪沙','张元干','宋','宋词','song-ci','浣溪沙','[]','曲室明窗烛吐光。',48,'宋词/ci.song.7000.json','["曲室明窗烛吐光。", "瓦炉灰暖炷瓢香。", "夜阑茗碗间飞觞。", "坐稳蒲团凭棐几，熏馀纸帐掩梨床。", "个中风味更难忘。"]'),
('song-ci-288','浣溪沙','张元干','宋','宋词','song-ci','浣溪沙','[]','一枕秋风两处凉。',48,'宋词/ci.song.7000.json','["一枕秋风两处凉。", "雨声初歇漏声长。", "池塘零落藕花香。", "归梦等闲归燕去，断肠分付断云行。", "画屏今夜更思量。"]'),
('song-ci-289','浣溪沙','张元干','宋','宋词','song-ci','浣溪沙','[]','翡翠钗头缀玉虫。',48,'宋词/ci.song.7000.json','["翡翠钗头缀玉虫。", "秋蟾飘下广寒宫。", "数枝金粟露华浓。", "花底清歌生皓齿，烛边疏影映酥胸。", "恼人风味冷香中。"]'),
('song-ci-290','浣溪沙','张元干','宋','宋词','song-ci','浣溪沙','[]','燕掠风樯款款飞。',48,'宋词/ci.song.7000.json','["燕掠风樯款款飞。", "艳桃秾李闹长堤。", "骑鲸人去晓莺啼。", "可意湖山留我住，断肠烟水送君归。", "三春不是别离时。"]'),
('song-ci-291','浣溪沙','张元干','宋','宋词','song-ci','浣溪沙','[]','云气吞江卷夕阳。',48,'宋词/ci.song.7000.json','["云气吞江卷夕阳。", "白头波上电飞忙。", "奔雷惊雨溅胡床。", "玉节故人同壮观，锦囊公子更平章。", "榕阴归梦十分凉。"]'),
('song-ci-292','浣溪沙','张元干','宋','宋词','song-ci','浣溪沙','[]','山绕平湖波撼城。',48,'宋词/ci.song.7000.json','["山绕平湖波撼城。", "湖光倒影浸山青。", "水晶楼下欲三更。", "雾柳暗时云度月，露荷翻处水流萤。", "萧萧散发到天明。"]'),
('song-ci-293','浣溪沙','张元干','宋','宋词','song-ci','浣溪沙','[]','目送归州铁瓮城。',48,'宋词/ci.song.7000.json','["目送归州铁瓮城。", "隔江想见蜀山青。", "风前团扇仆频更。", "梦里有时身化鹤，人间无数草为萤。", "此时山月下楼明。"]'),
('song-ci-294','浣溪沙','张元干','宋','宋词','song-ci','浣溪沙','[]','月转花枝清影疏。',48,'宋词/ci.song.7000.json','["月转花枝清影疏。", "露华浓处滴真珠。", "天香遗恨罥花须。", "沐出乌云多态度，晕成娥绿费功夫。", "归时分付与妆梳。"]'),
('song-ci-295','浣溪沙','张元干','宋','宋词','song-ci','浣溪沙','[]','花气天然百和芬。',48,'宋词/ci.song.7000.json','["花气天然百和芬。", "仙风吹过海中春。", "龙涎沈水总销魂。", "清润巧萦金缕细，氤氲偏傍玉脂温。", "别来长是惜馀熏。"]'),
('song-ci-296','浣溪沙','张元干','宋','宋词','song-ci','浣溪沙','[]','萼绿华家萼绿春。',48,'宋词/ci.song.7000.json','["萼绿华家萼绿春。", "山瓶何处下青云。", "浓香气味已醺人。", "竹叶传杯惊老眼，松醪题赋倒纶巾。", "须防银字暖朱唇。"]'),
('song-ci-297','浣溪沙','张元干','宋','宋词','song-ci','浣溪沙','[]','花气蒸浓古鼎烟。',48,'宋词/ci.song.7000.json','["花气蒸浓古鼎烟。", "水沈春透露华鲜。", "心清无暇数龙涎。", "乞与病夫僧帐座，不妨公子醉茵眠。", "普熏三界扫腥膻。"]'),
('song-ci-298','浣溪沙','张元干','宋','宋词','song-ci','浣溪沙','[]','花气薰人百和香。',48,'宋词/ci.song.7000.json','["花气薰人百和香。", "少陵佳句是仙方。", "空教蜂蝶为花忙。", "和露摘来轻换骨，傍怀闻处恼回肠。", "去年时候入思量。"]'),
('song-ci-299','浣溪沙','张元干','宋','宋词','song-ci','浣溪沙','[]','残腊晴寒出众芳。',48,'宋词/ci.song.7000.json','["残腊晴寒出众芳。", "风流勾引破春光。", "年年长为此花忙。", "夜久莫教银烛灺，酒边何似玉台妆。", "冰肌温处觅馀香。"]'),
('song-ci-300','浣溪沙','张元干','宋','宋词','song-ci','浣溪沙','[]','棐几明窗乐未央。',48,'宋词/ci.song.7000.json','["棐几明窗乐未央。", "熏炉茗碗是家常。", "客来长揖对胡床。", "蟹眼汤深轻泛乳，龙涎灰暖细烘香。", "为君行草写秋阳。"]'),
('song-ci-301','浣溪沙','张元干','宋','宋词','song-ci','浣溪沙','[]','榕叶桄榔驿枕溪。',48,'宋词/ci.song.7000.json','["榕叶桄榔驿枕溪。", "海风吹断瘴云低。", "薄寒初觉到征衣。", "岁晚可堪归梦远，愁深偏恨得书稀。", "荒庭日脚又垂西。"]'),
('song-ci-302','柳梢青','张元干','宋','宋词','song-ci','柳梢青','[]','清山浮碧。',61,'宋词/ci.song.7000.json','["清山浮碧。", "细风丝雨，新愁如织。", "慵试春衫，不禁宿酒，天涯寒食。", "归期莫数芳辰，误几度、回廊夜色。", "入户飞花，隔帘双燕，有谁知得。"]'),
('song-ci-303','柳梢青','张元干','宋','宋词','song-ci','柳梢青','[]','小楼南陌。',61,'宋词/ci.song.7000.json','["小楼南陌。", "翠軿金勒，谁家春色。", "冷雨吹花，禁烟怯柳，伤心行客。", "少年百万呼卢，拥越女、吴姬共掷。", "被底香浓，尊前烛灭，如今消得。"]'),
('song-ci-304','醉花阴','张元干','宋','宋词','song-ci','醉花阴','[]','紫枢泽笏趋龙尾。',62,'宋词/ci.song.7000.json','["紫枢泽笏趋龙尾。", "平入钧衡位。", "春殿听宣麻，争喜登庸，何似今番喜。", "崑台宜有神仙裔。", "奕世貂蝉贵。", "玉砌长兰芽，好拥笙歌，长向花前醉。"]'),
('song-ci-305','醉花阴','张元干','宋','宋词','song-ci','醉花阴','[]','翠箔阴阴笼画阁。',62,'宋词/ci.song.7000.json','["翠箔阴阴笼画阁。", "昨夜东风恶。", "芳径满香泥，南陌东郊，惆怅妨行乐。", "伤春比似年时恶。", "潘鬓新来薄。", "何处不禁愁，雨滴花腮，和泪胭脂落。"]'),
('song-ci-306','长相思令・长相思','张元干','宋','宋词','song-ci','长相思令・长相思','[]','香暖帏。',44,'宋词/ci.song.7000.json','["香暖帏。", "玉暖肌。", "娇卧嗔人来睡迟。", "印残双黛眉。", "虫声低。", "漏声稀。", "惊枕初醒灯暗时。", "梦人归未归。"]'),
('song-ci-307','长相思令・长相思','张元干','宋','宋词','song-ci','长相思令・长相思','[]','花下愁。',44,'宋词/ci.song.7000.json','["花下愁。", "月下愁。", "花落月明人在楼。", "断肠春复秋。", "从他休。", "任他休。", "如今青鸾不自由。", "看看天尽头。"]'),
('song-ci-308','如梦令','张元干','宋','宋词','song-ci','如梦令','[]','雨洗青冥风露。',40,'宋词/ci.song.7000.json','["雨洗青冥风露。", "云外双星初度。", "乞巧夜楼空，月妒回廊私语。", "凝伫。", "凝伫。", "不似去年情绪。"]'),
('song-ci-309','如梦令','张元干','宋','宋词','song-ci','如梦令','[]','潮退江南晚渡。',40,'宋词/ci.song.7000.json','["潮退江南晚渡。", "山暗水西烟雨。", "天气十分凉，断送一年残暑。", "归去。", "归去。", "香雾曲屏深处。"]'),
('song-ci-310','如梦令','张元干','宋','宋词','song-ci','如梦令','["\u897f\u6e56"]','卧看西湖烟渚。',40,'宋词/ci.song.7000.json','["卧看西湖烟渚。", "绿盖红妆无数。", "帘卷曲栏风，拂面荷香吹雨。", "归去。", "归去。", "笑损花边鸥鹭。"]'),
('song-ci-311','春光好','张元干','宋','宋词','song-ci','春光好','[]','疏雨洗，细风吹。',50,'宋词/ci.song.7000.json','["疏雨洗，细风吹。", "淡黄时。", "不分小亭芳草绿，映檐低。", "楼下十二层梯。", "日长影里莺啼。", "倚遍阑干看尽柳，忆腰肢。"]'),
('song-ci-312','春光好','张元干','宋','宋词','song-ci','春光好','[]','吴绫窄，藕丝重。',51,'宋词/ci.song.7000.json','["吴绫窄，藕丝重。", "一钩红。", "翠被眠时常要人暖，著怀中。", "六幅裙窣轻风。", "见人遮尽行踪。", "正是踏青天气好，忆弓弓。"]'),
('song-ci-313','虞美人','张元干','宋','宋词','song-ci','虞美人','[]','开残桃李春方到。',66,'宋词/ci.song.7000.json','["开残桃李春方到。", "谁送东风早。", "杖藜幽径踏馀花。", "却对绿阴青子、问年华。", "迢迢云水横清浅。", "不遣愁眉展。", "数竿修竹自横斜。", "犹有小窗朱户、似侬家。"]'),
('song-ci-314','青玉案','张元干','宋','宋词','song-ci','青玉案','[]','华裾玉辔青丝鞚。',80,'宋词/ci.song.7000.json','["华裾玉辔青丝鞚。", "记年少、金吾从。", "花底朝回珠翠拥。", "晓钟初断，宿酲犹带，绿锁窗中梦。", "天涯相遇鞭鸾凤。", "老去堂成更情重。", "月转檐牙云绕栋。", "凉吹香雾，酒迷歌扇，春笋传杯送。"]'),
('song-ci-315','青玉案','张元干','宋','宋词','song-ci','青玉案','[]','王孙陌上春风鞚。',80,'宋词/ci.song.7000.json','["王孙陌上春风鞚。", "蕊珠宴、云軿从。", "归去笙歌常醉拥。", "蜡残花炬，月侵冰簟，惯作凉堂梦。", "玉人劝客钗斜凤。", "条脱擎杯腕嫌重。", "燕子入帘飞画栋。", "雨馀深院，漏催清夜，更轧秦筝送。"]'),
('song-ci-316','青玉案','张元干','宋','宋词','song-ci','青玉案','[]','花王独占春风远。',80,'宋词/ci.song.7000.json','["花王独占春风远。", "看百卉、芳菲遍。", "五福长随今日宴。", "粉光生艳，宝香飘雾，方响流苏颤。", "寿祺堂上修篁畔。", "乳燕双双贺新院。", "玉斝明年何处劝。", "旌幢满路，貂蝉宜面，归觐黄金殿。"]'),
('song-ci-317','青玉案','张元干','宋','宋词','song-ci','青玉案','[]','水芝香远摇红影。',80,'宋词/ci.song.7000.json','["水芝香远摇红影。", "泛瑞霭、横山顶。", "缥缈笙歌云不定。", "玉钩斜挂，素蟾初满，醉惬浮瓜冷。", "庭兰戏彩传金鼎。", "小袖青衫更辉映。", "谁道筠溪归计近。", "秋风催去，凤池难老，长把中书印。"]'),
('song-ci-318','青玉案','张元干','宋','宋词','song-ci','青玉案','[]','银潢露洗冰轮皎。',80,'宋词/ci.song.7000.json','["银潢露洗冰轮皎。", "谪仙下、蓬莱岛。", "帘卷横山珠翠绕。", "生朝香雾，玳筵丝管，长醉壶天晓。", "金銮夜锁麻新草。", "入辅明光拜元老。", "看取明年人总道。", "中兴贤相，太平时世，分外风光好。"]'),
('song-ci-319','青玉案','张元干','宋','宋词','song-ci','青玉案','[]','月华冷沁花梢露。',80,'宋词/ci.song.7000.json','["月华冷沁花梢露。", "芳意恋、香肌住。", "心字龙涎饶济楚。", "素馨风味，碎琼流品，别有天然处。", "围炉屈曲宜深炷。", "留取春光向朱户。", "绿绮声中谁暗许。", "小窗归去，梦回犹记，金鼎分云缕。"]'),
('song-ci-320','青玉案','张元干','宋','宋词','song-ci','青玉案','[]','平生百绕垂虹路。',80,'宋词/ci.song.7000.json','["平生百绕垂虹路。", "看万顷、翻云去。", "山澹夕晖帆影度。", "菱歌风断，袜罗尘散，总是关情处。", "少年陈迹今迟暮。", "走笔犹能醉时句。", "花底自成心暗许。", "旧家春事，觉来客恨，分付疏篷雨。"]'),
('song-ci-321','点绛唇','张元干','宋','宋词','song-ci','点绛唇','[]','山暗秋云，暝鸦接翅啼榕树。',50,'宋词/ci.song.7000.json','["山暗秋云，暝鸦接翅啼榕树。", "故人何处。", "一夜溪亭雨。", "梦入新凉，只道消残暑。", "还知否。", "燕将雏去。", "又是流年度。"]'),
('song-ci-322','点绛唇','张元干','宋','宋词','song-ci','点绛唇','[]','水驿凝霜，夜帆风驶潮生晓。',50,'宋词/ci.song.7000.json','["水驿凝霜，夜帆风驶潮生晓。", "酒醒寒悄。", "枕底波声小。", "好去归舟，有个人风调。", "君行了。", "此欢应少。", "索共梅花笑。"]'),
('song-ci-323','点绛唇','张元干','宋','宋词','song-ci','点绛唇','[]','春晓轻雷，采苹洲上清明雨。',50,'宋词/ci.song.7000.json','["春晓轻雷，采苹洲上清明雨。", "乱云遮树。", "暗澹江村路。", "今夜归舟，绿润红香处。", "遥山暮。", "画楼何许。", "唤取潮回去。"]'),
('song-ci-324','点绛唇','张元干','宋','宋词','song-ci','点绛唇','[]','画阁深围，暖红光里芳林影。',50,'宋词/ci.song.7000.json','["画阁深围，暖红光里芳林影。", "暗香成阵。", "上下花相映。", "倒挂疏枝，月落参横冷。", "休装景。", "要人酒醒。", "除是花枝并。"]'),
('song-ci-325','点绛唇','张元干','宋','宋词','song-ci','点绛唇','[]','嵩洛云烟，间生真相耆英裔。',50,'宋词/ci.song.7000.json','["嵩洛云烟，间生真相耆英裔。", "要知鲐背。", "难老中和气。", "报道玉堂，已草调元制。", "华夷喜。", "绣裳貂珥。", "便向东山起。"]'),
('song-ci-326','点绛唇','张元干','宋','宋词','song-ci','点绛唇','[]','清夜沈沈，暗蛩啼处檐花落。',50,'宋词/ci.song.7000.json','["清夜沈沈，暗蛩啼处檐花落。", "乍凉帘幕。", "香绕屏山角。", "堪恨归鸿，情似秋云薄。", "书难托。", "尽交寂寞。", "忘了前时约。"]'),
('song-ci-327','点绛唇','张元干','宋','宋词','song-ci','点绛唇','[]','醉泛吴松，小舟谁怕东风大。',50,'宋词/ci.song.7000.json','["醉泛吴松，小舟谁怕东风大。", "旧时经过。", "曾向垂虹卧。", "月淡霜天，今夜空清坐。", "还知麽。", "满斟高和。", "只有君知我。"]'),
('song-ci-328','点绛唇','张元干','宋','宋词','song-ci','点绛唇','[]','减塑冠儿，宝钗金缕双緌结。',50,'宋词/ci.song.7000.json','["减塑冠儿，宝钗金缕双緌结。", "怎教宁帖。", "眼恼儿里劣。", "韵底人人，天与多磨折。", "休分说。", "放灯时节。", "闲了花和月。"]'),
('song-ci-329','点绛唇','张元干','宋','宋词','song-ci','点绛唇','[]','水鹢风帆，两眉只解相思皱。',50,'宋词/ci.song.7000.json','["水鹢风帆，两眉只解相思皱。", "悄然难受。", "教我怎唧𠺕。", "待得书来，不管归时瘦。", "娇痴后。", "是事撋就。", "只这难依口。"]'),
('song-ci-330','虞美人','张元干','宋','宋词','song-ci','虞美人','[]','广寒蟾影开云路。',66,'宋词/ci.song.7000.json','["广寒蟾影开云路。", "目断愁来处。", "菊花轻泛玉杯空。", "醉后不知星斗、乱西东。", "今宵入梦阳台雨。", "谁忍先归去。", "酒醒长是五更钟。", "休念旧游吹帽、几秋风。"]'),
('song-ci-331','虞美人','张元干','宋','宋词','song-ci','虞美人','[]','西郊追赏寻芳处。',66,'宋词/ci.song.7000.json','["西郊追赏寻芳处。", "闻道冲寒去。", "雨肥红绽向南枝。", "岁晚才开应是、恨春迟。", "天涯乐事王孙贵。", "花底还君醉。", "有人风味胜疏梅。", "醉里折花归去、更传杯。"]'),
('song-ci-332','虞美人','张元干','宋','宋词','song-ci','虞美人','[]','菊坡九日登高路。',66,'宋词/ci.song.7000.json','["菊坡九日登高路。", "往事知何处。", "陵迁谷变总成空。", "回首十年秋思、吹台东。", "西窗一夜萧萧雨。", "梦绕中原去。", "觉来依旧画楼锺。", "不道木犀香撼、海山风。"]'),
('song-ci-333','渔家傲','张元干','宋','宋词','song-ci','渔家傲','[]','钓笠披云青障绕。',72,'宋词/ci.song.7000.json','["钓笠披云青障绕。", "橛头细雨春江渺。", "白鸟飞来风满棹。", "收纶了。", "渔童拍手樵青笑。", "明月太虚同一照。", "浮家泛宅忘昏晓。", "醉眼冷看城市闹。", "烟波老。", "谁能惹得闲烦恼。"]'),
('song-ci-334','渔家傲','张元干','宋','宋词','song-ci','渔家傲','[]','楼外天寒山欲暮。',72,'宋词/ci.song.7000.json','["楼外天寒山欲暮。", "溪过雪后藏云树。", "小艇风斜沙觜露。", "流年度。", "春光已向梅梢住。", "短梦今宵还到否。", "苇村四望知何处。", "客里从来无意绪。", "催归去。", "故园正要莺花主。"]'),
('song-ci-335','渔家傲','张元干','宋','宋词','song-ci','渔家傲','[]','寒日西郊湖畔路。',72,'宋词/ci.song.7000.json','["寒日西郊湖畔路。", "天低野阔山无数。", "路转斜冈花满树。", "丝吹雨。", "南枝占得春光住。", "藉草携壶花底去。", "花飞酒面香浮处。", "老手调羹当独步。", "须记取。", "坐中都是芳菲侣。"]'),
('song-ci-336','谒金门','张元干','宋','宋词','song-ci','谒金门','[]','鸳鸯渚。',53,'宋词/ci.song.7000.json','["鸳鸯渚。", "春涨一江花雨。", "别岸数声初过橹。", "晚风生碧树。", "艇子相呼相语。", "载取暮愁归去。", "寒食烟村芳草路。", "愁来无着处。"]'),
('song-ci-337','谒金门','张元干','宋','宋词','song-ci','谒金门','[]','风露底。',53,'宋词/ci.song.7000.json','["风露底。", "石上岸巾愁起。", "月到房心天似水。", "乱峰清影里。", "此去登瀛须记。", "今夕道山同醉。", "春殿明年人共指。", "玉皇香案吏。"]'),
('song-ci-338','谒金门','张元干','宋','宋词','song-ci','谒金门','[]','清光溢。',53,'宋词/ci.song.7000.json','["清光溢。", "影转画檐凉入。", "风露一天星斗湿。", "无云天更碧。", "满引送君何惜。", "记取吾曹今夕。", "目断秋江君到日。", "潮来风正急。"]'),
('song-ci-339','瑞鹧鸪','张元干','宋','宋词','song-ci','瑞鹧鸪','[]','雏莺初转斗尖新。',64,'宋词/ci.song.7000.json','["雏莺初转斗尖新。", "双蕊花娇掌上身。", "总解满斟偏劝客，多生俱是绮罗人。", "回波偷顾轻招拍，方响底敲更合𥱧。", "豆蔻梢头春欲透，情知巫峡待为云。"]'),
('song-ci-340','瑞鹧鸪','张元干','宋','宋词','song-ci','瑞鹧鸪','[]','白衣苍狗变浮云。',64,'宋词/ci.song.7000.json','["白衣苍狗变浮云。", "千古功名一聚尘。", "好是悲歌将进酒，不妨同赋惜馀春。", "风光全似中原日，臭味要须我辈人。", "雨后飞花知底数，醉来赢取自由身。"]'),
('song-ci-341','好事近','张元干','宋','宋词','song-ci','好事近','[]','老去更思归，芳草正薰南陌。',53,'宋词/ci.song.7000.json','["老去更思归，芳草正薰南陌。", "上巳又逢寒食，叹三年为客。", "吹花小雨湿秋千，闲却好春色。", "天甚不怜人老，早教人归得。"]'),
('song-ci-342','好事近','张元干','宋','宋词','song-ci','好事近','[]','梅润乍晴天，帘卷画堂风月。',53,'宋词/ci.song.7000.json','["梅润乍晴天，帘卷画堂风月。", "珠翠共迷香雾，是长年时节。", "瑶池清夜宴群仙，鸾笙未吹彻。", "西母醉中微笑，看蟠桃初结。"]'),
('song-ci-343','好事近','张元干','宋','宋词','song-ci','好事近','[]','春色到花房，芳信一枝偏好。',53,'宋词/ci.song.7000.json','["春色到花房，芳信一枝偏好。", "勾引万红千翠，为化工呈巧。", "花姑玉貌笑东风，今朝放春早。", "看取鬓边幡胜，永宜春难老。"]'),
('song-ci-344','好事近','张元干','宋','宋词','song-ci','好事近','[]','斗帐炷炉熏，花露裛成芗泽。',53,'宋词/ci.song.7000.json','["斗帐炷炉熏，花露裛成芗泽。", "萦透雪儿金缕，醉玉壶春色。", "非烟非雾锁窗中，王孙倦留客。", "不道粉墙南畔，也有人闻得。"]'),
('song-ci-345','怨王孙・忆王孙','张元干','宋','宋词','song-ci','怨王孙・忆王孙','[]','小院春昼。',65,'宋词/ci.song.7000.json','["小院春昼。", "晴窗霞透。", "把雨燕脂，倚风翠袖。", "芳意恼乱人多。", "暖金荷。", "多情不分群葩后。", "伤春瘦。", "浅黛眉尖秀。", "红潮醉脸，半掩花底重门。", "怨黄昏。"]'),
('song-ci-346','怨王孙・忆王孙','张元干','宋','宋词','song-ci','怨王孙・忆王孙','[]','霁雨天迥。',65,'宋词/ci.song.7000.json','["霁雨天迥。", "平林烟暝。", "灯闪沙汀，水生钓艇。", "楼外柳暗谁家。", "乱昏鸦。", "相思怪得今番甚。", "寒食近。", "小砑鱼笺信。", "屏山交掩，微醉独倚栏干。", "恨春寒。"]'),
('song-ci-347','喜迁莺令・喜迁莺','张元干','宋','宋词','song-ci','喜迁莺令・喜迁莺','[]','文倚马，笔如椽。',56,'宋词/ci.song.7000.json','["文倚马，笔如椽。", "桂殿早登仙。", "旧游册府记当年。", "衮绣合貂蝉。", "庆天申，瞻玉座，鹓鹭正陪班。", "看君稳步过花砖。", "归院引金莲。"]'),
('song-ci-348','喜迁莺令・喜迁莺','张元干','宋','宋词','song-ci','喜迁莺令・喜迁莺','[]','云叶乱，月华光。',57,'宋词/ci.song.7000.json','["云叶乱，月华光。", "罗幕卷新凉。", "玉醅初泛嫩鹅黄。", "花露滴秋香。", "地行仙，天上相。", "风度世间人样。", "悬知洗盏径开尝。", "谁醉伴禅床。"]'),
('song-ci-349','喜迁莺慢・喜迁莺','张元干','宋','宋词','song-ci','喜迁莺慢・喜迁莺','[]','雁塔题名，宝津朌宴，盛事簪绅常说。',124,'宋词/ci.song.7000.json','["雁塔题名，宝津朌宴，盛事簪绅常说。", "文物昭融，圣代搜罗，千里争趋丹阙。", "元侯劝驾，乡老献书，发轫龟前列。", "山川秀，圜冠众多，无如闽越豪杰。", "姓标红纸，帖报泥金，喜信归来俱捷。", "骄马芦鞭醉垂，蓝绶吹雪。", "芳月素娥情厚，桂华一任郎君折。", "须满引，南台又是，合沙时节。"]'),
('song-ci-350','鹧鸪天','张元干','宋','宋词','song-ci','鹧鸪天','[]','不怕微霜点玉肌。',64,'宋词/ci.song.7000.json','["不怕微霜点玉肌。", "恨无流水照冰姿。", "与君著意从头看，初见东南第一枝。", "人散后，雪晴时。", "陇头春色寄来迟。", "使君本是花前客，莫怪殷勤为赋诗。"]'),
('song-ci-351','忆秦娥','张元干','宋','宋词','song-ci','忆秦娥','[]','桃花萼。',56,'宋词/ci.song.7000.json','["桃花萼。", "雨肥红绽东风恶。", "东风恶。", "长亭无寐，短书难托。", "征衫辜负深闺约。", "禁烟时候春罗薄。", "春罗薄。", "多应消瘦，可忺梳掠。"]'),
('song-ci-352','明月逐人来','张元干','宋','宋词','song-ci','明月逐人来','[]','花迷珠翠。',76,'宋词/ci.song.7000.json','["花迷珠翠。", "香飘罗绮。", "帘旌外、月华如水。", "暖红影里，谁会王孙意。", "最乐升平景致。", "长记宫中五夜，春风鼓吹。", "游仙梦、轻寒半醉。", "凤帏未暖，归去熏浓被。", "更问阴晴天气。"]'),
('song-ci-353','小重山','张元干','宋','宋词','song-ci','小重山','[]','谁向晴窗伴素馨。',70,'宋词/ci.song.7000.json','["谁向晴窗伴素馨。", "兰芽初秀发，紫檀心。", "国香幽艳最情深。", "歌白雪，祗少一张琴。", "新月冷光侵。", "醉时花近眼，莫频斟。", "薛涛笺上楚妃吟。", "空凝睇，归去梦中寻。"]'),
('song-ci-354','生查子','邓肃','宋','宋词','song-ci','生查子','[]','执手两潸然，情极都无语。',48,'宋词/ci.song.7000.json','["执手两潸然，情极都无语。", "去马更匆匆，一息迷回顾。", "孤馆得村醪，一醉空离绪。", "酒醒却无人，帘外三更雨。"]'),
('song-ci-355','感皇恩','邓肃','宋','宋词','song-ci','感皇恩','[]','翠竹谩连云，天风不到。',82,'宋词/ci.song.7000.json','["翠竹谩连云，天风不到。", "帘幕重重自热恼。", "冷香忽至，爱惜当同芝草。", "井花浮碧玉，炎威扫。", "酒渴想东邻，忧心如捣。", "纳履生疑谩悔懊。", "未容沈李，相对尊前倾倒。", "报君惟短句，琼琚好。"]'),
('song-ci-356','一剪梅・一翦梅','邓肃','宋','宋词','song-ci','一剪梅・一翦梅','[]','雨过春山翠欲浮。',64,'宋词/ci.song.7000.json','["雨过春山翠欲浮。", "影落寒溪碧玉流。", "片帆乘兴挂东风，夹岸花香拥去舟。", "尊酒时追李郭游。", "醉卧烟波万事休。", "梦回风定斗杓寒，渔笛一声天地秋。"]'),
('song-ci-357','蝶恋花','邓肃','宋','宋词','song-ci','蝶恋花','[]','执手长亭无一语。',70,'宋词/ci.song.7000.json','["执手长亭无一语。", "泪眼汪汪，滴下阳关句。", "牵马欲行还复住。", "春风吹断梨花雨。", "海角三千千叠路。", "归侍玉皇，那复回头顾。", "旌旆已因风月驻。", "何妨醉过清明去。"]'),
('song-ci-358','江城子','邓肃','宋','宋词','song-ci','江城子','[]','酒阑携手过回廊。',86,'宋词/ci.song.7000.json','["酒阑携手过回廊。", "夜初凉。", "月如霜。", "笑问木樨，何日吐天香。", "待插一枝归斗帐，和云雨，殢襄王。", "如今满目雨新黄。", "绕高堂。", "自芬芳。", "不见堂中，携手旧鸳鸯。", "已对秋光成感慨，更夜永，漏声长。"]'),
('song-ci-359','菩萨蛮','谢明远','宋','宋词','song-ci','菩萨蛮','[]','春风春雨花经眼。',52,'宋词/ci.song.7000.json','["春风春雨花经眼。", "石泉槐火春容晚。", "流水自无情。", "回波聚落英。", "问春何处去。", "春向天边住。", "举酒欲销愁。", "酒阑愁更愁。"]'),
('song-ci-360','踏莎行','谢明远','宋','宋词','song-ci','踏莎行','[]','楚树芊绵，江云芜漫。',68,'宋词/ci.song.7000.json','["楚树芊绵，江云芜漫。", "晓风吹堕梅千片。", "惊禽飞去响春空，平沙月落光零乱。", "人意伤离，物华惊换。", "武夷此去如天远。", "临分为我少留连，柳条独在江南岸。"]'),
('song-ci-361','踏莎行','张焘','宋','宋词','song-ci','踏莎行','[]','阳复寒根，气回枯杆。',68,'宋词/ci.song.7000.json','["阳复寒根，气回枯杆。", "前村昨夜梅初绽。", "谁言造化没偏颇，半开何独南枝暖。", "素艳幽轻，清香远散。", "雪中岂恨和羹晚。", "不知何处误东君，至今不使春拘管。"]'),
('song-ci-362','恨欢迟・恨来迟','张焘','宋','宋词','song-ci','恨欢迟・恨来迟','[]','淡薄情怀。',66,'宋词/ci.song.7000.json','["淡薄情怀。", "浅缀胭脂。", "独占江梅。", "最好是、严凝苦寒天气，却是开时。", "也不许、桃杏斗妍媸。", "也不许、雪霜相欺。", "又只恐、谁家一声羌笛，落尽南枝。"]'),
('song-ci-363','青玉案','姚述尧1','宋','宋词','song-ci','青玉案','["\u897f\u6e56"]','三年枕上吴中路。',80,'宋词/ci.song.7000.json','["三年枕上吴中路。", "遣黄耳、随君去。", "君到松江呼小渡。", "莫惊鸥鹭，四桥尽是，老子经行处。", "辋川图上看春暮。", "长记高人右丞句。", "作个归期天已许。", "春衫犹是，小蛮针线，曾湿西湖雨。"]'),
('song-ci-364','薄幸','吕渭老','宋','宋词','song-ci','薄幸','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','青楼春晚。',133,'宋词/ci.song.7000.json','["青楼春晚。", "昼寂寂、梳匀又懒。", "乍听得、鸦啼莺弄，惹起新愁无限。", "记年时、偷掷春心，花间隔雾遥相见。", "便角枕题诗，宝钗贳酒，共醉青苔深院。", "怎忘得、回廊下，携手处、花明月满。", "如今但暮雨，蜂愁蝶恨，小窗闲对芭蕉展。", "却谁拘管。", "尽无言、闲品秦筝，泪满参差雁。", "腰支渐小，心与杨花共远。"]'),
('song-ci-365','望海潮','吕渭老','宋','宋词','song-ci','望海潮','[]','侧寒斜雨，微灯薄雾，匆匆过了元宵。',129,'宋词/ci.song.7000.json','["侧寒斜雨，微灯薄雾，匆匆过了元宵。", "帘影护风，盆池见日，青青柳叶柔条。", "碧草皱裙腰。", "正昼长烟暖，蜂困莺娇。", "望处凄迷，半篙绿水浸斜桥。", "孙郎病酒无聊。", "记乌丝醉语，碧玉风标。", "新燕又双，兰心渐吐，嘉期趁取花朝。", "心事转迢迢。", "但梦随人远，心与山遥。", "误了芳音，小窗斜日对芭蕉。"]'),
('song-ci-366','选冠子','吕渭老','宋','宋词','song-ci','选冠子','[]','雨湿花房，风斜燕子，池阁昼长春晚。',131,'宋词/ci.song.7000.json','["雨湿花房，风斜燕子，池阁昼长春晚。", "檀盘战象，宝局铺棋，筹画未分还懒。", "谁念少年，齿怯梅酸，病疏霞盏。", "正青钱遮路，绿丝明水，倦寻歌扇。", "空记得、小阁题名，红笺青制，灯火夜深裁剪。", "明眸似水，妙语如弦，不觉晓霜鸡唤。", "闻道近来，筝谱慵看，金铺长掩。", "瘦一枝梅影，回首江南路远。"]'),
('song-ci-367','选冠子','吕渭老','宋','宋词','song-ci','选冠子','[]','风约晴云，花乾宿露，帘幕万家清晓。',131,'宋词/ci.song.7000.json','["风约晴云，花乾宿露，帘幕万家清晓。", "青帘赛酒，小坞藏春，冶叶艳枝相照。", "羊驾小车，笑逐游人，远迷芳草。", "更红英飞舞，绣茵连接，雾台烟沼。", "年少日、细马戎鞯，红靴玉带，同指软尘西笑。", "珍珠戏掷，彩笔搜奇，不觉暮春莺老。", "谁见这回，霜点髯衰，事萦怀抱。", "诉一春心事，燕子周遮来了。"]'),
('song-ci-368','念奴娇','吕渭老','宋','宋词','song-ci','念奴娇','[]','暮云收尽，霁霞明、高拥一轮寒玉。',121,'宋词/ci.song.7000.json','["暮云收尽，霁霞明、高拥一轮寒玉。", "帘影横斜房户静，小立啼红蔌蔌。", "素鲤频传，蕉心微展，双蕊明红烛。", "开门疑是，故人敲撼窗竹。", "长记那里西楼，小寒窗静，尽掩风筝鸣屋。", "泪眼灯光情未尽，尽觉语长更促。", "短短霞杯，温温罗帊，妙语书裙幅。", "五湖何日，小舟同泛春绿。"]'),
('song-ci-369','情久长','吕渭老','宋','宋词','song-ci','情久长','["\u957f\u6c5f"]','锁窗夜永，无聊尽作伤心句。',129,'宋词/ci.song.7000.json','["锁窗夜永，无聊尽作伤心句。", "甚近日、带红移眼，梨脸择雨。", "春心偿未足，怎忍听、啼血催归杜宇。", "暮帆挂、沈沈暝色，衮衮长江，流不尽、来无据。", "点检风光，岁月今如许。", "趁此际、浦花汀草，一棹东去。", "云窗雾阁，洞天晓、同作烟霞伴侣。", "算谁见、梅帘醉梦，柳陌晴游，应未许、春知处。"]'),
('song-ci-370','情久长','吕渭老','宋','宋词','song-ci','情久长','[]','冰梁跨水，沈沈霁色遮千里。',129,'宋词/ci.song.7000.json','["冰梁跨水，沈沈霁色遮千里。", "怎向我、小舟孤楫，天外飘逐。", "夜寒侵短发，睡不稳、窗外寒风渐起。", "岁华暮、蟾光射雪，碧瓦飘霜，尘不动、寒无际。", "鸡咽荒郊，梦也无归计。", "拥绣枕、断魂残魄，清吟无味。", "想伊睡起，又念远、楼阁横枝对倚。", "待归去、西窗剪烛，小阁凝香，深翠幕、饶春睡。"]'),
('song-ci-371','满江红','吕渭老','宋','宋词','song-ci','满江红','[]','晚浴新凉，风蒲乱、松梢见月。',110,'宋词/ci.song.7000.json','["晚浴新凉，风蒲乱、松梢见月。", "庭阴尽、暮蝉啼歇。", "萤绕井阑帘入燕，荷香兰气供摇箑。", "赖晚来、一雨洗游尘，无些热。", "心下事，峰重叠。", "人甚处，星明灭。", "想行云应在，凤凰城阙。", "曾约佳期同菊蕊，当时共指灯花说。", "据眼前、何日是西风，凉吹叶。"]'),
('song-ci-372','满江红','吕渭老','宋','宋词','song-ci','满江红','[]','笑语移时，风影乱、半帘寒日。',110,'宋词/ci.song.7000.json','["笑语移时，风影乱、半帘寒日。", "鲜明是、晚来妆饰。", "共说西园携手处，小桥深竹连苔色。", "到如今、梧叶染清霜，封行迹。", "春未透，梅先拆。", "人纵健，时难得。", "想明年虚过，上元寒食。", "数著佳期愁入眼，雨珠零乱梨花湿。", "任翠鬟、猗侧背斜阳，鸣瑶瑟。"]'),
('song-ci-373','满江红','吕渭老','宋','宋词','song-ci','满江红','[]','燕拂危樯，斜日外、数峰凝碧。',112,'宋词/ci.song.7000.json','["燕拂危樯，斜日外、数峰凝碧。", "正暗潮生渚，暮风飘席。", "初过南村沽酒市，连空十顷菱花白。", "想故人、轻箑障游丝，闻遥笛。", "鱼与雁，通消息。", "心与梦，空牵役。", "到如今相见，怎生休得。", "斜抱琵琶传密意，一襟新月横空碧。", "问甚时、同作醉中仙，烟霞客。"]'),
('song-ci-374','满江红','吕渭老','宋','宋词','song-ci','满江红','[]','山绕吴城，修竹外、满林围碧。',112,'宋词/ci.song.7000.json','["山绕吴城，修竹外、满林围碧。", "任孤樯百丈，远牵江色。", "政简民闲无一事，同游仍是鸳鸾客。", "到晚年、遗爱续新题，都堪说。", "修门赋，今谁续。", "痛饮士，天应惜。", "正彩霞垂帔，暮风飘瑟。", "笑疾禅痴今在否，风灯石火同飘忽。", "去醉乡、深处著身心，休铭栉。"]'),
('song-ci-375','醉蓬莱','吕渭老','宋','宋词','song-ci','醉蓬莱','[]','任落梅铺缀，雁齿斜桥，裙腰芳草。',120,'宋词/ci.song.7000.json','["任落梅铺缀，雁齿斜桥，裙腰芳草。", "闲伴游丝，过晓园庭沼。", "厮近清明，雨晴风软，称少年寻讨。", "碧缕墙头，红云水面，柳堤花岛。", "谁信而今，怕愁憎酒，对著花枝，自疏歌笑。", "莺语丁宁，问甚时重到。", "梦笔题诗，帊绫封泪，向凤箫人道。", "处处伤心，年年远念，惜春人老。"]'),
('song-ci-376','齐天乐','吕渭老','宋','宋词','song-ci','齐天乐','[]','香红飘没明春水，寒食万家游舫。',125,'宋词/ci.song.7000.json','["香红飘没明春水，寒食万家游舫。", "整整斜斜，疏疏密密，帘缬旗红相望。", "江波荡漾。", "称彩舰龙舟，绣衣霞桨。", "舞楫争先，歌笑箫鼓乱清唱。", "重来刘郎又老，对故园桃红春晚，尽成惆怅。", "泪雨难晴，愁眉又结，翻覆十年手掌。", "如今怎向。", "念舞板歌尘，远如天上。", "斜日回舟，醉魂空舞扬。"]'),
('song-ci-377','沁园春','吕渭老','宋','宋词','song-ci','沁园春','[]','复把元宵，等闲过了，算来告谁。',140,'宋词/ci.song.7000.json','["复把元宵，等闲过了，算来告谁。", "整二年三岁，尊前笑处，知他陪了，多少歌诗。", "岂信如今，不成些事，还是无聊空皱眉。", "争知道，冤家误我，日许多时。", "心儿。", "转更痴迷。", "又疑道、清明得共伊。", "但自家晚夜，多方遣免，不须烦恼，雨月为期。", "用破身心，博些欢爱，有后不成人便知。", "从来是，这风流伴侣，有分双飞。"]'),
('song-ci-378','满路花・促拍满路花','吕渭老','宋','宋词','song-ci','满路花・促拍满路花','[]','西风秋日短，小雨菊花寒。',101,'宋词/ci.song.7000.json','["西风秋日短，小雨菊花寒。", "断云低古木，暗江天。", "星娥尺五，佳约误当年。", "小语凭肩处，犹记西园。", "画桥斜月阑干。", "鸟啼花落，春信遣谁传。", "尚容清夜梦、小留连。", "青楼何处，宝镜注婵娟。", "应念红笺事，微晕春山。", "背窗愁枕孤眠。"]'),
('song-ci-379','蓦山溪','吕渭老','宋','宋词','song-ci','蓦山溪','[]','韵高格妙。',102,'宋词/ci.song.7000.json','["韵高格妙。", "不数闲花草。", "向晚小梳妆，换一套、新衣始了。", "横钗整鬓，倚醉唱清词，房户静，酒杯深。", "帘幕明残照。", "扬州一梦，未尽还惊觉。", "自恁在心头，拈不出、倚时是了。", "吴霜点鬓，春色老刘郎，云路远，晚溪横，谁见桃花笑。"]'),
('song-ci-380','蓦山溪','吕渭老','宋','宋词','song-ci','蓦山溪','[]','元宵灯火。',102,'宋词/ci.song.7000.json','["元宵灯火。", "月淡游人可。", "携手步长廊，又说道、倾心向我。", "归来一梦，整整十年馀，人似旧，去无因，牵惹情怀破。", "章台杨柳，闻道无关锁。", "行客挽长条，悄不似、当初些个。", "而今休也，摇落任东风，但恣意，尽留情，我也知无那。"]'),
('song-ci-381','千秋岁','吕渭老','宋','宋词','song-ci','千秋岁','[]','宝香盈袖。',87,'宋词/ci.song.7000.json','["宝香盈袖。", "约腕金条瘦。", "裙儿细裥如肩皱。", "笑多簪髻侧，语小丝簧奏。", "洞房晚，千金未直横波溜。", "缘短欢难又。", "人去春如旧。", "枝上月，谁携手。", "宿云迷远梦，泪枕中残酒。", "怎奈向，繁阴乱叶梅如豆。"]'),
('song-ci-382','早梅芳近・早梅芳','吕渭老','宋','宋词','song-ci','早梅芳近・早梅芳','[]','画帘深，妆阁小。',98,'宋词/ci.song.7000.json','["画帘深，妆阁小。", "曲径明花草。", "风声约雨，暝色啼鸦暮天杳。", "染眉山对碧，匀脸霞相照。", "渐更衣对客，微坐自轻笑。", "醉红明，金叶倒。", "恣看还新好。", "莹汪粉泪，滴烁波光射庭沼。", "犀心通密语，珠唱翻新调。", "佳期、定约秋了。"]'),
('song-ci-383','醉落魄・一斛珠','吕渭老','宋','宋词','song-ci','醉落魄・一斛珠','[]','明窗读易。',67,'宋词/ci.song.7000.json','["明窗读易。", "时才人地俱超轶。", "偶然一坠槐安国。", "说利谈功，这事怎休得。", "何时置酒图书室。", "挥弦目送西飞翼。", "夜来已觉春笋溢。", "月影三人，一醉旧相识。"]'),
('song-ci-384','醉落魄・一斛珠','吕渭老','宋','宋词','song-ci','醉落魄・一斛珠','[]','纤鞋窄袜。',67,'宋词/ci.song.7000.json','["纤鞋窄袜。", "红茵自称琵琶拍。", "明衣妆脸春梳掠。", "好好亭亭，那得恁标格。", "匆匆一醉霜华白。", "归来偏记蓝桥宅。", "五更残梦迷蝴蝶。", "觑著花枝，只被绣帘隔。"]'),
('song-ci-385','惜分飞','吕渭老','宋','宋词','song-ci','惜分飞','[]','白玉花骢金络脑。',58,'宋词/ci.song.7000.json','["白玉花骢金络脑。", "十里华灯相照。", "帘映春窈窕。", "雾香残腻桃花笑。", "一串歌珠云外袅。", "饮罢玉楼寒悄。", "归去城南道。", "柳梢猎猎东风晓。"]'),
('song-ci-386','浣溪沙','吕渭老','宋','宋词','song-ci','浣溪沙','[]','烟柳濛濛鹊做巢。',48,'宋词/ci.song.7000.json','["烟柳濛濛鹊做巢。", "青青弱草带斜桥。", "莺声多在杏花梢。", "逐伴不知春路远，见人时著小词招。", "阿谁有分伴吹箫。"]'),
('song-ci-387','浣溪沙','吕渭老','宋','宋词','song-ci','浣溪沙','[]','彩选骰儿隔袖拈。',48,'宋词/ci.song.7000.json','["彩选骰儿隔袖拈。", "整钗微见玉纤纤。", "夜寒窗外更垂帘。", "好事灯花双作蕊，照人月影入斜檐。", "新愁日日座中添。"]'),
('song-ci-388','浣溪沙','吕渭老','宋','宋词','song-ci','浣溪沙','[]','做得因缘不久长。',48,'宋词/ci.song.7000.json','["做得因缘不久长。", "惊风枝上偶成双。", "归来魂梦带幽香。", "灯下揉花春去早，竹间影月索归忙。", "十年前事费思量。"]'),
('song-ci-389','渔家傲','吕渭老','宋','宋词','song-ci','渔家傲','["\u5e90\u5c71"]','闻道庐山横广泽。',72,'宋词/ci.song.7000.json','["闻道庐山横广泽。", "晴空万顷波涛白。", "上有至人营窟宅。", "经游客。", "古今多是烟霞谪。", "一钵上人轻六翮。", "选场要射如来策。", "点化黄金非妙药。", "难堪酌。", "三生一口都吞却。"]'),
('song-ci-390','渔家傲','吕渭老','宋','宋词','song-ci','渔家傲','[]','昨夜山空流石乳。',72,'宋词/ci.song.7000.json','["昨夜山空流石乳。", "道人妙手亲拈取。", "未欲凌云归洞府。", "清风举。", "大千一叶同掀舞。", "笑把须弥挝破鼓。", "东山云作西山雨。", "我欲住庵无拄斧。", "君相许。", "三更明月湖心午。"]'),
('song-ci-391','渔家傲','吕渭老','宋','宋词','song-ci','渔家傲','[]','潦倒瞿昙饶口悄。',72,'宋词/ci.song.7000.json','["潦倒瞿昙饶口悄。", "拈花冤道头陀笑。", "鸡足山中眠未觉。", "谁知道。", "至今功业犹分剖。", "唇口周遮何日了。", "禅床四面藤萝绕。", "有个路头君试讨。", "梅花老。", "南园蝴蝶飞芳草。"]'),
('song-ci-392','渔家傲','吕渭老','宋','宋词','song-ci','渔家傲','["\u5e90\u5c71"]','高绊袈裟挑纸帔。',72,'宋词/ci.song.7000.json','["高绊袈裟挑纸帔。", "一杯茶罢成行计。", "路入庐山风细细。", "轻弹指。", "百千三昧俱游戏。", "法椅何曾烧两臂。", "谁知纸上无穷意。", "欲识普贤真实际。", "齁齁地。", "小炉雪夜和衣睡。"]'),
('song-ci-393','渔家傲','吕渭老','宋','宋词','song-ci','渔家傲','[]','顶上铁轮飞火焰。',72,'宋词/ci.song.7000.json','["顶上铁轮飞火焰。", "防身细按威神剑。", "体用双行谁敢觇。", "光闪闪。", "何须更把茶林撼。", "衲子家风存古俭。", "一条榔栗如天堑。", "粥鼓未鸣灯火暗。", "无恩念。", "断崖古木横藤簟。"]'),
('song-ci-394','渔家傲','吕渭老','宋','宋词','song-ci','渔家傲','[]','落月杜鹃啼未了。',72,'宋词/ci.song.7000.json','["落月杜鹃啼未了。", "粥鱼忽报千山晓。", "笠子盖头衣钵少。", "穿林表。", "回头高刹空中小。", "官路旧多林木绕。", "露浓花蕊皆颠倒。", "渡水登山排草草。", "卢山好。", "香炉峰下湖波渺。"]'),
('song-ci-395','思佳客','吕渭老','宋','宋词','song-ci','思佳客','[]','江上何人一笛横。',64,'宋词/ci.song.7000.json','["江上何人一笛横。", "倚楼吹得月华生。", "寒风堕指倾三弄，小市收灯欲二更。", "持蟹股，破霜橙。", "玉人水调品秦筝。", "细看桃李春时面，共尽玻璃酒一觥。"]'),
('song-ci-396','思佳客','吕渭老','宋','宋词','song-ci','思佳客','[]','微点胭脂晕泪痕。',64,'宋词/ci.song.7000.json','["微点胭脂晕泪痕。", "更衣整鬓立黄昏。", "春风搅树花如雨，夕霭迷空燕趁门。", "题往事，锦回纹。", "春心无定似行云。", "深屏绣幌空愁独，明月梨花殢一尊。"]'),
('song-ci-397','好事近','吕渭老','宋','宋词','song-ci','好事近','[]','别酒带愁酸，千里失群黄鹄。',53,'宋词/ci.song.7000.json','["别酒带愁酸，千里失群黄鹄。", "行到小桥梯下，便飞云南北。", "不妨垂手小徘徊，日影转阑曲。", "从此贺囊佳制，有新奇题目。"]'),
('song-ci-398','好事近','吕渭老','宋','宋词','song-ci','好事近','[]','飞雪过江来，船在赤栏桥侧。',53,'宋词/ci.song.7000.json','["飞雪过江来，船在赤栏桥侧。", "惹报布帆无恙，著两行亲札。", "从今日日在南楼，鬓自此时白。", "一咏一觞谁共，负平生书册。"]'),
('song-ci-399','好事近','吕渭老','宋','宋词','song-ci','好事近','[]','年少万函书，朱紫只应低拾。',53,'宋词/ci.song.7000.json','["年少万函书，朱紫只应低拾。", "更赖主人明眼，作青云梯级。", "归来应是印累累，笳鼓闹乡邑。", "若访老人生计，贩谢郎蓑笠。"]'),
('song-ci-400','好事近','吕渭老','宋','宋词','song-ci','好事近','[]','云影护梅枝，短短未禁飞雪。',53,'宋词/ci.song.7000.json','["云影护梅枝，短短未禁飞雪。", "彩幅自题新句，作催妆佳阕。", "西楼昨夜五更寒，恐一枝先发。", "元是素娥无寐，驾半轮明月。"]'),
('song-ci-401','好事近','吕渭老','宋','宋词','song-ci','好事近','[]','小饮破清寒，坐久困花颓玉。',53,'宋词/ci.song.7000.json','["小饮破清寒，坐久困花颓玉。", "两行艳衣明粉，听阿谁拘束。", "丽华百媚坐来生，仙韵动群目。", "一曲凤箫同去，倦人间丝竹。"]'),
('song-ci-402','天仙子','吕渭老','宋','宋词','song-ci','天仙子','[]','楼下辘轳横露井。',80,'宋词/ci.song.7000.json','["楼下辘轳横露井。", "楼上婵娟开晓镜。", "下楼难忘上楼时，风未定。", "帆不正。", "簌簌珍珠挥麈柄。", "眉上新愁吹不醒。", "别酒未斟歌未忍。", "雪中梅下定重来，烟暝暝。", "肠寸寸。", "莫放笛声吹落尽。"]'),
('song-ci-403','燕归梁','吕渭老','宋','宋词','song-ci','燕归梁','[]','楼外东风杜宇声。',62,'宋词/ci.song.7000.json','["楼外东风杜宇声。", "双枕细眉颦。", "女郎番马小山屏。", "金笼冷、梦魂惊。", "起来重绾双罗髻，无个事、泪盈盈。", "杨花蝴蝶乱分身。", "飞不定、暮云晴。"]'),
('song-ci-404','小重山','吕渭老','宋','宋词','song-ci','小重山','[]','半夜灯残鼠上檠。',70,'宋词/ci.song.7000.json','["半夜灯残鼠上檠。", "上窗风动竹，月微明。", "梦魂偏记水西亭。", "琅玕碧，花影弄晴蜓。", "千里暮云平。", "南楼催上烛，晚来晴。", "酒阑人散斗西倾。", "天如水，团扇扑流萤。"]'),
('song-ci-405','河传','吕渭老','宋','宋词','song-ci','河传','[]','斜红照水。',75,'宋词/ci.song.7000.json','["斜红照水。", "似晴空万里。", "明霞相倚。", "逐伴笑歌，小立绿槐阴里。", "诮没些，春气味。", "纷纷觑著闲桃李。", "浅浅深深，不满游人意。", "幽艳一枝，向晚重帘深闭。", "是青君、爱惜底。"]'),
('song-ci-406','清平乐','吕渭老','宋','宋词','song-ci','清平乐','[]','水瓶石砚。',54,'宋词/ci.song.7000.json','["水瓶石砚。", "败壁蜗书篆。", "窗下日舒缝衲线。", "屋角晚风飞霰。", "上元灯火佳时。", "长廊语笑追随。", "高卧一番纸帔，觉来月贯南枝。"]'),
('song-ci-407','握金钗','吕渭老','宋','宋词','song-ci','握金钗','[]','风日困花枝，晴蜂自相趁。',78,'宋词/ci.song.7000.json','["风日困花枝，晴蜂自相趁。", "晚来红浅香尽。", "整顿腰肢晕残粉。", "弦上语，梦中人，天外信。", "青杏已成双，新尊荐樱笋。", "为谁一和销损。", "数著佳期又不稳。", "春去也，怎当他，清昼永。"]'),
('song-ci-408','握金钗','吕渭老','宋','宋词','song-ci','握金钗','[]','向晚小妆匀，明窗倦裁剪。',78,'宋词/ci.song.7000.json','["向晚小妆匀，明窗倦裁剪。", "见花清泪遮眼。", "开尽繁桃又春晚。", "心下事，比年时，都较懒。", "胡蝶入帘飞，郎声似莺啭。", "见来无计拘管。", "心似芭蕉乍舒展。", "归去也，夕阳斜，红满院。"]'),
('song-ci-409','南歌子','吕渭老','宋','宋词','song-ci','南歌子','[]','策杖穿荒圃，登临笑晚风。',62,'宋词/ci.song.7000.json','["策杖穿荒圃，登临笑晚风。", "无穷秋色蔽晴空。", "遥见夕阳江上、卷飞蓬。", "雁过菰蒲远，山遥梦寐通。", "一林枫叶堕愁红。", "归去暮烟深处、听疏锺。"]'),
('song-ci-410','南歌子','吕渭老','宋','宋词','song-ci','南歌子','[]','远色连朱阁，寒鸦噪夕阳。',62,'宋词/ci.song.7000.json','["远色连朱阁，寒鸦噪夕阳。", "小炉温手酌鹅黄。", "掩乱一枝清影、在寒窗。", "念远歌声小，嗔归泪眼长。", "纤腰今属冶游郎。", "朝暮楚宫云雨、恨茫茫。"]'),
('song-ci-411','蝶恋花','吕渭老','宋','宋词','song-ci','蝶恋花','[]','风洗游丝花皱影。',70,'宋词/ci.song.7000.json','["风洗游丝花皱影。", "碧草初齐，舞鹤闲相趁。", "短梦乍回慵理鬓。", "惊心忽数清明近。", "逐伴强除眉上恨。", "趁蝶西园，不觉鞋儿褪。", "醉笑眼波横一寸。", "微微酒色生红晕。"]'),
('song-ci-412','蝶恋花','吕渭老','宋','宋词','song-ci','蝶恋花','[]','花色撩人红入眼。',70,'宋词/ci.song.7000.json','["花色撩人红入眼。", "可是东君，要得人肠断。", "欲诉深情春不管。", "风枝雨叶空撩乱。", "谩插一枝飞一盏。", "小赏幽期，破我平生愿。", "珍约未成春又短。", "但凭蝴蝶传深怨。"]'),
('song-ci-413','品令','吕渭老','宋','宋词','song-ci','品令','[]','绣衣未整。',80,'宋词/ci.song.7000.json','["绣衣未整。", "傍窗格、临清镜。", "新霜薄雾，这下几日，阴晴不定。", "欲插黄花，心事又还记省。", "去年香径。", "共粉蝶、闲相趁。", "宝香玉佩，暗解付与，多情荀令。", "何日西楼，重见暮帆烟艇。"]'),
('song-ci-414','祝英台・祝英台近','吕渭老','宋','宋词','song-ci','祝英台・祝英台近','[]','宝蟾明，朱阁静，新燕近帘语。',95,'宋词/ci.song.7000.json','["宝蟾明，朱阁静，新燕近帘语。", "还记元宵，灯火小桥路。", "逢迎春笋柔微，凌波纤稳，诮不顾、斗斜三鼓。", "甚无据。", "谁信一霎是春，惊声留不住。", "柳色苔痕，风雨暗花圃。", "细看罗带银钩，绡巾香泪，算不枉、那时分付。"]'),
('song-ci-415','水调歌头','吕渭老','宋','宋词','song-ci','水调歌头','[]','扁舟思独往，樯影划晴烟。',114,'宋词/ci.song.7000.json','["扁舟思独往，樯影划晴烟。", "要伴人随明月，踏破水中天。", "谁信骑鲸高逝，空对笔端风雨，如泛楚江船。", "老子穷无赖，端欲把降竿。", "白苹汀，归老计，似高闲。", "平生爱我，一言相置二刘间。", "准拟何山松桂，折足铛能安稳，芋火对阑残。", "何必少林语，立雪问心安。"]'),
('song-ci-416','水调歌头','吕渭老','宋','宋词','song-ci','水调歌头','[]','江湖堪极目，非雾亦非烟。',114,'宋词/ci.song.7000.json','["江湖堪极目，非雾亦非烟。", "故人相见，纵横高义薄云天。", "已具萸尊茗话，怅望云中江树，不见子猷船。", "日色隐林表，十里认帆竿。", "百年间，无个事，且安闲。", "功名两字，茫然都坠有无间。", "且尽身前一醉，休问古来今往，及取菊花残。", "仙事占无据，竹帛笑刘安。"]'),
('song-ci-417','水调歌头','吕渭老','宋','宋词','song-ci','水调歌头','[]','秋斋多梦谒，舌本欲生烟。',114,'宋词/ci.song.7000.json','["秋斋多梦谒，舌本欲生烟。", "独步一庭明月，雁字已横天。", "作个生涯不遂，松竹雨荒三径，却忆五湖船。", "小阮贫尤甚，犊鼻挂长竿。", "白鸥汀，风共水，一生闲。", "横琴唳鹤，要携妻子老云间。", "灯火荧荧深夜，高卧南窗折几，杯到不留残。", "莫遣江湖手，遮日向长安。"]'),
('song-ci-418','水调歌头','吕渭老','宋','宋词','song-ci','水调歌头','[]','心肝皆锦绣，落笔尽云烟。',114,'宋词/ci.song.7000.json','["心肝皆锦绣，落笔尽云烟。", "诗狂酒兴，要骑赤鲤上青天。", "织女回车相劳，指点虚无征路，翻动月明船。", "举手谢同辈，岂复念渔竿。", "我平生，心正似，白云闲。", "衣冠污我，偶逢游戏到人间。", "常念孤云高妙，若作辘轳俯仰，谁复食君残。", "拜尘金谷辈，都是卧崇安。"]'),
('song-ci-419','水调歌头','吕渭老','宋','宋词','song-ci','水调歌头','[]','诗人翻水尽，寂寞五侯烟。',114,'宋词/ci.song.7000.json','["诗人翻水尽，寂寞五侯烟。", "醉魂何在，应骑箕尾列青天。", "记得平生谈笑，夹岸手栽杨柳，同泛夜深船。", "溪水还依旧，深浅半青竿。", "小神仙，殷七七，许闲闲。", "黄粱未熟，经游都在梦魂间。", "我厌嚣寺浊味，几欲凌云羽化，鸡犬不留残。", "俗事丹砂冷，且抱一枝安。"]'),
('song-ci-420','水调歌头','吕渭老','宋','宋词','song-ci','水调歌头','[]','暮云遮远眼，叠叠入青烟。',114,'宋词/ci.song.7000.json','["暮云遮远眼，叠叠入青烟。", "十年不见，醯鸡同舞瓮中天。", "闻道山阴回棹，相去都无百里，李郭可同船。", "行止皆天意，端欲自操竿。", "功名事，须早计，真安闲。", "高才妙手，不当留意市廛间。", "俄已山林长往，尘面时时拂镜，齿发甚衰残。", "廊庙非吾事，茅屋且安安。"]'),
('song-ci-421','水调歌头','吕渭老','宋','宋词','song-ci','水调歌头','[]','抚床多感慨，白发困风烟。',114,'宋词/ci.song.7000.json','["抚床多感慨，白发困风烟。", "出门有碍，更堪寒暮雪飞天。", "君弃一盂一衲，奔走五湖清海，杯度不乘船。", "来访山中友，□□□□竿。", "看人间，谁得似，谪仙闲。", "生涯不问，留情多在酒杯间。", "剪烛西风谈笑，零落一尊相对，不觉已更残。", "回首功名事，笺记谢任安。"]'),
('song-ci-422','水调歌头','吕渭老','宋','宋词','song-ci','水调歌头','[]','十年禅榻畔，风雨扬茶烟。',114,'宋词/ci.song.7000.json','["十年禅榻畔，风雨扬茶烟。", "跳丸日月，未甘白发困尧天。", "江左风流才子，要伴江湖张翰，同泛洛阳船。", "酌酒情无尽，海燕绕船竿。", "逼人来，功业事，不教闲。", "男儿三十，定当谈笑在堂间。", "老子婆娑贫态，闭户长须赤脚，他日要分残。", "禹浪桃花影，归棹正轻安。"]'),
('song-ci-423','江城子','吕渭老','宋','宋词','song-ci','江城子','[]','晓参垂户宿酲醒。',86,'宋词/ci.song.7000.json','["晓参垂户宿酲醒。", "坐南亭。", "对疏星。", "点点萤光，偏向竹梢明。", "望断长空何处是，云叶乱，彩霞横。", "西楼依旧抱重城。", "小银屏。", "此时情。", "鸦阵翻丛，枯柳两三声。", "敧枕欲寻初夜梦，鸡唱远，晓蟾倾。"]'),
('song-ci-424','江城子','吕渭老','宋','宋词','song-ci','江城子','[]','闻君见影已堪怜。',86,'宋词/ci.song.7000.json','["闻君见影已堪怜。", "短因缘。", "偶同筵。", "相见无言，分散倍依然。", "做梦杨花随去也，妆阁畔，绣床前。", "觉来离绪意绵绵。", "写蛮笺。", "倩谁传。", "鱼雁悠悠，门外水如天。", "欲上西楼还不忍，难著眼，望秋千。"]'),
('song-ci-425','水龙吟','吕渭老','宋','宋词','song-ci','水龙吟','[]','五湖春水茫茫，梦魂夜逐杨花去。',126,'宋词/ci.song.7000.json','["五湖春水茫茫，梦魂夜逐杨花去。", "汀花岸草，佳人微笑，眼波横注。", "借问刘郎，心期则甚，一成无据。", "自春来泪满，挼蓝袖口，没整顿，心情处。", "闻道相如病渴，念文君、白头新句。", "相思两地，无穷烟水，一庭花雾。", "锦字藏头，织成机上，一时分付。", "问他年，更有微云淡月，重来兮否。"]'),
('song-ci-426','减字木兰花','吕渭老','宋','宋词','song-ci','减字木兰花','[]','雨帘高卷。',52,'宋词/ci.song.7000.json','["雨帘高卷。", "芳树阴阴连别馆。", "凉气侵楼。", "蕉叶荷枝各自秋。", "前溪夜舞。", "化作惊鸿留不住。", "愁损腰肢。", "一桁香销旧舞衣。"]'),
('song-ci-427','减字木兰花','吕渭老','宋','宋词','song-ci','减字木兰花','[]','明眸巧笑。',52,'宋词/ci.song.7000.json','["明眸巧笑。", "坐久更宜灯烛照。", "小醉辞归。", "怀抱明明只自知。", "琐窗重见。", "桃李春风三月面。", "怎不思量。", "折柳孤吟断杀肠。"]'),
('song-ci-428','江城子慢','吕渭老','宋','宋词','song-ci','江城子慢','[]','新枝媚斜日。',132,'宋词/ci.song.7000.json','["新枝媚斜日。", "花径霁、晚碧泛红滴。", "近寒食。", "蜂蝶乱、点检一城春色。", "倦游客。", "门外昏鸦啼梦破，春心似、游丝飞远碧。", "燕子又语斜檐，行云自没消息。", "当时乌丝夜语，约桃花时候，同醉瑶瑟。", "甚端的。", "看看是、榆角杨花飞掷。", "怎忘得。", "斜倚红楼回泪眼，天如水、沈沈连翠璧。", "想伊不整啼妆影帘侧。"]'),
('song-ci-429','如梦令','吕渭老','宋','宋词','song-ci','如梦令','[]','百和宝钗香佩。',40,'宋词/ci.song.7000.json','["百和宝钗香佩。", "短短同心霞带。", "清镜照新妆，巧画一双眉黛。", "多态。", "多态。", "偷观榴花窗外。"]'),
('song-ci-430','极相思','吕渭老','宋','宋词','song-ci','极相思','[]','拂墙花影飘红。',60,'宋词/ci.song.7000.json','["拂墙花影飘红。", "微月辨帘栊。", "香风满袖，金莲印步，狭径迎逢。", "笑面乍开远敛翠，正花时、却恁西东。", "别房初睡，斜门未锁，且更从容。"]'),
('song-ci-431','极相思','吕渭老','宋','宋词','song-ci','极相思','[]','西园斗草归迟。',60,'宋词/ci.song.7000.json','["西园斗草归迟。", "隔叶啭黄鹂。", "阑干醉倚，秋千背立，数遍佳期。", "寒食清明都过了，趁如今、芍药蔷薇。", "衩衣吟露，归舟缆月，方解开眉。"]'),
('song-ci-432','贺新郎','吕渭老','宋','宋词','song-ci','贺新郎','[]','斜日封残雪。',140,'宋词/ci.song.7000.json','["斜日封残雪。", "记别时、檀槽按舞，霓裳初彻。", "唱煞阳关留不住，桃花面皮似热。", "渐点点、珍珠承睫。", "门外潮平风席正，指佳期、共约花同折。", "情未忍，带双结。", "钗金未断肠先结。", "下扁舟、更有暮山千叠。", "别后武陵无好梦，春山子规更切。", "但孤坐、一帘明月。", "蚕共茧、花同蒂，甚人生要见，底多离别。", "谁念我，泪如血。"]'),
('song-ci-433','浪淘沙','吕渭老','宋','宋词','song-ci','浪淘沙','[]','倚枕数更筹。',64,'宋词/ci.song.7000.json','["倚枕数更筹。", "清夜悠悠。", "竹风荷露小窗秋。", "往事迷人浑不省，总是离愁。", "无赖是横眸。", "济楚风流。", "一时搂揽著心头。", "调数梦魂将我去，明月重楼。"]'),
('song-ci-434','思佳客','吕渭老','宋','宋词','song-ci','思佳客','[]','深夜槐风析酲惺。',64,'宋词/ci.song.7000.json','["深夜槐风析酲惺。", "露荷凉气满西庭。", "凭栏小语花梢月，缓步偷拈石上萤。", "秋意早，暑衣轻。", "殢人索酒复同倾。", "大家沈醉还高枕，一任西楼报五更。"]'),
('song-ci-435','二郎神','吕渭老','宋','宋词','song-ci','二郎神','[]','西池旧约。',123,'宋词/ci.song.7000.json','["西池旧约。", "燕语柳梢桃萼。", "向紫陌、秋千影下，同绾双双凤索。", "过了莺花休则问，风共月、一时闲却。", "知谁去、唤得秋阴，满眼败垣红叶。", "飘泊。", "江湖载酒，十年行乐。", "甚近日、伤高念远，不觉风前泪落。", "橘熟橙黄堪一醉，断未负、晚凉池阁。", "只愁被、撩拨春心，烦恼怎生安著。"]'),
('song-ci-436','百宜娇・眉妩','吕渭老','宋','宋词','song-ci','百宜娇・眉妩','[]','隙月垂篦，乱蛩催织，秋晚嫩凉房户。',130,'宋词/ci.song.7000.json','["隙月垂篦，乱蛩催织，秋晚嫩凉房户。", "燕拂帘旌，鼠窥窗网，寂寂飞萤来去。", "金铺镇掩，谩记得、花时南浦。", "约重阳、萸糁菊英，小楼遥夜歌舞。", "银烛暗、佳期细数。", "帘幕渐西风，午窗秋雨。", "叶底翻红，水面皱碧，灯火裁缝砧杵。", "登高望极，正雾锁、官槐归路。", "定须相将，宝马钿车，访吹箫侣。"]'),
('song-ci-437','醉思仙','吕渭老','宋','宋词','song-ci','醉思仙','[]','断人肠。',110,'宋词/ci.song.7000.json','["断人肠。", "正西楼独上，愁倚斜阳。", "称鸳鸯鸂鶒，两两池塘。", "春又老，人何处，怎惯不思量。", "到如今，瘦损我，又还无计禁当。", "小院呼卢夜，当时醉倒残缸。", "被天风吹散，凤翼难双。", "南窗雨，西廊月，尚未散、拂天香。", "听莺声，悄记得，那时舞板歌梁。"]'),
('song-ci-438','眼儿媚','吕渭老','宋','宋词','song-ci','眼儿媚','[]','晓钗催鬓语南风。',58,'宋词/ci.song.7000.json','["晓钗催鬓语南风。", "碧涧小桥通。", "榆阴短短，露光炯炯，满地花红。", "天涯不见归帆影，蜂蝶尽西东。", "宿酲渐解，残妆犹在，晓日帘栊。"]'),
('song-ci-439','眼儿媚','吕渭老','宋','宋词','song-ci','眼儿媚','[]','循槛琅玕粉沾衣。',58,'宋词/ci.song.7000.json','["循槛琅玕粉沾衣。", "一片子规啼。", "蓬壶梦短，蜀衾香远，愁损腰肢。", "石城堂上双双燕，应傍莫愁飞。", "春江艇子，雪中梅下，知与谁期。"]'),
('song-ci-440','梦玉人引','吕渭老','宋','宋词','song-ci','梦玉人引','[]','上危梯尽，尽画阁迥，昼帘垂。',102,'宋词/ci.song.7000.json','["上危梯尽，尽画阁迥，昼帘垂。", "曲水飘香，小园莺唤春归。", "舞袖弓弯，正满城、烟草凄迷。", "结伴踏青，趁蝴蝶双飞。", "赏心欢计，从别后、无意到西池。", "自检罗囊，要寻红叶留诗。", "懒约无凭，莺花都不知。", "怕人问，强开怀、细酌酴醿。"]'),
('song-ci-441','倾杯令・杯倾乐','吕渭老','宋','宋词','song-ci','倾杯令・杯倾乐','[]','枫叶飘红，莲房肥露，枕席嫩凉先到。',62,'宋词/ci.song.7000.json','["枫叶飘红，莲房肥露，枕席嫩凉先到。", "帘外蟾华如扫。", "枝上啼鸦催晓。", "秋风又送潘郎老。", "小窗明、疏萤浅照。", "登高送远惆怅，白发至今未了。"]'),
('song-ci-442','倾杯令・倾杯乐','吕渭老','宋','宋词','song-ci','倾杯令・倾杯乐','[]','隔座藏钩，分曹射覆，烛艳渐催三鼓。',62,'宋词/ci.song.7000.json','["隔座藏钩，分曹射覆，烛艳渐催三鼓。", "筝按教坊新谱。", "楼外月生春浦。", "徘徊争忍忙归去。", "怕明朝、无情风雨。", "珍花美酒团坐，且作尊前笑侣。"]'),
('song-ci-443','生查子','吕渭老','宋','宋词','song-ci','生查子','[]','摊钱临小窗，扑蝶穿斜径。',48,'宋词/ci.song.7000.json','["摊钱临小窗，扑蝶穿斜径。", "醉戏晚风前，吹乱连枝影。", "别来秋夜长，梦到金屏近。", "肠断一声鸡，残月悬朝镜。"]'),
('song-ci-444','生查子','吕渭老','宋','宋词','song-ci','生查子','[]','裙长步渐迟，扇薄羞难掩。',48,'宋词/ci.song.7000.json','["裙长步渐迟，扇薄羞难掩。", "鞋褪倚郎肩，问路眉先敛。", "踏青南陌回，倚醉开娇靥。", "今夜更同行，忍笑匀妆脸。"]'),
('song-ci-445','生查子','吕渭老','宋','宋词','song-ci','生查子','[]','双鬟绿发齐，多笑蔫红落。',48,'宋词/ci.song.7000.json','["双鬟绿发齐，多笑蔫红落。", "穿竹过西斋，问字时偷学。", "娇慵不惯羞，同倚阑干角。", "屈指数元宵，灯火堪行乐。"]'),
('song-ci-446','扑蝴蝶近・扑蝴蝶','吕渭老','宋','宋词','song-ci','扑蝴蝶近・扑蝴蝶','[]','分钗绾髻，洞府难分手。',93,'宋词/ci.song.7000.json','["分钗绾髻，洞府难分手。", "离觞短阕，啼痕冰舞袖。", "马嘶霜滑，桥横路转，人依古柳。", "晓色渐分星斗。", "怎分剖。", "心儿一似，倾入离愁万千斗。", "垂鞭伫立，伤心还病酒。", "十年梦里婵娟，二月花中豆蔻。", "春风为谁依旧。"]'),
('song-ci-447','扑蝴蝶近・扑蝴蝶','吕渭老','宋','宋词','song-ci','扑蝴蝶近・扑蝴蝶','[]','风荷露竹，秋意侵疏鬓。',93,'宋词/ci.song.7000.json','["风荷露竹，秋意侵疏鬓。", "微灯曲几。", "有帘通桂影。", "乍凉衣著，轻明微醉，歌声听稳。", "新愁殢人方寸。", "怎不闷。", "当初欲凭，燕翼西飞寄归信。", "小窗睡起，梁间都去尽。", "夜长旅枕先知，秋杪黄花渐近。", "一成为伊销损。"]'),
('song-ci-448','一落索','吕渭老','宋','宋词','song-ci','一落索','[]','蝉带残声移别树。',57,'宋词/ci.song.7000.json','["蝉带残声移别树。", "晚凉房户。", "秋风有意染黄花，下几点、凄凉雨。", "渺渺双鸿飞去。", "乱云深处。", "一山红叶为谁愁，供不尽、相思句。"]'),
('song-ci-449','一落索','吕渭老','宋','宋词','song-ci','一落索','[]','宫锦裁书寄远。',54,'宋词/ci.song.7000.json','["宫锦裁书寄远。", "意长辞短。", "香兰泣露雨催莲，暑气昏池馆。", "向晚小园行遍。", "石榴红满。", "花花叶叶尽成双，浑似我、梁间燕。"]'),
('song-ci-450','一落索','吕渭老','宋','宋词','song-ci','一落索','["\u957f\u6c5f"]','鸟散馀花飞舞。',54,'宋词/ci.song.7000.json','["鸟散馀花飞舞。", "满地风雨。", "长江滚滚接天流，夜送征帆去。", "今夜行云何处。", "断肠南浦。", "残灯不剪五更寒，独自与、馀香语。"]'),
('song-ci-451','谒金门','吕渭老','宋','宋词','song-ci','谒金门','[]','人已老。',53,'宋词/ci.song.7000.json','["人已老。", "春亦不留些少。", "花尽叶长蚕又抱。", "子规啼未了。", "往事不论多少。", "且向尊前一笑。", "白发满头愁已到。", "路长波渺渺。"]'),
('song-ci-452','鼓笛慢・水龙吟','吕渭老','宋','宋词','song-ci','鼓笛慢・水龙吟','[]','拍肩笑别洪崖，共看紫海还清浅。',126,'宋词/ci.song.7000.json','["拍肩笑别洪崖，共看紫海还清浅。", "蓬壶旧约，人间舒笑，桃红千遍。", "去岁争春，今年逼腊，满空飘霰。", "渐横枝照水，清绿弄日，都点缀、江南岸。", "须吸百川为寿，卷恩波、已倾银汉。", "戎袍拥戟，万钉围带，天孙新眷。", "十里尘香，五更弦月，未收弦管。", "正秦筝续谱，宫箫定拍，候来冬按。"]'),
('song-ci-453','卜算子','王之道','宋','宋词','song-ci','卜算子','["\u897f\u6e56"]','拄颊看西湖，屡对纶巾岸。',52,'宋词/ci.song.7000.json','["拄颊看西湖，屡对纶巾岸。", "江上相从醉万山，六见年华换。", "君唱我当酬，我醉君休管。", "明日醒时小艇东，莫负传书雁。"]'),
('song-ci-454','卜算子','王之道','宋','宋词','song-ci','卜算子','[]','堂下水浮天，人指山为岸。',52,'宋词/ci.song.7000.json','["堂下水浮天，人指山为岸。", "水落寒沙只见山，暗被天偷换。", "堂上老诗翁，客至劳相管。", "风喘西头客自东，目送云中雁。"]'),
('song-ci-455','卜算子','王之道','宋','宋词','song-ci','卜算子','["\u897f\u6e56"]','今日富川滨，后夜湓江岸。',52,'宋词/ci.song.7000.json','["今日富川滨，后夜湓江岸。", "千里西湖指顾间，未怕新年换。", "再见复何时，此意凭吟管。", "应有新诗当尺书，日望南来雁。"]'),
('song-ci-456','丑奴儿・采桑子','王之道','宋','宋词','song-ci','丑奴儿・采桑子','[]','青腰似诧天公富，奔走风云。',52,'宋词/ci.song.7000.json','["青腰似诧天公富，奔走风云。", "银界无痕。", "委巷穷山草木春。", "玉楼不怕歌茵湿，笑语纷纷。", "须放他们。", "醉里冰姿光照人。"]'),
('song-ci-457','桃源忆故人','王之道','宋','宋词','song-ci','桃源忆故人','[]','逢人借问春归处。',56,'宋词/ci.song.7000.json','["逢人借问春归处。", "遥指芜城烟树。", "收尽柳梢残雨。", "月闯西南户。", "游丝不解留伊住。", "漫惹闲愁无数。", "燕子为谁来去。", "似说江头路。"]'),
('song-ci-458','桃源忆故人','王之道','宋','宋词','song-ci','桃源忆故人','[]','不知春色归何处。',56,'宋词/ci.song.7000.json','["不知春色归何处。", "但见茂林芳树。", "庭巷落花如雨。", "斗乱穿窗户。", "晚行溪上东风住。", "荷点青钱无数。", "蛱蝶飞来还去。", "错认花间路。"]'),
('song-ci-459','桃源忆故人','王之道','宋','宋词','song-ci','桃源忆故人','[]','南园最是花多处。',56,'宋词/ci.song.7000.json','["南园最是花多处。", "门掩绿杨千树。", "别后几番风雨。", "碧藓侵苔户。", "侬家旧在郊西住。", "门外远山无数。", "谁道不如归去。", "咫尺长安路。"]'),
('song-ci-460','桃源忆故人','王之道','宋','宋词','song-ci','桃源忆故人','[]','依依杨柳青青草。',56,'宋词/ci.song.7000.json','["依依杨柳青青草。", "梦断画桥春晓。", "风里落花如扫。", "莫厌寻芳早。", "酴醿芍药看来好。", "恰似江湖遗老。", "锦段荷□传到。", "愧乏琼瑶报。"]'),
('song-ci-461','桃源忆故人','王之道','宋','宋词','song-ci','桃源忆故人','[]','望中风絮迷烟草。',56,'宋词/ci.song.7000.json','["望中风絮迷烟草。", "愁结几番昏晓。", "花径有时亲扫。", "载酒应须早。", "人情曷似春山好。", "山色不随春老。", "旧隐何当重到。", "迎得平安报。"]'),
('song-ci-462','沁园春','王之道','宋','宋词','song-ci','沁园春','[]','城郭萧条，风雨霏微，酝造春愁。',139,'宋词/ci.song.7000.json','["城郭萧条，风雨霏微，酝造春愁。", "况鸷群雕鹗，未谐荐祢，棘栖鸾凤，犹叹栖仇。", "世路如棋，人情似纸，厚薄高低何日休。", "逢殷浩，会披云对月，同赋南楼。", "堪嗟日月如流。", "甚首夏朅来今半秋。", "纵荻花枫叶，强撩归思，有莼羹菰饭，归更何忧。", "三板松舟，一篙秋水，百里淮山无暂留。", "何须问，蘧蘧栩栩，孰是庄周。"]'),
('song-ci-463','惜奴娇','王之道','宋','宋词','song-ci','惜奴娇','[]','不厮知名，怎奈向、前缘注定。',91,'宋词/ci.song.7000.json','["不厮知名，怎奈向、前缘注定。", "一封书、便成媒娉。", "千里相从，恰似寻盟合姓。", "泥泞。", "尚隔个、轿儿难近。", "薄薄纱厨，小驿夜凉人静。", "红一点、暗通犀晕。", "花月多情，摇碎半窗清影。", "安稳。", "悄不知、人痛损。"]'),
('song-ci-464','惜奴娇','王之道','宋','宋词','song-ci','惜奴娇','[]','甚麽因缘，恰得一年相聚。',86,'宋词/ci.song.7000.json','["甚麽因缘，恰得一年相聚。", "和闰月、更无剩数。", "说著分飞，背面偷弹玉箸。", "好去。", "记取许时言语。", "旧爱新人，后夜一时分付。", "从前事、不堪回顾。", "怎奈冤家，抵死牵肠惹肚。", "愁苦。", "梦断五更风雨。"]'),
('song-ci-465','南乡子','王之道','宋','宋词','song-ci','南乡子','[]','遗爱满南州。',66,'宋词/ci.song.7000.json','["遗爱满南州。", "千骑曾为万里游。", "琳馆归来，无责更无忧。", "坐听笙歌醉玉舟。", "香雾郁金虬。", "春入梅花助献酬。", "请祝遐年，长笑挹浮丘。", "何止莘君一百筹。"]'),
('song-ci-466','南乡子','王之道','宋','宋词','song-ci','南乡子','[]','天际彩虹垂。',66,'宋词/ci.song.7000.json','["天际彩虹垂。", "风起痴云快一吹。", "原隰畇畇，春水更弥弥。", "布谷期从野鸟知。", "初霁卷帘时。", "巷陌泥融燕子飞。", "午醉醒来，红日欲平西。", "一碗新茶乳面肥。"]'),
('song-ci-467','南乡子','王之道','宋','宋词','song-ci','南乡子','[]','出户绣帘垂。',66,'宋词/ci.song.7000.json','["出户绣帘垂。", "拂面从他细细吹。", "乘兴有谁招访戴，难为。", "暖帐薰炉醉不知。", "闲看逐风时。", "欲著梅花又却飞。", "雅兴佳人回舞袂，相宜。", "试比冰肌可煞肥。"]'),
('song-ci-468','南乡子','王之道','宋','宋词','song-ci','南乡子','[]','春霁柳花垂。',66,'宋词/ci.song.7000.json','["春霁柳花垂。", "娇软轻狂不待吹。", "圆欲成球还复碎，谁为。", "习习和风即旧知。", "深院日长时。", "乱扑珠帘入坐飞。", "试问荻芽生也未，偏宜。", "出网河豚美更肥。"]'),
('song-ci-469','南乡子','王之道','宋','宋词','song-ci','南乡子','[]','风急断虹收。',66,'宋词/ci.song.7000.json','["风急断虹收。", "孤鹜摇摇下荻洲。", "醉帽尽从吹落去，飕飕。", "幸有黄花插满头。", "君唱我当酬。", "千里湖山照眼秋。", "不见故人思故国，休休。", "一阕清歌听解愁。"]'),
('song-ci-470','南乡子','王之道','宋','宋词','song-ci','南乡子','[]','翠袖熨沈香。',66,'宋词/ci.song.7000.json','["翠袖熨沈香。", "黛拂修蛾淡淡妆。", "消得多情锺傅粉，何郎。", "风动珠帘月半床。", "素手捧瑶觞。", "谁念苏州已断肠。", "夜雨不随歌扇歇，浪浪。", "归去无心赋海棠。"]'),
('song-ci-471','减字木兰花','王之道','宋','宋词','song-ci','减字木兰花','[]','彩幡金胜。',52,'宋词/ci.song.7000.json','["彩幡金胜。", "一笑酬春聊适性。", "呆女痴儿。", "半挽梅花半柳枝。", "追欢何计。", "幸对绿尊环皂髻。", "欲舞还羞。", "美盼娇回碧水秋。"]'),
('song-ci-472','减字木兰花','王之道','宋','宋词','song-ci','减字木兰花','[]','诗成呵手。',52,'宋词/ci.song.7000.json','["诗成呵手。", "欲写已输君赋就。", "寒粟生肤。", "一盏浇肠可得无。", "回风弄巧。", "比似婆娑尤敏妙。", "似个人人。", "嗅认梅花孰是真。"]'),
('song-ci-473','减字木兰花','王之道','宋','宋词','song-ci','减字木兰花','[]','尊前放手。',52,'宋词/ci.song.7000.json','["尊前放手。", "铜钵声穷诗已就。", "姑射肌肤。", "舞罢缠头怎得无。", "青腰更巧。", "搓粉团酥来斗妙。", "不敢方人。", "容色依稀似太真。"]'),
('song-ci-474','减字木兰花','王之道','宋','宋词','song-ci','减字木兰花','[]','玉奴招手。',52,'宋词/ci.song.7000.json','["玉奴招手。", "来看前山琼琢就。", "透骨侵肤。", "似恁清寒更有无。", "春工纵巧。", "只许梅花称独妙。", "花底逢人。", "逐马银杯误认真。"]'),
('song-ci-475','减字木兰花','王之道','宋','宋词','song-ci','减字木兰花','[]','鳖头龟手。',52,'宋词/ci.song.7000.json','["鳖头龟手。", "孤坐书生能意就。", "暖体温肤。", "绣被春寒想见无。", "雪词工巧。", "高压君房天下妙。", "白发欺人。", "甚矣吾衰懒是真。"]'),
('song-ci-476','减字木兰花','王之道','宋','宋词','song-ci','减字木兰花','[]','修眉山远。',52,'宋词/ci.song.7000.json','["修眉山远。", "娇抹乌云秋水畔。", "酒里花前。", "坐拥斯人怎得寒。", "醁醽浮满。", "须索空缸仍覆盏。", "正恐相妨。", "归去如闻笑语香。"]'),
('song-ci-477','减字木兰花','王之道','宋','宋词','song-ci','减字木兰花','[]','江梅清远。',52,'宋词/ci.song.7000.json','["江梅清远。", "潇洒一枝尊俎畔。", "雪里风前。", "照水窥檐巧耐寒。", "多情美满。", "共饮自应渠釂盏。", "醉赏何妨。", "倾国天教抵死香。"]'),
('song-ci-478','减字木兰花','王之道','宋','宋词','song-ci','减字木兰花','[]','笑中声远。',52,'宋词/ci.song.7000.json','["笑中声远。", "走向曲房花树畔。", "拥在尊前。", "顿觉春温却夜寒。", "愿酬心满。", "只得教伊频劝盏。", "缓唱何妨。", "贴体衫儿扑扑香。"]'),
('song-ci-479','减字木兰花','王之道','宋','宋词','song-ci','减字木兰花','[]','仙姿凝远。',52,'宋词/ci.song.7000.json','["仙姿凝远。", "半出新妆琼户畔。", "缓步来前。", "正值东风料峭寒。", "钗头花满。", "舞罢梅英飞入盏。", "一釂何妨。", "花与佳人巧斗香。"]'),
('song-ci-480','减字木兰花','王之道','宋','宋词','song-ci','减字木兰花','[]','离筵暂住。',52,'宋词/ci.song.7000.json','["离筵暂住。", "君在龙舒曾是主。", "今作行人。", "卧辙何妨借寇恂。", "清歌妙舞。", "断送吟鞭乘醉去。", "一釂休辞。", "捧爵佳人玉箸垂。"]'),
('song-ci-481','减字木兰花','王之道','宋','宋词','song-ci','减字木兰花','[]','金尊频倒。',52,'宋词/ci.song.7000.json','["金尊频倒。", "照坐梅花清更好。", "春到长杨。", "宠拜三公入郑庄。", "月城两载。", "千里生灵蒙惠爱。", "舞彻歌词。", "并立新妆绿带垂。"]'),
('song-ci-482','减字木兰花','王之道','宋','宋词','song-ci','减字木兰花','[]','蛾眉螓首。',52,'宋词/ci.song.7000.json','["蛾眉螓首。", "舞雪娇回开冻候。", "尽道今年。", "千里风光萃绮筵。", "坐来新月。", "照我苍颜并白发。", "酒到休辞。", "自有黄芽介寿祺。"]'),
('song-ci-483','阮郎归','王之道','宋','宋词','song-ci','阮郎归','[]','玉绳低转斗阑干。',56,'宋词/ci.song.7000.json','["玉绳低转斗阑干。", "欠温春酒寒。", "夜长风劲怯衣单。", "有人哦二山。", "蟾欲满，雁初还。", "桃花微破颜。", "枕痕犹带断红残。", "无言心自闲。"]'),
('song-ci-484','阮郎归','王之道','宋','宋词','song-ci','阮郎归','[]','长杨风软弄腰肢。',56,'宋词/ci.song.7000.json','["长杨风软弄腰肢。", "日长胡蝶飞。", "雨馀新绿细通池。", "玉钩悬妓衣。", "鸿雁远，子规啼。", "此情谁得知。", "一尊聊与故人持。", "醉来悲别离。"]'),
('song-ci-485','长相思','王之道','宋','宋词','song-ci','长相思','[]','雨濛濛。',44,'宋词/ci.song.7000.json','["雨濛濛。", "日昽昽。", "洗出远山三四重。", "分明眉黛浓。", "野桥西，官路东。", "小驿夜凉风入松。", "梦魂谁与同。"]'),
('song-ci-486','长相思','王之道','宋','宋词','song-ci','长相思','[]','花一枝。',44,'宋词/ci.song.7000.json','["花一枝。", "酒一卮。", "举酒对花君莫辞。", "人生多别离。", "行相随。", "坐相随。", "更有何人得似伊。", "春融胡蝶飞。"]'),
('song-ci-487','长相思','王之道','宋','宋词','song-ci','长相思','[]','天四垂。',44,'宋词/ci.song.7000.json','["天四垂。", "山四围。", "山色天容入坐帷。", "清风吹我衣。", "湖水东，江水西。", "东去西来无尽期。", "不如君共伊。"]'),
('song-ci-488','长相思','王之道','宋','宋词','song-ci','长相思','[]','吴江枫。',44,'宋词/ci.song.7000.json','["吴江枫。", "吴江风。", "索索秋声飞乱红。", "晚来归兴浓。", "淮山西，淮山东。", "明月今宵何处同。", "相寻魂梦中。"]'),
('song-ci-489','长相思','王之道','宋','宋词','song-ci','长相思','[]','风凄凄。',44,'宋词/ci.song.7000.json','["风凄凄。", "雨霏霏。", "风雨夜寒人别离。", "梦回还自疑。", "蛩声悲。", "漏声迟。", "一点青灯明更微。", "照人双泪垂。"]'),
('song-ci-490','长相思','王之道','宋','宋词','song-ci','长相思','[]','桃花春。',44,'宋词/ci.song.7000.json','["桃花春。", "杏花春。", "桃杏妖娆如个人。", "歌声清遏云。", "酒醺醺。", "烛荧荧。", "眼尾微红无限情。", "相逢堪断魂。"]'),
('song-ci-491','满庭芳','王之道','宋','宋词','song-ci','满庭芳','[]','紫角初繁，青裳正好，充闾清露飘香。',118,'宋词/ci.song.7000.json','["紫角初繁，青裳正好，充闾清露飘香。", "悬弧何早，乌辔上扶桑。", "试问椿龄几许，逾万计、才满三章。", "佳辰乐，林塘增气，菡萏拥红妆。", "称觞。", "人共庆，盘中白李，来自华阳。", "倩壶中日月，特地舒长。", "定见霜毫换绿，天荐祉、家庆延昌。", "情千万，辞悭思窘，聊献满庭芳。"]'),
('song-ci-492','满庭芳','王之道','宋','宋词','song-ci','满庭芳','[]','蔡水西来，于门南峙，天波拥入华楹。',118,'宋词/ci.song.7000.json','["蔡水西来，于门南峙，天波拥入华楹。", "芝兰争秀，难弟遇难兄。", "欲说随龙雨露，庆千载、河海初清。", "良辰好，榴花照眼，绿柳隐啼莺。", "君恩，隆横赐，冰桃火枣，来自蓬瀛。", "正雾横玉篆，泉泻金鲸。", "四座香和酒泛，对妙舞、弦索铿鍧。", "椿难老，年年今日，论报祝长生。"]'),
('song-ci-493','满庭芳','王之道','宋','宋词','song-ci','满庭芳','[]','翠盖千重，青钱万叠，雨馀绿涨银塘。',119,'宋词/ci.song.7000.json','["翠盖千重，青钱万叠，雨馀绿涨银塘。", "藕花无数，高下斗芬芳。", "浑似华清赐浴，温泉滑、洗出真香。", "何妨更，合欢连理，高压万芝祥。", "风流，贤太守，当年奏瑞，盛事名堂。", "好是琉璃池上，一片宫妆。", "况有薰风解愠，流霞泛、丝竹成行。", "依莲暇，联珠唱玉，应不愧金相。"]'),
('song-ci-494','满庭芳','王之道','宋','宋词','song-ci','满庭芳','[]','天驷呈祥，土牛颁政，欢呼万井春来。',118,'宋词/ci.song.7000.json','["天驷呈祥，土牛颁政，欢呼万井春来。", "雕轮丹毂，杂沓展轻雷。", "风动珠帘不卷，香散处、半露梅腮。", "东郊好，波澜浸绿，萌蘖上条枚。", "徘徊。", "应共怪，十年豹隐，一旦鸾台。", "问康时术业，混俗情怀。", "过雪湖山清丽，笙歌沸、舞袖萦回。", "兵厨富，酒肠似海，莫惜醉金杯。"]'),
('song-ci-495','满庭芳','王之道','宋','宋词','song-ci','满庭芳','[]','雪霁风温，霜消日暖，一时笑语烘春。',118,'宋词/ci.song.7000.json','["雪霁风温，霜消日暖，一时笑语烘春。", "草堂何幸，四座德星邻。", "聊借红妆侑爵，兰膏腻、高髻盘云。", "清歌妙，贯珠馀韵，犹振画梁尘。", "熙朝，卿相种，扁舟东去，入侍严宸。", "忆当年擢桂，连见三秦。", "休说参军俊逸，应难过、开府清新。", "从今去，八州都督，端不困无津。"]'),
('song-ci-496','满庭芳','王之道','宋','宋词','song-ci','满庭芳','[]','露溢金茎，风翔玉宇，嫩凉初霁秋容。',118,'宋词/ci.song.7000.json','["露溢金茎，风翔玉宇，嫩凉初霁秋容。", "山肴野蔌，聊快一尊同。", "正值大田多稼，临邛隘、酒客憧憧。", "追随处，杯盘狼藉，野草荫长松。", "新词，何所似，金声应铎，玉气腾虹。", "时来终宦达，休怨苍穹。", "顾我蹉跎老矣，飘素发、衰态龙锺。", "心犹壮，会看文度，独步大江东。"]'),
('song-ci-497','满庭芳','王之道','宋','宋词','song-ci','满庭芳','[]','麦野青深，桃溪红暗，浪游何处芳园。',118,'宋词/ci.song.7000.json','["麦野青深，桃溪红暗，浪游何处芳园。", "清明初过，门巷霭晴烟。", "柳外池塘绿遍，溪流细、终日溅溅。", "东风软，谁家儿女，墙里送秋千。", "花前。", "从醉倒，吾当尽量，君盍忘年。", "纵杯盘草草，随分开筵。", "自有高谈雄辩，何须问、急管繁弦。", "身长健，少陵如在，应赋饮中仙。"]'),
('song-ci-498','满庭芳','王之道','宋','宋词','song-ci','满庭芳','[]','歌彻骊驹，酒斟醽醁，帆樯高映城楼。',118,'宋词/ci.song.7000.json','["歌彻骊驹，酒斟醽醁，帆樯高映城楼。", "绣衣携具，开宴话离愁。", "两岸橙黄橘绿，一行雁、几点沙鸥。", "情千万，相看无语，送我上孤舟。", "悠悠。", "冬向晚，梅花潜暖，随处香浮。", "奈长亭饮散，无计淹留。", "归路淮山百舍，空梦想、连岁清游。", "烦双鲤，频将尺素，来往寄江流。"]'),
('song-ci-499','醉蓬莱','王之道','宋','宋词','song-ci','醉蓬莱','[]','对黄芦卧雨，苍雁横秋，江天重九。',119,'宋词/ci.song.7000.json','["对黄芦卧雨，苍雁横秋，江天重九。", "千载渊明，信风流称首。", "吟绕东篱，白衣何处，谁复当年偶。", "蓝水清游，龙山胜集，恍然依旧。", "萸实嫩红，菊团馀馥，付与佳人，比妍争嗅。", "一曲婆娑，看舞腰萦柳。", "举世纷纷名利逐，罕遇笑来开口。", "慰我寂寥，酬君酩酊，不容无酒。"]'),
('song-ci-500','醉蓬莱','王之道','宋','宋词','song-ci','醉蓬莱','[]','正薰风解愠，萱草忘忧，黄梅新霁。',120,'宋词/ci.song.7000.json','["正薰风解愠，萱草忘忧，黄梅新霁。", "缥缈歌台，半金衣公子。", "丹桂香中，碧梧枝上，两两飞还止。", "似说当年，而今时候，长庚诞贵。", "恩厚随龙，官崇御带，二十横金，玉阶寸地。", "须信骅骝，一日能千里。", "况遇王良伯乐，算九万、何劳睥睨。", "磊落金盘，华阳白李，休辞沈醉。"]'),
('song-ci-501','浣溪沙','王之道','宋','宋词','song-ci','浣溪沙','[]','一样檀心半卷舒。',48,'宋词/ci.song.7000.json','["一样檀心半卷舒。", "淡黄衫子衬冰肤。", "细看全似那人姝。", "枕里芳蕤薰绣被，酒中馀馥溢金壶。", "不须频嗅惹罗裾。"]'),
('song-ci-502','浣溪沙','王之道','宋','宋词','song-ci','浣溪沙','[]','晓日晖晖玉露光。',48,'宋词/ci.song.7000.json','["晓日晖晖玉露光。", "枝头一样斗宫妆。", "可怜娇额半涂黄。", "衣与酴醿新借色，肌同薝卜更薰香。", "风流荀令雅相当。"]'),
('song-ci-503','浣溪沙','王之道','宋','宋词','song-ci','浣溪沙','[]','过雨花容杂笑啼。',48,'宋词/ci.song.7000.json','["过雨花容杂笑啼。", "淡妆深注半开时。", "娇娆情态自天姿。", "新浴太真增艳丽，微风新燕斗清奇。", "绿窗朱户雅相宜。"]'),
('song-ci-504','浣溪沙','王之道','宋','宋词','song-ci','浣溪沙','[]','阳气初升土脉苏。',48,'宋词/ci.song.7000.json','["阳气初升土脉苏。", "东郊人散欲回车。", "一时春雪十年无。", "鱼枕蕉深浮酒蚁，鹿胎冠子粲歌珠。", "题诗不觉烛然须。"]'),
('song-ci-505','浣溪沙','王之道','宋','宋词','song-ci','浣溪沙','[]','体粟须烦鼎力苏。',48,'宋词/ci.song.7000.json','["体粟须烦鼎力苏。", "流涎正值麴盈车。", "坐来兽炭拨还无。", "一阕可能酬一绝，双银端不换双珠。", "松毛粉白老翁须。"]'),
('song-ci-506','浣溪沙','王之道','宋','宋词','song-ci','浣溪沙','[]','春到衡门病滞苏。',48,'宋词/ci.song.7000.json','["春到衡门病滞苏。", "力强犹可驾柴车。", "少年狂望一时无。", "清坐不堪肌起粟，高谈还喜唾成珠。", "红裙痴笑雪如须。"]'),
('song-ci-507','浣溪沙','王之道','宋','宋词','song-ci','浣溪沙','[]','冻卧袁安已复苏。',48,'宋词/ci.song.7000.json','["冻卧袁安已复苏。", "闭门那患出无车。", "似渠人物到今无。", "可笑崑山夸片玉，须怜沧海叹遗珠。", "时来应许捋君须。"]'),
('song-ci-508','浣溪沙','王之道','宋','宋词','song-ci','浣溪沙','[]','残雪笼晴作沍寒。',48,'宋词/ci.song.7000.json','["残雪笼晴作沍寒。", "北风吹浪过前滩。", "远山云气尚漫漫。", "睡起阳乌窥破牖，坐怜香雾蔼雕盘。", "一尊聊佐旅中欢。"]'),
('song-ci-509','浣溪沙','王之道','宋','宋词','song-ci','浣溪沙','[]','玉骨冰肌软更香。',48,'宋词/ci.song.7000.json','["玉骨冰肌软更香。", "一枝丹棘映青裳。", "相逢归去未须忙。", "曲里春山情不浅，尊前秋水意何长。", "酒醺颜色粉生光。"]'),
('song-ci-510','浣溪沙','王之道','宋','宋词','song-ci','浣溪沙','[]','寒透珠帘怯晓霜。',48,'宋词/ci.song.7000.json','["寒透珠帘怯晓霜。", "灰飞缇室验回阳。", "坐看红日上修廊。", "泉泻龙头深泛酒，烟凝象口暖吹香。", "及时歌舞意何长。"]'),
('song-ci-511','浣溪沙','王之道','宋','宋词','song-ci','浣溪沙','[]','水外山光淡欲无。',48,'宋词/ci.song.7000.json','["水外山光淡欲无。", "堤边草色翠如铺。", "绿杨风软鸟相呼。", "牛蒡叶齐罗翠扇，鹿黎花小隘真珠。", "一声何处叫提壶。"]'),
('song-ci-512','东风第一枝','王之道','宋','宋词','song-ci','东风第一枝','[]','玉骨冰肌，绛趺檀口，玲珑亚竹当户。',123,'宋词/ci.song.7000.json','["玉骨冰肌，绛趺檀口，玲珑亚竹当户。", "嫣然照雪精神，消得东君眷与。", "群芳退舍，顾凡下、非伊朋侣。", "却自有、薝卜酴醿，次第效颦追步。", "寓心赏、还须吟醉，赴目成、便依歌舞。", "情锺束素无华，意在含情不语。", "纷纷桃李，亦何用、轻猜轻妒。", "觅一枝、欲寄相思，伴取个人书去。"]'),
('song-ci-513','西江月','王之道','宋','宋词','song-ci','西江月','[]','黄菊正怀彭泽，白衣俄致江州。',58,'宋词/ci.song.7000.json','["黄菊正怀彭泽，白衣俄致江州。", "登高馀醉快扶头。", "此贶义兼情厚。", "痛饮还须酒对，清吟况值诗流。", "轻投无惜万金酬。", "木李旧先琼玖。"]'),
('song-ci-514','西江月','王之道','宋','宋词','song-ci','西江月','[]','北陆藏冰欲竟，东风解冻非遥。',58,'宋词/ci.song.7000.json','["北陆藏冰欲竟，东风解冻非遥。", "一时芳意巧相撩。", "入眼绿娇红小。", "柳色轻摇弱线，梅英纷缀枯梢。", "觥筹醉里赖君饶。", "归去斜阳尚早。"]'),
('song-ci-515','西江月','王之道','宋','宋词','song-ci','西江月','[]','磨急锯霏琼屑，汤鸣车转羊肠。',58,'宋词/ci.song.7000.json','["磨急锯霏琼屑，汤鸣车转羊肠。", "一杯聊解水仙浆。", "七日狂酲顿爽。", "指点红裙劝坐，招呼岩桂分香。", "看花不觉酒浮觞。", "醉倒宁辞鼠量。"]'),
('song-ci-516','西江月','王之道','宋','宋词','song-ci','西江月','[]','雪后千林尚冻，城边一径微通。',58,'宋词/ci.song.7000.json','["雪后千林尚冻，城边一径微通。", "柳梢摇曳转东风。", "来看梅花应梦。", "酒面初潮蚁绿，歌唇半启樱红。", "冰肌绰约月朦胧。", "仿佛暗香浮动。"]'),
('song-ci-517','西江月','王之道','宋','宋词','song-ci','西江月','[]','春色荒荒别浦，春潮滟滟长堤。',58,'宋词/ci.song.7000.json','["春色荒荒别浦，春潮滟滟长堤。", "绿杨风喘客帆迟。", "肠断江南双鲤。", "短梦当年楚雨，扁舟后夜秦溪。", "一声啼鸟怨春归。", "人在酴醿花底。"]'),
('song-ci-518','西江月','王之道','宋','宋词','song-ci','西江月','[]','一霎轻云过雨，半篙新绿横舟。',58,'宋词/ci.song.7000.json','["一霎轻云过雨，半篙新绿横舟。", "梅花池馆暗香浮。", "酒入朱唇红透。", "有恨尤怜别恨，多愁不惯春愁。", "舞馀何惜更迟留。", "肠断断肠更后。"]'),
('song-ci-519','西江月','王之道','宋','宋词','song-ci','西江月','[]','一别清风北牖，几番明月西楼。',58,'宋词/ci.song.7000.json','["一别清风北牖，几番明月西楼。", "断肠千里致书邮。", "借问近来安否。", "归路淮山过雨，归舟江水澄秋。", "佳人应已数程头。", "准拟到家时候。"]'),
('song-ci-520','归朝欢','王之道','宋','宋词','song-ci','归朝欢','[]','透隙敲窗风摵摵。',122,'宋词/ci.song.7000.json','["透隙敲窗风摵摵。", "坐见广庭飞缟白。", "长安道上正骑驴，蔡州城里谁坚壁。", "表表风尘物。", "瑶林琼宇三豪客。", "对分毫、连珠唱玉，竟把诗笺掷。", "草草杯盘还促席。", "痛饮狂歌话胸臆。", "前村昨夜访梅花，东邻休更夸容色。", "清欢那易得。", "明朝乌辔升南极。", "带随车、黄垆咫尺，莫作山河隔。"]'),
('song-ci-521','宴春台','王之道','宋','宋词','song-ci','宴春台','[]','翠竹扶疏，丹葵隐映，绿窗朱户萦回。',121,'宋词/ci.song.7000.json','["翠竹扶疏，丹葵隐映，绿窗朱户萦回。", "帘卷虾须，清风时自南来。", "题舆好客筵开。", "俨新妆、深出云街。", "歌珠累贯，一时倾坐，全胜腰雷。", "金猊袅碧，玉兕浮红，令传三杏，情寄双梅。", "楼头漏促，笼纱暗落花煤。", "锦里遗音，忆当年、曾赋春台。", "醉蓬莱。", "归欤无寐，想馀韵徘徊。"]');
